-- Poems batch 255
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('016002cd-5004-4780-b08d-a7c32eebb498','配食大成樂章 酌獻沂國公','王應麟','宋','宋诗','song-poetry','','[]','公傳自曾，孟傳自公。',40,'全唐诗/poet.song.229000.json','["公傳自曾，孟傳自公。", "有的緒承，允得其宗。", "提綱開縕，乃作中庸。", "侑於元聖，億載是崇。"]'),
('45141701-ff6e-432a-803e-b69c3f0ed62c','吳刺史廟祭神辭','王應麟','宋','宋诗','song-poetry','','[]','坎擊鼓兮鄞水滸，思仁侯兮昔召父。',139,'全唐诗/poet.song.229000.json','["坎擊鼓兮鄞水滸，思仁侯兮昔召父。", "堰九里兮釃流爲雨，水泱泱兮芃芃麥黍。", "鴻隙堙兮謠荳芋，侯嘉績兮依其在渚。", "神之來兮飆輪下，蘭觴勺兮薦椒糈。", "民不忘侯兮歌且舞，侯不忘民兮俾寧宇。", "神之歸兮娭瑶圃，格顥穹兮降多祜。", "婁豐穰兮除疾苦，年千世百兮保艾吾土。", "事侯如存兮侯其福女，敬共承祀兮無怠終古。"]'),
('b55bf433-2443-469b-8c98-e158561ab53b','吳刺史廟','王應麟','宋','宋诗','song-poetry','','[]','城西有祠臨水涘，翠松列植路如砥。',208,'全唐诗/poet.song.229000.json','["城西有祠臨水涘，翠松列植路如砥。", "問之耆老此爲誰，唐大曆中吳刺史。", "刺史爲民開陂湖，故蹟猶傳堰九里。", "年年簫鼓報豐穰，决渠爲雨潤澤美。", "遺愛有橋名懷恩，姓名不載太史氏。", "昔漢吳公治第一，列傳寂寂名無紀。", "刺史豈其苗裔歟，明州政亦河南比。", "堂上大書荆公詩，蘭菊春秋百世祀。", "地志祇稱王長官，有功於民蓋一揆。", "吾聞是邦多賢守，裴王碑字顔與李。", "惟侯盛德著人心，彼石可焚祠弗圯。", "廣德湖爲鴻隙陂，召棠欒社誰敢毀。", "秔稌充羨侯之賜，廟食長存如此水。"]'),
('0f0f2553-010f-4dcf-91fa-0bb23f5490eb','東山','王應麟','宋','宋诗','song-poetry','','[]','東山美周公，千載邈遺音。',228,'全唐诗/poet.song.229000.json','["東山美周公，千載邈遺音。", "槃槃謝家安，陳迹猶可尋。", "仰睇虞峰高，俯挹娥濤深。", "偉人不可作，感慨生登臨。", "典午鼎岌岌，日夕照忠忱。", "談笑沮溫謀，尊俎却氐侵。", "斯民免爲魚，清風濯鬴鬵。", "撫箏疑未釋，西州復霑衿。", "紫囊皆少年，秉鉞掃雲陰。", "茂績世茅土，有孫亦璆琳。", "祚移卯金刀，志士皆噎喑。", "曷不效靖節，種菊遯幽林。", "既縻無嘉爵，空懷子房心。", "鴻鳴九霄遠，雉翳嗟珍禽。", "行藏異危遜，覽古得良箴。", "吾遊幾入越，獨欠隮崟岑。", "晉士豈清談，底柱屹江潯。", "翠屏倚空碧，浮雲更古今。", "永言廣武歎，誰續洛生吟。"]'),
('4b5ce11a-def9-4906-b06c-da6e3f12b643','鄉飲酒詩','王侑','宋','宋诗','song-poetry','','[]','聖主方求治，偏城敢後儒。',72,'全唐诗/poet.song.229000.json','["聖主方求治，偏城敢後儒。", "采芹嚴祀事，序齒集生徒。", "黄髮居賓右，青衿隘坐隅。", "遠侔魯泮飲，下陋漢庭酺。", "席正群心肅，盃行美化敷。", "君恩何以報，忠孝是良圖。"]'),
('a5ba45ae-ac74-4dcc-b210-f40c29759ad5','鄉飲酒倡和詩','王侑','宋','宋诗','song-poetry','','[]','旴江文物盛江西，有底醇風欠轉移。',64,'全唐诗/poet.song.229000.json','["旴江文物盛江西，有底醇風欠轉移。", "端藉鄉賢扶世道，共修禮飲迪民彜。", "厖眉華髮四朝老，方領圜冠三代儀。", "天理人心非外有，信乎王道不難知。"]'),
('42d2db3b-e51c-46ac-97ab-3743f011f035','贊鄭貞娘','陳贊','宋','宋诗','song-poetry','','[]','宋主南奔閩海頭，至元鐵騎震山丘。',64,'全唐诗/poet.song.229000.json','["宋主南奔閩海頭，至元鐵騎震山丘。", "守臣不識歸降耻，處女獨懷污辱羞。", "雲氣古今和恨結，潮聲日夜带哀流。", "死生大義須臾事，留取芳名幾百秋。"]'),
('803114ab-6d14-4024-87cd-1ad723a0e66b','遊四明留題丹山','唐震','宋','宋诗','song-poetry','','[]','四明光照九霄寒，閬苑神仙日往還。',64,'全唐诗/poet.song.229000.json','["四明光照九霄寒，閬苑神仙日往還。", "瀑布遠從銀漢落，洞門長鎖白雲閒。", "深崖瑞木金文潤，絕頂靈槎鐵色斑。", "無限遺蹤人莫識，落花香泛水潺潺。"]'),
('6f09270b-0247-43a4-ab94-6b71d16e28da','鬰林寺','唐元齡','宋','宋诗','song-poetry','','[]','一徑通深窈，叢林獨蔚然。',48,'全唐诗/poet.song.229000.json','["一徑通深窈，叢林獨蔚然。", "神仙棲佛屋，香火當僧田。", "罕見催租吏，誰談文字禪。", "吳儂來拜朔，僂指滿三千。"]'),
('00578721-c034-4e41-9329-c618c1ea6f22','華蓋山','唐元齡','宋','宋诗','song-poetry','','[]','巍然獨立九霄中，勢壓衡廬亙華嵩。',64,'全唐诗/poet.song.229000.json','["巍然獨立九霄中，勢壓衡廬亙華嵩。", "擣藥聲高蟾闕近，乘槎路渺鵲橋通。", "三更見日生滄海，六月飛霜下翠空。", "好挾千年王子晉，玉笙輕度碧桃風。"]'),
('3c420600-f1e9-4f57-aca3-f1dd11cca640','象眠山','唐元齡','宋','宋诗','song-poetry','','[]','作縣苦無俄頃閒，喜逢佳節一開顔。',64,'全唐诗/poet.song.229000.json','["作縣苦無俄頃閒，喜逢佳節一開顔。", "無人送酒來彭澤，有客登臨嗣魯山。", "慨想鶴汀鳬渚外，盤桓鰲水象峯間。", "賞心未盡天將晚，賸插黄花带月還。"]'),
('2d01b6b5-9b12-40cd-b91a-8899b4246292','和太傅平章賈魏公咸淳庚午冬大雪遺安撫潛侍郎','文及翁','宋','宋诗','song-poetry','','[]','身遊廊廟意山林，六出花開一寸心。',64,'全唐诗/poet.song.229000.json','["身遊廊廟意山林，六出花開一寸心。", "平地尺書叨載史，瞻天班賀齒諸任。", "屢豐歲事常如昔，太素風光直到今。", "收斂神功放晴景，白河半夜掃層陰。"]'),
('14dca19c-b176-4561-afae-f730b35b0243','山中夜坐','文及翁','宋','宋诗','song-poetry','','[]','悠悠天地間，草木獻奇怪。',24,'全唐诗/poet.song.229000.json','["悠悠天地間，草木獻奇怪。", "投老一蒲團，山中大自在。"]'),
('6092f165-9671-44d5-ad9b-b42fc34a3be9','和東坡韻二首  其一','文及翁','宋','宋诗','song-poetry','','[]','萬壽山藏不二中，九峯峯下善財童。',64,'全唐诗/poet.song.229000.json','["萬壽山藏不二中，九峯峯下善財童。", "敲門問竹機鋒觸，倚檻看花色界空。", "汝坐蒲團曾有夢，我來芻牧媿無功。", "吳天蜀地元來近，月照峨嵋日又東。"]'),
('9f2d6de1-d71f-4ea3-a126-52a30959b786','和東坡韻二首  其二','文及翁','宋','宋诗','song-poetry','','[]','身滿華嚴法界中，香厨底事感天童。',64,'全唐诗/poet.song.229000.json','["身滿華嚴法界中，香厨底事感天童。", "那知本覺從何覺，纔悟真空自不空。", "若有相時元說夢，到無言處却收功。", "一鈎月上星三點，汝向西床我面東。"]'),
('aec5279f-96b8-495e-812a-42dc653ca4f9','次回仙韻  其一','文及翁','宋','宋诗','song-poetry','','[]','開山鑿石天無際，釣水耕雲地有餘。',32,'全唐诗/poet.song.229000.json','["開山鑿石天無際，釣水耕雲地有餘。", "金鼎莫傳添汞法，墨池且問太玄書。"]'),
('7a4110ef-4613-4b8c-a152-2824a0e86201','次回仙韻  其二','文及翁','宋','宋诗','song-poetry','','[]','形棲枯槁元寂寞，跡寄榴皮特有餘。',32,'全唐诗/poet.song.229000.json','["形棲枯槁元寂寞，跡寄榴皮特有餘。", "欲喚回仙談往事，直須癭相認天書。"]'),
('2184842c-ba75-409f-ba17-ae16b2ffd2c1','重華巖','郭鳳','宋','宋诗','song-poetry','','[]','重華人逸夏商前，奚取名巖紫洞巔。',64,'全唐诗/poet.song.229000.json','["重華人逸夏商前，奚取名巖紫洞巔。", "深入纔如窺寸管，仰瞻早已到中天。", "仙田有跡閑芳草，韶樂無聲寄滴泉。", "遐想溫恭遊古昔，恍如瞻對聽虞弦。"]'),
('96b5897e-6300-4ec6-98d3-1b0066b302e4','舜廟','郭鳳','宋','宋诗','song-poetry','','[]','雲封舜冢杳難尋，徒取箾韶索九陰。',64,'全唐诗/poet.song.229000.json','["雲封舜冢杳難尋，徒取箾韶索九陰。", "學講執中憑古籍，道傳精一抱遺心。", "五臣山拱如班瑞，二女峯和似鼓琴。", "英爽不磨天地老，萬年悲淚植篁琳。"]'),
('0c85c935-ffc4-4842-a15a-9a819ebc420c','句','郭鳳','宋','宋诗','song-poetry','','[]','遺響簫韶猺尚奏，啼痕湘竹淚新飄。',16,'全唐诗/poet.song.229000.json','["遺響簫韶猺尚奏，啼痕湘竹淚新飄。"]'),
('c5c7569c-3ce0-457f-b78e-fa65b67e598c','題元實弟姚山別業','孫炳炎','宋','宋诗','song-poetry','','[]','別業倚嶙峋，幽居寓目新。',48,'全唐诗/poet.song.229000.json','["別業倚嶙峋，幽居寓目新。", "閑花繁覆砌，靜燕語通人。", "野翠生窗曉，林香入戶春。", "願因張老祝，持以對芳辰。"]'),
('34b2c8c1-7568-4958-8d1a-ca78f4f029ac','句','尹棟','宋','宋诗','song-poetry','','[]','白蘋影蘸無痕水，黄菊香催未了詩。',16,'全唐诗/poet.song.229000.json','["白蘋影蘸無痕水，黄菊香催未了詩。"]'),
('c59a1c0a-c9d0-4bcc-bf22-8927c6cc9ff7','春晚','危昭德','宋','宋诗','song-poetry','','[]','晴天楊柳絲千緒，淡月梨花玉一庭。',32,'全唐诗/poet.song.229000.json','["晴天楊柳絲千緒，淡月梨花玉一庭。", "又是東風去時節，數聲啼鳥不堪聽。"]'),
('59119c94-2cca-4740-ac62-8cedad4eeafb','吳越王廟','徐起濱','宋','宋诗','song-poetry','','[]','天晴四塞靄蒼蒼，古殿秋陰下夕陽。',64,'全唐诗/poet.song.229000.json','["天晴四塞靄蒼蒼，古殿秋陰下夕陽。", "急管向傳流水咽，殘碑空覆落花香。", "綿坳錢庫遺千載，澗藻溪毛祀一鄉。", "玉輦不遊芳草合，屯雲翠蓋寄寒螿。"]'),
('a9b08907-018d-4a5f-998c-3f025bfc7e43','廣德早行','潘希白','宋','宋诗','song-poetry','','[]','草屨穿籬過，衣濕槿花露。',48,'全唐诗/poet.song.229000.json','["草屨穿籬過，衣濕槿花露。", "千里浙東人，今踏江南路。", "曉程猶带夜，衆星照高樹。", "家中猶未醒，夢我青雲去。"]'),
('ec112104-a95f-44de-8323-6317136d136e','送蔣朴之維陽','潘希白','宋','宋诗','song-poetry','','[]','隋家天子愛揚州，四十離宮取次遊。',64,'全唐诗/poet.song.229000.json','["隋家天子愛揚州，四十離宮取次遊。", "荆棘久迷秦隴路，柳絲空拂汴河流。", "君才清似庾開府，世事難於孫仲謀。", "莫爲青衫怯騎馬，却將風景付閒愁。"]'),
('84a276be-dd62-4cd4-96e8-c25c093c83a4','積靄','潘希白','宋','宋诗','song-poetry','','[]','積靄收殘雨，千峯在小樓。',24,'全唐诗/poet.song.229000.json','["積靄收殘雨，千峯在小樓。", "忽然空遠思，野服上漁舟。"]'),
('c7377a60-4b75-43fa-9c9d-ae0b254ea3a6','入南溪','潘希白','宋','宋诗','song-poetry','','[]','沙頭落月照蓬低，杜宇誰家樹底啼。',32,'全唐诗/poet.song.229000.json','["沙頭落月照蓬低，杜宇誰家樹底啼。", "舟子不知人未起，載將殘夢上青溪。"]'),
('57cf35f4-b542-4c83-872a-a996ea43d163','凉夜','潘希白','宋','宋诗','song-poetry','','[]','凉夜無雲星自流，池塘促織早知秋。',32,'全唐诗/poet.song.229000.json','["凉夜無雲星自流，池塘促織早知秋。", "遠更不受重城隔，時逐西風到小樓。"]'),
('ce6e8fe8-2833-462e-a3b6-61494b4bba7d','題雲山圖','潘希白','宋','宋诗','song-poetry','','[]','谷口無人烟樹迷，雨添新瀑下前溪。',32,'全唐诗/poet.song.229000.json','["谷口無人烟樹迷，雨添新瀑下前溪。", "思家只作歸程看，疑有春深杜宇啼。"]'),
('24034c0d-8063-43bf-a204-92e8ed84bdd2','一字天','蔡公亮','宋','宋诗','song-poetry','','[]','石室陰幽却朗然，仰窺長罅見清玄。',32,'全唐诗/poet.song.229000.json','["石室陰幽却朗然，仰窺長罅見清玄。", "不知誰把如椽筆，畫出光明一字天。"]'),
('af58279c-c199-402b-b1c1-facba1658398','挽故知容州朝請陶公','胡文舉','宋','宋诗','song-poetry','','[]','孤松挺挺凜高風，萬語形容不盡中。',32,'全唐诗/poet.song.229000.json','["孤松挺挺凜高風，萬語形容不盡中。", "獨指平塘塘上水，水之清處儼如公。"]'),
('1179b54b-b1ff-4da9-9996-0a25647fd5a2','楚塞樓','黄播','宋','宋诗','song-poetry','','[]','樓上何由楚塞名，楚人曾此設重扃。',32,'全唐诗/poet.song.229000.json','["樓上何由楚塞名，楚人曾此設重扃。", "固知宇宙同文軌，聊把江山作障屏。"]'),
('741b2cf3-2962-4134-a5d3-ea6cdcad7e85','題關夫子','趙崇璉','宋','宋诗','song-poetry','','[]','天挺孤忠世所欽，桃園口血誓堅金。',64,'全唐诗/poet.song.229000.json','["天挺孤忠世所欽，桃園口血誓堅金。", "單刀萬古英雄膽，明燭一生節義心。", "蜀漢史書傳不朽，春秋廟祀有餘歆。", "當年無奈曹孫在，今日曹孫何處尋。"]'),
('3ea51d41-8058-4600-8bc2-930ad44252e8','題曹孝娥','趙崇璉','宋','宋诗','song-poetry','','[]','孝女方童丱，哀誠動鬼神。',48,'全唐诗/poet.song.229000.json','["孝女方童丱，哀誠動鬼神。", "父沈迷死所，己不愛其身。", "蒼檜根泉壤，靈祠食水濱。", "中郎八個字，惱得老奸人。"]'),
('c341bbab-70bc-4492-aa67-f7549f37a221','題兩橋','趙崇璉','宋','宋诗','song-poetry','','[]','一溪夾道枕流水，上有兩橋橫絕流。',64,'全唐诗/poet.song.229000.json','["一溪夾道枕流水，上有兩橋橫絕流。", "烏鵲互飛銀漢夜，彩虹交映玉潭秋。", "東西雨過苔痕潤，左右晴分浪影收。", "誰是當年題柱者，還應並駕到瀛洲。"]'),
('84e85d17-ba75-416e-a59c-e8dde96ba5e2','挽胡季昭','林起鰲','宋','宋诗','song-poetry','','[]','直節槃槃古樹平，綱常山重一身輕。',64,'全唐诗/poet.song.229000.json','["直節槃槃古樹平，綱常山重一身輕。", "歷陳高廟神靈語，願法周公日月更。", "飛霧墮鳶遷客憾，漏泉疏爵大君明。", "百年富貴端能幾，天壤無窮獨令名。"]'),
('77bc28e9-f8e1-4056-9bd2-33b828eb73ed','與永嘉僚友餞別','趙良坦','宋','宋诗','song-poetry','','[]','霏霏細雨濕溪橋，雨霽溪清野趣饒。',64,'全唐诗/poet.song.229000.json','["霏霏細雨濕溪橋，雨霽溪清野趣饒。", "把臂忽驚分袂早，登程不憚去途遥。", "馬嘶煙樹和愁慘，帆掛仙舟類羽飄。", "不盡尊間賢聖酒，何時重對此酕醄。"]'),
('21d80be1-a8bd-4faa-a5a4-72d0dfd295e7','獄中附家二首  其一','趙良坦','宋','宋诗','song-poetry','','[]','不才離別已多時，脈脈關河入夢思。',64,'全唐诗/poet.song.229000.json','["不才離別已多時，脈脈關河入夢思。", "萬種閒情詩易遣，一腔愁緒酒難移。", "風迥過雁鄉書斷，月滿圜扉夜漏遲。", "臣子立身忠與孝，此心期不愧丹墀。"]'),
('5931c8e1-7dda-4660-bb48-f7e8b7b7fd98','獄中附家二首  其二','趙良坦','宋','宋诗','song-poetry','','[]','一著南冠二載餘，安危不必問何如。',64,'全唐诗/poet.song.229000.json','["一著南冠二載餘，安危不必問何如。", "精金百鍊鋼還銳，勁竹三冬節不枯。", "對月欲同鵑带血，臨風會有雁傳書。", "瓦杯冷落孤燈裏，幾度吞聲祇自吁。"]'),
('c3e53250-58ef-42af-a57d-a8260c014b12','探禹穴感懷','趙與緡','宋','宋诗','song-poetry','','[]','神禹宏疏鑿，流傳山海經。',108,'全唐诗/poet.song.229000.json','["神禹宏疏鑿，流傳山海經。", "披覽未爲足，時騎李白鯨。", "是日輕飆起，翛然天籟鳴。", "孤峰带江浙，突兀地軸橫。", "振衣履絕頂，盤踞雄殿亭。", "群峯百里外，拱護頼衆星。", "乃信王氣鍾，根深奕葉生。", "厥後卧薪者，會稽棲復興。", "此義久懵懵，寂寞羞山陵。"]'),
('555875ab-d435-442a-8a04-7a4275e4ae47','訪劉漢英','趙與緡','宋','宋诗','song-poetry','','[]','無情歲月迅飛梭，却笑浮生慮更多。',32,'全唐诗/poet.song.229000.json','["無情歲月迅飛梭，却笑浮生慮更多。", "最羨君能尋舊業，半溪春雨一漁蓑。"]'),
('149cd0bb-f863-42f7-a7db-0628dbadbfda','游洞霄紀實','馬元演','宋','宋诗','song-poetry','','[]','甲寅良月初，爲捧帥垣檄。',288,'全唐诗/poet.song.229000.json','["甲寅良月初，爲捧帥垣檄。", "遍走三蕩所，村落怪荒寂。", "人謂白昇里，杭邑纔咫尺。", "杭有洞霄宮，神仙其窟宅。", "慣是名勝游，不許俗眼識。", "余雖一俗吏，心實慕名德。", "癡兒官事了，此行烏可惜。", "天氣暖如春，得意馬蹄疾。", "僕夫嗟况瘁，告我請休息。", "止宿蕭市中，明朝辨行色。", "未曉垂玉繩，向風嘶金勒。", "行行十數里，漸漸仙境出。", "始見九鎖峯，窮眸望不極。", "一似天爲門，四山作扃鐍。", "雲烟一齊起，松檜萬古碧。", "巖洞是處有，名字難盡憶。", "入拜大有庭，奇特更奇特。", "洞天與福地，它山得其一。", "惟此爲兩全，四字揭奎畫。", "主人貝道士，高志頗嗜客。", "引謁帝宸殿，金釘朱戶飾。", "出示御書經，鳳篆龍章筆。", "拜手拈瓣香，舉頭看近日。", "既見撫掌泉，又觀松花石。"]'),
('3834723b-e0db-4d0e-98bb-ba2038fae418','題二陸祠','陳琰','宋','宋诗','song-poetry','','[]','塵暗香殘二陸祠，可憐詞藻妙當時。',32,'全唐诗/poet.song.229000.json','["塵暗香殘二陸祠，可憐詞藻妙當時。", "聯鑣入洛成何事，一段淒涼鶴不知。"]'),
('b336b4cc-1d6f-44aa-84b2-518c6536d5eb','登法華臺','陳琰','宋','宋诗','song-poetry','','[]','流水西來遶亂山，山色曲折幾重灘。',64,'全唐诗/poet.song.229000.json','["流水西來遶亂山，山色曲折幾重灘。", "烟雲出入搜尋易，人世興亡入畫難。", "南楚歸舟牽客思，西風脫葉轉秋寒。", "年華漸晚邊城遠，凝望中天更倚欄。"]'),
('06b88734-31f3-434e-b64a-df63a30f1a62','遊澤山','汪翔龍','宋','宋诗','song-poetry','','[]','獨俯空堂夜，無人境自寬。',48,'全唐诗/poet.song.229000.json','["獨俯空堂夜，無人境自寬。", "高風河影動，斜月竹身寒。", "潮海秋聲闊，山林客夢安。", "坐來更幾點，北斗挂闌干。"]'),
('d4d44646-8da8-4ba7-a432-55577d0377d7','訪黄吏部不值','汪翔龍','宋','宋诗','song-poetry','','[]','一鏡湖光半壁山，主人何往客來觀。',64,'全唐诗/poet.song.229000.json','["一鏡湖光半壁山，主人何往客來觀。", "閑蝶自專花富貴，幽禽如語竹平安。", "烟雲變化草木媚，日月往來天地寬。", "何當共整登臨屐，更上崔嵬絕頂看。"]'),
('4af92d2d-35c7-4992-b840-700c730ae7bc','題靈山絹機石','梅應發','宋','宋诗','song-poetry','','[]','山澗來湍流，媼神閟崛奇。',96,'全唐诗/poet.song.229000.json','["山澗來湍流，媼神閟崛奇。", "不作江湖迥，縠水清而漪。", "異哉靈山靈，幻此天然機。", "杼軸馳紅女，朝朝忙繭絲。", "不見玉指勞，便製鮫室衣。", "民家得此練，應寬縷征期。", "兩岸蘚磴滑，誰敢拭眼窺。", "却宜就暑飲，六月霜雪飛。"]'),
('245a0dfe-eed2-4914-b265-da4306cec83f','西湖','陳大震','宋','宋诗','song-poetry','','["\u897f\u6e56"]','有湖光處有山多，獨此平坡玉一窩。',64,'全唐诗/poet.song.229000.json','["有湖光處有山多，獨此平坡玉一窩。", "天下比來幾西子，水中曾見百東坡。", "不隨巨浸熏爲瘴，肯爲飛廉鼓作波。", "莫作無根潢潦看，兩支流出萬囷禾。"]'),
('67477ae2-21d2-40ba-8ff0-0323b8748478','句','陳大震','宋','宋诗','song-poetry','','[]','海濱推老大，粹行比珩璜。',12,'全唐诗/poet.song.229000.json','["海濱推老大，粹行比珩璜。"]'),
('0ba01fd5-a8ce-4b79-a41e-a181426ebecd','句','黄猶','宋','宋诗','song-poetry','','[]','遷屋避嫌明暗漏，買田分券便比鄰。',16,'全唐诗/poet.song.229000.json','["遷屋避嫌明暗漏，買田分券便比鄰。"]'),
('b3409485-d7d2-414f-91f4-927cfc99b362','挽故知容州朝請舅  其一','樊夢辰','宋','宋诗','song-poetry','','[]','人物晨星似，誰歟硬脊梁。',48,'全唐诗/poet.song.229000.json','["人物晨星似，誰歟硬脊梁。", "高風思靖節，流派到平塘。", "勇向急流退，歸來三徑荒。", "未爲先懶句，寄傲益增光。"]'),
('396c6513-ceb3-431e-a8f7-ebb2bf2efb8d','挽故知容州朝請舅  其二','樊夢辰','宋','宋诗','song-poetry','','[]','利慾嗟瀾倒，沈淪幾縉紳。',48,'全唐诗/poet.song.229000.json','["利慾嗟瀾倒，沈淪幾縉紳。", "頹波障流俗，砥柱頼斯人。", "高節標時望，清風濯世塵。", "聖朝公史筆，卓行傳名臣。"]'),
('8c3b46c5-d8d5-465b-b479-1c9cd51f58d3','挽故知容州朝請陶公章二首  其一','易中行','宋','宋诗','song-poetry','','[]','平塘古君子，出處一淵明。',48,'全唐诗/poet.song.229000.json','["平塘古君子，出處一淵明。", "詩句月般好，宦情雲樣輕。", "從教五馬貴，不博幾鷗輕。", "滿目西山恨，遥途駐降旌。"]'),
('477e5793-1503-47b3-99d7-333e470b7f6f','挽故知容州朝請陶公章二首  其二','易中行','宋','宋诗','song-poetry','','[]','顧予生最後，相去又臨川。',48,'全唐诗/poet.song.229000.json','["顧予生最後，相去又臨川。", "欠識先生面，幸親令子賢。", "典型端有自，衣鉢豈無傳。", "德似君家好，清修一節堅。"]'),
('bdca3092-a053-454f-bcbd-e8ae9779085b','澹山巖','釋紹玨','宋','宋诗','song-poetry','','[]','使君得佳句，簡存如猗那。',24,'全唐诗/poet.song.229000.json','["使君得佳句，簡存如猗那。", "著之巖石中，千古不可磨。"]'),
('1c2b9568-2eea-413d-a27a-ad82b1a4c198','諷臨安試','淳祐士人','宋','宋诗','song-poetry','','[]','南省觀圖喪一名，補闈又試萬人英。',64,'全唐诗/poet.song.229000.json','["南省觀圖喪一名，補闈又試萬人英。", "兩重門閾如天險，十有七人倒地橫。", "誰設秦阬來貢院，枉教唐士夢登瀛。", "雲山萬里家何在，月白風清鬼哭聲。"]'),
('67df6c01-96d0-411e-acb5-964f8fe354ad','幽居','戴某','宋','宋诗','song-poetry','','[]','幽棲纔一室，意足便爲安。',48,'全唐诗/poet.song.229000.json','["幽棲纔一室，意足便爲安。", "片石星霜老，八窗風月寒。", "已無蝸角累，自號鹿門看。", "清夜誰同語，橫琴試一彈。"]'),
('2b3a7804-eafe-4035-82ce-d45401c7dba5','題化龍山','朱真人','宋','宋诗','song-poetry','','[]','郭外郊西柳色芽，東流注目浩無涯。',64,'全唐诗/poet.song.229000.json','["郭外郊西柳色芽，東流注目浩無涯。", "江明白白紅紅樹，春在三三兩兩家。", "幾度來臨逢社燕，一樽相對到昏鴉。", "此邦物色吟成畫，高謝山中景致嘉。"]'),
('eba22a17-e7dd-457f-bb30-084575baf85f','題泠然洞  其一','朱真人','宋','宋诗','song-poetry','','[]','江山秀麗有奇峯，雲水悠悠物外通。',32,'全唐诗/poet.song.229000.json','["江山秀麗有奇峯，雲水悠悠物外通。", "容足安夷尋達士，無緣寄語在乘風。"]'),
('5370e996-74e9-4f3d-8c49-759c8b148edd','題泠然洞  其二','朱真人','宋','宋诗','song-poetry','','[]','不踏輕紅塵，扁舟寄此身。',48,'全唐诗/poet.song.229000.json','["不踏輕紅塵，扁舟寄此身。", "江湖雙短鬢，天地一閒人。", "換酒穿紅鯉，調羹芼紫蓴。", "醉來歌一曲，流韻滿青蘋。"]'),
('4d7177c9-ad54-4557-8157-7a263b732a4c','白頭吟','林泳','宋','宋诗','song-poetry','','[]','彈却眼中淚，自唱白頭吟。',84,'全唐诗/poet.song.229000.json','["彈却眼中淚，自唱白頭吟。", "借君向時耳，明妾今朝心。", "身苦尚可忍，心苦不可禁。", "妾心似妾鏡，對景長相尋。", "君心似君琴，轉手成別音。", "失身妾命薄，輕身妾恨深。", "再唱白頭吟，擊碎青玉簪。"]'),
('5c2c78b9-2333-48f0-97a1-b45d1b888d57','劉直夫之入道今復逢衣余飲之酒','林泳','宋','宋诗','song-poetry','','[]','脫了紫霞衣，琴書欲傍誰。',48,'全唐诗/poet.song.229000.json','["脫了紫霞衣，琴書欲傍誰。", "焚香懶持咒，銜袖旋吟詩。", "無本窮應悔，知章夢已遲。", "梅寒不堪折，斗酒謾澆之。"]'),
('97819928-06e9-4cdf-84b2-f3564282ee2d','蔬餐','林泳','宋','宋诗','song-poetry','','[]','山人藜莧慣枯腸，上頓時憑般若湯。',64,'全唐诗/poet.song.229000.json','["山人藜莧慣枯腸，上頓時憑般若湯。", "折項葫蘆初熟美，著毛蘿蔔久煨香。", "炊粱剪韭貧聊辦，煮餠澆葱病未嘗。", "晦叔十齋從客笑，空房巾鉢似支郎。"]'),
('5cd0eb8d-f699-4f0d-a165-d516a466f878','宿囊山懷堅師','林泳','宋','宋诗','song-poetry','','[]','伏虎巖頭向上層，袈裟幾度憶同登。',32,'全唐诗/poet.song.229000.json','["伏虎巖頭向上層，袈裟幾度憶同登。", "薜荔石屋應無恙，風雨誰明徹夜燈。"]'),
('7a90f395-578c-44cf-be6d-e5e409076fe2','贈俞竹心','林泳','宋','宋诗','song-poetry','','[]','避雨君平肆，相親一笑邊。',48,'全唐诗/poet.song.229000.json','["避雨君平肆，相親一笑邊。", "我歌大司命，君說小行年。", "傾蓋多豪貴，掀簾半醉眠。", "自言謀竹隠，聊覓印山錢。"]'),
('6ddffa45-e13c-46f3-b144-3b088b0ef78d','宿赤岸寄太初弟','林泳','宋','宋诗','song-poetry','','[]','橘樹繞溪邊，人家一簇烟。',48,'全唐诗/poet.song.229000.json','["橘樹繞溪邊，人家一簇烟。", "急灘聽似雨，低閣坐如船。", "遠客思親語，癡兒望叔憐。", "愁來吟未了，燈火已催眠。"]'),
('4f30ffc5-7f23-4048-86c3-0f5b47833881','揚州雜詩  其一','林泳','宋','宋诗','song-poetry','','[]','落日吟詩望戍樓，烟花空憶古揚州。',32,'全唐诗/poet.song.229000.json','["落日吟詩望戍樓，烟花空憶古揚州。", "開明橋下千家市，但見朝朝掛髑髏。"]'),
('be1a9a3c-a586-4002-84b3-c1a74bf09f04','揚州雜詩  其二','林泳','宋','宋诗','song-poetry','','[]','角聲吹月上城頭，薄酒千杯不療愁。',32,'全唐诗/poet.song.229000.json','["角聲吹月上城頭，薄酒千杯不療愁。", "要覓當年杜書記，梔燈數朵竹西樓。"]'),
('7df1551b-02a8-4f20-8bc3-83e519ba39e0','揚州雜詩  其三','林泳','宋','宋诗','song-poetry','','[]','雄勇將軍赴上流，三千選士一時休。',32,'全唐诗/poet.song.229000.json','["雄勇將軍赴上流，三千選士一時休。", "營中婦女支官料，猶道兒郎在鄂州。"]'),
('468eb237-a3b6-4070-b574-dfc0027ac6ab','建溪道間  其一','林泳','宋','宋诗','song-poetry','','[]','白鷺沙頭犢子眠，隔溪茅屋起炊煙。',32,'全唐诗/poet.song.229000.json','["白鷺沙頭犢子眠，隔溪茅屋起炊煙。", "漁翁半醉斜陽裏，𣡬了柴門下釣船。"]'),
('41a40118-8f90-4b57-b78c-3efb92384861','建溪道間  其二','林泳','宋','宋诗','song-poetry','','[]','三兩漁舟竹影中，山禽相對哢晴風。',32,'全唐诗/poet.song.229000.json','["三兩漁舟竹影中，山禽相對哢晴風。", "小橋落日無人處，一樹桃花照水紅。"]'),
('83560f03-f7f2-409c-95b2-5fb36ad6b183','寄題涉趣園','林泳','宋','宋诗','song-poetry','','[]','園中日涉趣云何，未老歸來氣亦豪。',64,'全唐诗/poet.song.229000.json','["園中日涉趣云何，未老歸來氣亦豪。", "還有郡人携斗酒，可無社客著方袍。", "詩如信筆真難到，琴不安絃更自高。", "辦取白頭猿鶴畔，莫教松菊只歸陶。"]'),
('c3673bf4-76ff-4ed2-9c0c-908e9985767f','詠塵','林泳','宋','宋诗','song-poetry','','[]','野馬相吹生不盡，海犀能辟語成空。',64,'全唐诗/poet.song.229000.json','["野馬相吹生不盡，海犀能辟語成空。", "高埋旗鼓無邊黑，暗染衣冠日下紅。", "寧可濯纓歌濁水，莫教舉扇障西風。", "渾無一點仙家殿，應在三韓漂渺中。"]'),
('d01b06fd-b1bb-4cdc-8027-901a0c2b50e3','西湖無水','林泳','宋','宋诗','song-poetry','','["\u897f\u6e56", "\u6d1e\u5ead\u6e56"]','紅雲赤日煮清瀾，涸蜯枯魚不忍看。',64,'全唐诗/poet.song.229000.json','["紅雲赤日煮清瀾，涸蜯枯魚不忍看。", "佛老因言滄海變，詩人曾賦洞庭乾。", "弄船渡子愁歸去，枕鼓雷官喚醒難。", "謾道天仙司下土，綠章幾度祝星壇。"]'),
('48efa304-4479-4d06-8b5e-a1fc1017e17f','白蓮  其一','林泳','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖萬景惹詩狂，愛此孤高壓衆芳。',64,'全唐诗/poet.song.229000.json','["西湖萬景惹詩狂，愛此孤高壓衆芳。", "大士化身衣未解，西施浄面鏡慵粧。", "歲寒却有花堪比，水種應無草敢香。", "茉莉素馨方用事，鼻參眼入細平章。"]'),
('b9954b61-99ce-4a57-9b81-7295f95d516f','白蓮  其二','林泳','宋','宋诗','song-poetry','','[]','泰華仙根不染塵，一枝冷淡種尤真。',64,'全唐诗/poet.song.229000.json','["泰華仙根不染塵，一枝冷淡種尤真。", "俗緣夢斷承妃步，色相空來坐佛身。", "凈比禪心月上女，粧羞麗質水邊人。", "紵袍羽扇吟相對，笑殺思王賦洛神。"]'),
('95a10450-cb4a-44f2-98d7-3d261ae64fbd','澹津園看梅','林泳','宋','宋诗','song-poetry','','[]','三嗅清香水月邊，冷然著我玉虛天。',32,'全唐诗/poet.song.229000.json','["三嗅清香水月邊，冷然著我玉虛天。", "何須白雪黄芽訣，只服梅花也解仙。"]'),
('0e49af3c-58a8-456c-b1f4-e3da44a18eca','仙都白鹿歌','林泳','宋','宋诗','song-poetry','','[]','山中白鹿老而靈，有客有客占鹿鳴。',130,'全唐诗/poet.song.229000.json','["山中白鹿老而靈，有客有客占鹿鳴。", "我尋石門不知處，道人出洞歡相迎。", "修行無力有我相，不應信息令渠驚。", "吁嗟至人離諸有，一切相自有心生。", "桃源意行花兩岸，山陰興盡雪三更。", "道人道人苦多事，爾自采藥渠食萍。", "白雲滿洞不須掃，客去客來雲無情。", "我聞神仙游處白鶴叫，試聽夜半空中聲。"]'),
('c7a1d1da-22b4-4ab3-abf3-653765bcdc90','春燕','林泳','宋','宋诗','song-poetry','','[]','鵲結巢隨太歲移，蜂分房占吉時飛。',32,'全唐诗/poet.song.229000.json','["鵲結巢隨太歲移，蜂分房占吉時飛。", "好將說與青臺史，社日祇憑燕子歸。"]'),
('341dcee9-9d88-4841-b39a-a99f512d4dfb','題進道西樓','林泳','宋','宋诗','song-poetry','','[]','買屋西樓好，詩中著卧龍。',48,'全唐诗/poet.song.229000.json','["買屋西樓好，詩中著卧龍。", "青山相對處，黄檗最高峯。", "小儘容書畫，低猶俯竹松。", "市聲不到耳，驚夢是鄰鍾。"]'),
('5edc66fc-54ed-4fc8-be61-3294a9b5afe7','題百五叔自得齋壁','林泳','宋','宋诗','song-poetry','','[]','矮屋匡床兩鬢皤，逍遥委順奈吾何。',64,'全唐诗/poet.song.229000.json','["矮屋匡床兩鬢皤，逍遥委順奈吾何。", "三千世界醉鄉大，十二時中靜坐多。", "疎懶對人如素隠，等閑出語似禪和。", "便須敕斷子平事，來伴溪翁安樂窩。"]'),
('bde954bd-f1ea-4810-83da-7c8b1ac36627','吳江小寺','林泳','宋','宋诗','song-poetry','','[]','當門苔石草毿毿，傍水低牆樹兩三。',32,'全唐诗/poet.song.229000.json','["當門苔石草毿毿，傍水低牆樹兩三。", "邂逅老胡聞好語，禪還不識字人參。"]'),
('c0beb98e-e5d5-4dc8-894b-bf6b0e13b589','雜述','林泳','宋','宋诗','song-poetry','','[]','俗士心胸塞，高人眼目醒。',240,'全唐诗/poet.song.229000.json','["俗士心胸塞，高人眼目醒。", "羅浮夜半日，南極海中星。", "觀心無別法，問夢有前人。", "夜或長於夜，身還外此身。", "萬種由心造，千靈並我生。", "病中聞蟻鬭，悟處喜馿鳴。", "天因斷鼇立，人共倮蟲生。", "積氣元無物，含靈總有情。", "壞衲歸杜窖，還舟上玉天。", "莫疑佛富貴，不信鬼神仙。", "功名祇可笑，時命偶相當。", "雞豕能爲帝，蚍蜉亦有王。", "色界真魔界，仙鄉半醉鄉。", "錯尋醒酒石，癡覓返魂香。", "生白靈觀妙，飛玄隠韻奇。", "不嫌崇有論，却愛步虛詞。", "叱訶鄭玄日，撏扯義山時。", "誰信塚中易，人疑崑裏詩。", "檐夫通筆意，海客悟琴心。", "禪法空中得，書生紙上尋。"]'),
('6567977c-a74f-45d3-b7f0-be8a644c1813','雜述  其一','林泳','宋','宋诗','song-poetry','','[]','關令著黄帝曰，柱史稱聖人云。',28,'全唐诗/poet.song.229000.json','["關令著黄帝曰，柱史稱聖人云。", "俗學謾誇臆說，仙書猶述舊聞。"]'),
('71acf76f-35e0-4b22-984d-3a65ae402408','雜述  其二','林泳','宋','宋诗','song-poetry','','[]','書生鑽故紙裏，衲子轉法華時。',28,'全唐诗/poet.song.229000.json','["書生鑽故紙裏，衲子轉法華時。", "易有九事未解，禪無一句可疑。"]'),
('35df6821-a621-4459-a468-44cab52f3733','雜述  其三','林泳','宋','宋诗','song-poetry','','[]','諂道正爲著相，謗禪未許知音。',28,'全唐诗/poet.song.229000.json','["諂道正爲著相，謗禪未許知音。", "人無第一等眼，佛具若干種心。"]'),
('895b3ffc-c39c-4b5f-b495-c4fe6d4242db','雜述  其四','林泳','宋','宋诗','song-poetry','','[]','竺僊論五百劫，蒙叟誇八千春。',28,'全唐诗/poet.song.229000.json','["竺僊論五百劫，蒙叟誇八千春。", "但聞堯舜氏作，誰識羲黄上人。"]'),
('477f5800-d86b-4e48-bbd6-6673b83f7e16','雜述  其五','林泳','宋','宋诗','song-poetry','','[]','畢方鶴而一足，鬼車鵂而九頭。',28,'全唐诗/poet.song.229000.json','["畢方鶴而一足，鬼車鵂而九頭。", "物怪不知誰使，人身又復何求。"]'),
('dfaaf771-85b1-4b7b-8b1f-7c5ca8c35c46','雜述  其六','林泳','宋','宋诗','song-poetry','','[]','坦腹東床佳婿，企脚北窗真人。',28,'全唐诗/poet.song.229000.json','["坦腹東床佳婿，企脚北窗真人。", "談笑眼前事業，風流膜外精神。"]'),
('47a93e54-2cb6-4e53-abcc-06c944db9395','雜述  其七','林泳','宋','宋诗','song-poetry','','[]','祝柱客曾興刺，斲窗史亦留名。',28,'全唐诗/poet.song.229000.json','["祝柱客曾興刺，斲窗史亦留名。", "我見諸相非相，天何不鳴善鳴。"]'),
('771a0bdd-4916-4910-ae90-756ffddcbbdd','雜述  其八','林泳','宋','宋诗','song-poetry','','[]','文章不宜命達，帝王亦忌時名。',28,'全唐诗/poet.song.229000.json','["文章不宜命達，帝王亦忌時名。", "謾說賦求司馬，曾聞詩殺道衡。"]'),
('bb4fff3d-09cf-4383-a8de-d893d165d3b1','雜述  其九','林泳','宋','宋诗','song-poetry','','[]','唐士有非國語，漢人曾反離騷。',28,'全唐诗/poet.song.229000.json','["唐士有非國語，漢人曾反離騷。", "依本定非筆傑，愛奇自是人豪。"]'),
('9d83acdf-a474-4f44-8b2b-0b0dac801329','雜述  其一○','林泳','宋','宋诗','song-poetry','','[]','徐無黨註歐史，黄仙鶴刻邕書。',28,'全唐诗/poet.song.229000.json','["徐無黨註歐史，黄仙鶴刻邕書。", "身外誰爲知己，眼前我正是渠。"]'),
('e66f36cf-0291-4e40-8720-ca5c0cc6e698','雜述  其一','林泳','宋','宋诗','song-poetry','','[]','號謫仙人太白老，稱村夫子少陵詩。',32,'全唐诗/poet.song.229000.json','["號謫仙人太白老，稱村夫子少陵詩。", "眼花賀監猶差黠，氣性楊公却自癡。"]'),
('d7dcb0e8-04ef-40c3-b495-ab43377dbe13','雜述  其二','林泳','宋','宋诗','song-poetry','','[]','棄稿謾浮瓢裏去，愛詩曾入藏中來。',32,'全唐诗/poet.song.229000.json','["棄稿謾浮瓢裏去，愛詩曾入藏中來。", "護持不信無神物，磨滅應難入劫灰。"]'),
('b3e397a1-13c6-487e-bdec-cdb1ce046c2e','雜述  其三','林泳','宋','宋诗','song-poetry','','[]','壞事曾聞嗔怪鬼，捉囚可不畏天公。',32,'全唐诗/poet.song.229000.json','["壞事曾聞嗔怪鬼，捉囚可不畏天公。", "撫床衛瓘寧非醉，對策劉蕡恐是風。"]'),
('0a8a0ade-5d38-4bbf-ba84-98e41f619ddc','雜述  其四','林泳','宋','宋诗','song-poetry','','[]','仙掌承來求大藥，法身贖得費千金。',32,'全唐诗/poet.song.229000.json','["仙掌承來求大藥，法身贖得費千金。", "兩宗曾誤國家事，百世誰明佛老心。"]'),
('3b342d77-8223-4520-95b6-24b0f421f601','雜述  其五','林泳','宋','宋诗','song-poetry','','[]','興亡豈料秦爲晉，廣莫寧知魏有梁。',32,'全唐诗/poet.song.229000.json','["興亡豈料秦爲晉，廣莫寧知魏有梁。", "萬歲是非同變滅，四維上下可思量。"]'),
('2c8b9d1c-3a24-4bf0-a36d-a5ab5927c29b','雜述  其六','林泳','宋','宋诗','song-poetry','','[]','恨無短劍乘風去，縱有長繩奈日何。',32,'全唐诗/poet.song.229000.json','["恨無短劍乘風去，縱有長繩奈日何。", "謾說千年歸鶴表，最憐九代入雞窠。"]'),
('432b0c64-181d-4c60-83f2-7c83c005f377','雜述  其七','林泳','宋','宋诗','song-poetry','','[]','一念重來如祖忍，三生盡見有圖澄。',32,'全唐诗/poet.song.229000.json','["一念重來如祖忍，三生盡見有圖澄。", "虎雖化女心常在，鷹已爲鳩眼可憎。"]'),
('09a5eac1-b3a9-4579-a15e-d33b136bddb6','雜述  其八','林泳','宋','宋诗','song-poetry','','[]','身無用處法當隠，詩要工時例是窮。',32,'全唐诗/poet.song.229000.json','["身無用處法當隠，詩要工時例是窮。", "東海校書稱釣客，香山學士作漁翁。"]'),
('4ecb1f1c-19f3-4b91-8dc5-084f026547a2','雜述  其九','林泳','宋','宋诗','song-poetry','','[]','俗交毋惜三分話，道眼須看上一層。',32,'全唐诗/poet.song.229000.json','["俗交毋惜三分話，道眼須看上一層。", "太傅莫疑高屐客，都官休厭紫衣僧。"]'),
('b526c766-af9e-4de5-a347-42cb788bf09e','雜述  其一○','林泳','宋','宋诗','song-poetry','','[]','人生作計蛇添足，世事難知卵有毛。',32,'全唐诗/poet.song.229000.json','["人生作計蛇添足，世事難知卵有毛。", "養得元身差快樂，具他法眼始孤高。"]'),
('6f6573ae-f8ba-455e-86ae-a188af9ee9ef','偶題','林泳','宋','宋诗','song-poetry','','[]','世間準擬轉成癡，靜裏高人一笑時。',32,'全唐诗/poet.song.229000.json','["世間準擬轉成癡，靜裏高人一笑時。", "無米竟無二丁傳，有花却有四娘詩。"]'),
('837fbb20-dd44-46a8-a3ab-0f16eb52c248','讀關尹子','林泳','宋','宋诗','song-poetry','','[]','杏壇之外聖人徒，千載遺編喜卷舒。',64,'全唐诗/poet.song.229000.json','["杏壇之外聖人徒，千載遺編喜卷舒。", "一字名篇原易卦，萬言論道廣聃書。", "黄庭丹學分苗裔，紫府仙經得緒餘。", "正爲文章太奇崛，尋常眼目亦疪渠。"]'),
('faf940ef-0fce-4e87-b174-4b60cd474cbd','吟邊','林泳','宋','宋诗','song-poetry','','[]','醉騎鶴背墮紅塵，鏡裏常羞一幅巾。',64,'全唐诗/poet.song.229000.json','["醉騎鶴背墮紅塵，鏡裏常羞一幅巾。", "窮達底論身外事，英雄或是眼前人。", "豈無散木偏能壽，亦有名花不及春。", "三萬六千長短日，吟邊莫遣兩眉顰。"]'),
('da2f45c7-ece9-48f6-9698-c3615e9ec9ca','論詩絕句依老人韻  其一','林泳','宋','宋诗','song-poetry','','[]','刪後紛紛競長雄，詩家妙處幾家同。',32,'全唐诗/poet.song.229000.json','["刪後紛紛競長雄，詩家妙處幾家同。", "門前荒草深三尺，老艾當年說國風。"]'),
('1f0ad603-cb64-4806-a94b-2a55a9e34833','論詩絕句依老人韻  其二','林泳','宋','宋诗','song-poetry','','[]','風騷一脈苦難知，媲白抽黄世不疑。',32,'全唐诗/poet.song.229000.json','["風騷一脈苦難知，媲白抽黄世不疑。", "沈謝諸人聲律起，千年無復性情詩。"]'),
('371345c5-ea6d-4b99-a870-ec99c621eb48','讀老人近詩','林泳','宋','宋诗','song-poetry','','[]','澤國歸來掩竹扉，千年知己十年詩。',64,'全唐诗/poet.song.229000.json','["澤國歸來掩竹扉，千年知己十年詩。", "讀書動地驚天事，得句吟風弄月時。", "紙上聖賢相唯諾，塵邊老宿費思惟。", "縱誇萬首龜堂集，樂處龜堂未必知。"]'),
('07517f98-69da-4d57-8d9c-2ab2ae98cb43','九疑紫霞洞歌','樂雷發','宋','宋诗','song-poetry','','[]','猗歟奇哉，紫霞之洞真天開。',359,'全唐诗/poet.song.229000.json','["猗歟奇哉，紫霞之洞真天開。", "千變萬狀不可述，恍疑幻出壺中之蓬萊。", "湘濱兩姝不敢到，悵望蒼梧雲縹緲。", "爾來三千三百年，斑龍空卧金光草。", "我採姹女江華濱，是爲三十六帝之外臣。", "右持綠玉杖，左携紫金經。", "長歌天上謠，一呼開先扃。", "列炬照深窈，懸身事幽討。", "群仙喜我來，驚笑欲絕倒。", "何侯撫我頂，偉遠拍我肩。", "綠華贈我金條脫，安期分我紅景丹。", "借問此何地，指言太虛天。", "翠霞紫雲張寶幄，懸黎結綠盤瓔珞。", "萬疊蒼苔荒石田，誰呼青龍耕紫烟。", "帝獄銅牆未偏識，擬開寶藏紬雲笈。", "嵯峨水際披蓑翁，應是籛鏗釣神龍。", "仙人仙人何多事，驚世駭俗變靈異。", "或跣巨足垂天雲，或卬短趾流沙潯。", "或現姑射處子身，粉霞紅綬藕絲裙。", "或示普陀大士形，或持簪柳垂寶瓔。", "或插鏤象管，或結火齊珍。", "或琢玄圃玉，或布祇園金。", "洞中之深不知幾百里，但見縈紆屈折一里一澗水。", "人言有路通桂林，乘興欲尋日華君。"]'),
('00f36102-ed8d-4496-9066-eba4b8f669d9','烏烏歌','樂雷發','宋','宋诗','song-poetry','','[]','莫讀書，莫讀書，惠施五車今何如。',299,'全唐诗/poet.song.229000.json','["莫讀書，莫讀書，惠施五車今何如。", "請君爲我焚却離騷賦，我亦爲君劈碎太極圖。", "朅來相就飲斗酒，聽我仰天歌烏烏。", "深衣大带講唐虞，不如長纓繫單于。", "吮豪搦管賦子虛，不如快鞭躍的盧。", "君不見前年賊兵破巴渝，今年賊兵屠成都。", "風塵澒洞兮豺虎塞途，殺人如麻兮流血成湖。", "眉山書院嘶哨馬，浣花草堂巢妖狐。", "何人笞中行，何人縛可汗。", "何人丸泥封函谷，何人三箭定天山。", "大冠若箕兮高劍拄頤，朝談回軻兮夕講濂伊。", "綬若若兮印纍纍，九州博大兮君今何之。", "有金須碎作僕姑，有鐵須鑄作蒺藜。", "我當贈君以湛盧青萍之劍，君當報我以太乙白鵲之旗。", "好殺賊奴取金印，何用區區章句爲。", "死諸葛兮能走仲達，非孔子兮孰却萊夷。", "噫，歌烏烏兮使我心不怡。", "莫讀書，成書癡。"]'),
('4d4547d0-be01-4a88-a3fb-823751bbedba','寄雪蓬姚使君','樂雷發','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','贈君昆吾湛盧之寶劍，青雀黄龍之巨航。',132,'全唐诗/poet.song.229000.json','["贈君昆吾湛盧之寶劍，青雀黄龍之巨航。", "懸黎垂棘之美玉，都梁篤耨之名香。", "佳人佳人在何處，濯足洞庭望八荒。", "䔾車馡馡薜芷綠，欲往從之道阻長。", "倚寶劍兮翼軫，膠巨航兮沅湘。", "玉以彰君子潔身之德，香以表騷人流世之芳。", "我所思兮隔秋水，天吳翕忽蛟螭翔。", "佳人佳人蹇誰與，愛而不見心衋傷。"]'),
('025f884c-cdf4-4c7e-ab95-c300cf253a20','胡料院出示車攻圖仍索俚作','樂雷發','宋','宋诗','song-poetry','','[]','九壤卧龍呼不起，乳臭談兵空滿耳。',252,'全唐诗/poet.song.229000.json','["九壤卧龍呼不起，乳臭談兵空滿耳。", "書生未識玉帳經，且抱此圖究終始。", "姬家出車詠，嬴家小戎詩。", "衛家武剛扞突騎，馬家偏廂走羌夷。", "只今車陣無人識，天狗橫空灑腥血。", "胡人以鞍馬爲家，誰遇奔衝展奇策。", "豫章先生今孔明，胸中森羅萬甲兵。", "天衡地軸妙絕識，內陣外陣何縱橫。", "千枝綠沈列虓虎，萬臂黄閒張白羽。", "人言險野難用車，公獨規模掩前古。", "車攻圖，車攻說，八采眉前曾進徹。", "世人苦謗陳濤斜，却向齊門空鼓瑟。", "今朝朱轓富川頭，絕江以北瞻神州。", "李綱政要講車戰，南渡勳業應可收。", "涇水黄，鐵山碎，雙輪快碾幽燕地。", "朗誦先王復古篇，他時此筆猶能繼。"]'),
('1dd9dcc1-d940-40a6-ae34-b0647a517215','壺中天歌贈侯明父','樂雷發','宋','宋诗','song-poetry','','[]','蓋頭即可居，容膝即可安。',172,'全唐诗/poet.song.229000.json','["蓋頭即可居，容膝即可安。", "連雲大厦千萬間，何如壺中別有天。", "壺中何所有，筆牀茶竈葫蘆酒。", "壺中何所爲，目送飛鴻揮園絲。", "窗前祝融老僧竹，壁上九疑狂客詩。", "壺中主人知爲誰，啖棗仙伯雪鶴姿。", "左攬玄微袂，笑移砥柱弄河水。", "右拍長房肩，飽餐麟脯傾玉舷。", "蓬萊山，在何處，勸君且占壺中住。", "不曾上列金馬門，也應不識崖州路。", "探禹穴，浮沅湘。", "脚下塵土鬢上霜，我到壺中如故鄉。"]'),
('362d6993-032f-45fb-b782-e56e20c694c6','謝楊孟溪縣丞惠以章墨','樂雷發','宋','宋诗','song-poetry','','[]','白首侯芭蜀江邊，曾向君家傳太玄。',114,'全唐诗/poet.song.229000.json','["白首侯芭蜀江邊，曾向君家傳太玄。", "射熊草賦留殘墨，想應當日還渠得。", "飄零蕭灑幾世孫，解得膠法舂玄雲。", "物理往來元莫測，後世子孫還舊璧。", "君家所有更贈君，君還贈我何殷勤。", "感君殷勤復三歎，努力西窗磨鐵硯。", "太玄難深吾不爲，願寫誠齋易傳探玄機。"]'),
('53aa2c16-fb1c-4405-a666-feb67c043909','佳人兩章寄許東溪  其一','樂雷發','宋','宋诗','song-poetry','','[]','衡之山，鬰蒼蒼。',58,'全唐诗/poet.song.229000.json','["衡之山，鬰蒼蒼。", "我有佳人，在山之陽。", "木難爲佩兮雲錦爲裳，愛而不見兮我心憂傷。", "安得爲鵾鵬，凌風置君傍。", "衡之山，鬰蒼蒼。"]'),
('29bc7ed2-7bc0-4741-a395-4ff28a21f90b','佳人兩章寄許東溪  其二','樂雷發','宋','宋诗','song-poetry','','[]','衡之江，清且漪。',58,'全唐诗/poet.song.229000.json','["衡之江，清且漪。", "我有佳人，在江之湄。", "朝餐菭蘠兮夕饌江蘺，欲往從之兮我馬虺隤。", "安得爲琴高，沿波與君隨。", "衡之江，清且漪。"]'),
('38fe94ee-e8d7-43d7-9084-ef12a038dd70','登濂溪太極樓','樂雷發','宋','宋诗','song-poetry','','[]','岑樓跨層崖，灌木翳頹沼。',132,'全唐诗/poet.song.229000.json','["岑樓跨層崖，灌木翳頹沼。", "曠哉宇宙心，況茲展遐眺。", "前哲日以遠，川麓被文藻。", "芳甸馥荃蘅，江渚雜鳬鳥。", "亭亭沼中蓮，冉冉庭下草。", "扣寂參太極，撫化領衆妙。", "俗薄神理乖，力柔聖途杳。", "英英考亭翁，反心會天奧。", "萬里粲良言，一誠貫元造。", "勗哉登樓人，畢景盡此道。", "深根復深根，篤行以爲寶。"]'),
('54a255b6-6f8d-4007-a144-58b264bf770c','送程營道官滿赴闕','樂雷發','宋','宋诗','song-poetry','','[]','高旻振爽籟，蒼雁鳴芳洲。',168,'全唐诗/poet.song.229000.json','["高旻振爽籟，蒼雁鳴芳洲。", "傾城餞茂宰，鄉耋羅藻舟。", "茂宰藴淵道，厥源泝伊流。", "字甿振仁策，範俗惇聖猷。", "夷心灼理要，政簡吏統周。", "芳風被儒肆，惠澤淪農疇。", "魯封有馴雉，張廷無訟牛。", "慨茲戒徂兩，離衷鬰綢繆。", "贈我茂叔蓮，紉君晏子裘。", "慶霄𥉻鳳躍，神囿瞻麟遊。", "世道日以隘，民瘼誰克瘳。", "厲志抗遐業，吹萬溥九州。", "揆予忝皇鑒，敷文免征愁。", "行行重行行，夷庚無駐舟。"]'),
('880d2dfc-94aa-4b38-8ab8-954ba0d43024','次韻李監丞月夕閔雨','樂雷發','宋','宋诗','song-poetry','','[]','穜稑旱欲槁，蒺藜秋向榮。',168,'全唐诗/poet.song.229000.json','["穜稑旱欲槁，蒺藜秋向榮。", "哲匠軫民瘵，慨此疚魂明。", "蓐收正秋斂，肥𧔥何縱橫。", "仰霄𥉻蟾曜，聆垤佇鸛鳴。", "彼美玩華光，芳罇酌蘭生。", "崇榭歌窈窕，秀質羅輜軿。", "節序孰不歡，宅生念匪輕。", "同袍正焦灼，對酒何忍傾。", "恤喜限惛智，同茲感陰晴。", "淰淰山雲起，策策林飈驚。", "企彼天瓢潤，弭此農槔聲。", "崇情發翰墨，賞心謝籌觥。", "溥澤乃夙念，穹爵豈所營。", "榮賤有異分，感茲友巖耕。"]'),
('7d43a08c-bfdf-46f3-b5af-09a0f0db69a6','次韻李監丞城西紀游','樂雷發','宋','宋诗','song-poetry','','[]','叫舜問寥闊，詠濂滌塵囂。',192,'全唐诗/poet.song.229000.json','["叫舜問寥闊，詠濂滌塵囂。", "駕言城西遊，慨彼往哲遥。", "儀鳳不可呼，鴐鵝浴清瀟。", "懷哉光風杳，蕙若吹凉飈。", "蒼梧隴雲愁，康廬草木彫。", "豈無人希周，亦有文規姚。", "佔畢末學阻，俗薄神理銷。", "沿流浮伊洛，泝源窺羲堯。", "執中與太極，萬古瞻魁杓。", "察微篤强力，賢聖誠匪遼。", "舜宮翳灌木，濂塾棲叢苕。", "觀乎紀遊作，悟彼進學條。", "蘭卮娛才彥，豈謂磊魂澆。", "得深清賞愜，理勝英藻超。", "揆予果何爲，農野勤耕穮。", "景迫昧見道，曷奉德化昭。"]'),
('0d500abe-5828-4216-bac8-af8ac73c3176','次韻李監丞同劉玉淵游七泉','樂雷發','宋','宋诗','song-poetry','','[]','世變如流水，前哲嗟逝川。',288,'全唐诗/poet.song.229000.json','["世變如流水，前哲嗟逝川。", "良牧隆化本，訪古漫叟泉。", "念茲名泉意，感彼末俗偏。", "淵竇與嵌臼，杖屨聊回旋。", "不識漫叟心，曷誦漫叟篇。", "惻念軫蒼氓，溥澤同一天。", "蟻聚與羔跪，命義當亦堅。", "回邪乃敗德，毋以己欲專。", "夸士五鼎辱，穹爵或自鎸。", "臨流歎澆風，薄言傾酒船。", "浸泉旌吾志，凍泉存舊傳。", "潓𣷡涍汸淔，銘石昭萬年。", "無限感發人，黜指敲墨氈。", "歲月亦云久，古迹埋塵烟。", "泉根石已泐，泉上樹欲仙。", "森戟呵虎士，誰能聽潺湲。", "理義著今古，貴賤俱荒阡。", "今公七泉遊，陵谷尚未遷。", "勵俗振古道，茲誦惡曲圓。", "劉侯同襟期，賡唱揮彩椽。", "漫叟誠有知，騎鯨躍層淵。", "彼哉賊君父，圓曲工求權。", "厲民恣屠斮，巧宦勤攀緣。", "安得激七泉，布作化雨宣。"]'),
('7064430d-1388-4946-a6ab-eb44d37b6be1','送絅齋李監丞赴湖南提舉','樂雷發','宋','宋诗','song-poetry','','[]','吏統久已紊，使選匪易爲。',216,'全唐诗/poet.song.229000.json','["吏統久已紊，使選匪易爲。", "蝎虺何蓁蓁，鴻雁何纍纍。", "持節豈不多，曠職苟所私。", "緬懷紫陽翁，昔使東浙湄。", "陳臬糾官邪，揚仁蘇民疲。", "茲道有先後，哲儒昭令規。", "絅齋寄瀟牧，那懋灼帝知。", "勵廉肅寮寀，反稅驩鄉耆。", "所學藴淵道，寬嚴權理宜。", "茲總全楚境，歌此皇華詩。", "位穹民言邈，壤廣吏蠹滋。", "問俗職所重，簡僚乃政基。", "視聽貴遠周，細微在可遺。", "攬轡戒前路，豈爲好爵縻。", "揆予忝英盼，懷德念別離。", "別離果何念，康濟乃所期。", "懿茲遠大業，肇此咨度時。", "勗哉振英采，慰我湘民思。"]'),
('629f78a4-a13a-40c3-80a4-3a2164ea6453','秋夜感懷','樂雷發','宋','宋诗','song-poetry','','[]','溽露霑灌莽，華月流高旻。',120,'全唐诗/poet.song.229000.json','["溽露霑灌莽，華月流高旻。", "吟嘯嘉此夜，撫化悲蕭辰。", "蕭辰何所悲，遊子多苦辛。", "道峻壯力謝，業遥昌志湮。", "玄鬢日以變，豐景將遂淪。", "堪輿一大宅，羲娥爲旅人。", "卉木互榮落，蛬蟀何吟呻。", "氣隨稚耄變，理勝卹喜均。", "反性樂天爵，測化葆道真。", "撫卷慨往哲，芳猷邈難親。"]'),
('03e757d7-8b15-491b-8f89-61fe745ff9a8','寄雪蓬姚使君','樂雷發','宋','宋诗','song-poetry','','[]','湘鱗六六寄相思，疏柳新蟬想別時。',64,'全唐诗/poet.song.229000.json','["湘鱗六六寄相思，疏柳新蟬想別時。", "今夜各聽三楚雁，秋風又老一年詩。", "梅花且補離騷闕，薏苡應爲史筆知。", "剪竹疑峯新製笛，待衝霜月訪桓伊。"]'),
('6fd4dc2f-497b-42d1-949c-a690ac2e591a','謁山齋先生易尚書','樂雷發','宋','宋诗','song-poetry','','[]','淳熙人物到嘉熙，聽說山齋亦白髭。',64,'全唐诗/poet.song.229000.json','["淳熙人物到嘉熙，聽說山齋亦白髭。", "文字盡傳融水後，精神如戰辟雍時。", "靈椿終不爭朝菌，蓍草惟堪養壽龜。", "細嚼梅花看總義，只應姬老是相知。"]'),
('9eb4b4ee-7aa0-4100-b992-6c4c530a3e54','送桂帥鍾尚書赴召','樂雷發','宋','宋诗','song-poetry','','[]','老依牙纛撚吟髭，又折梅花話別思。',64,'全唐诗/poet.song.229000.json','["老依牙纛撚吟髭，又折梅花話別思。", "五嶺不遮鸞鳳詔，四方都誦鱒魴詩。", "人才晉魏凋零後，國事江淮倥傯時。", "頼有老臣經濟在，快呼桂醑餞篙師。"]'),
('77dce9ba-320f-436b-830a-d6bd1a7d9a85','題鍾尚書北征詩稿','樂雷發','宋','宋诗','song-poetry','','[]','野雉江鷗滿故都，秋風禾黍撚吟鬚。',64,'全唐诗/poet.song.229000.json','["野雉江鷗滿故都，秋風禾黍撚吟鬚。", "六千里外驅旃旆，五十篇中見版圖。", "金鉉尚期扶日御，玉衡終令正天衢。", "書生亦有中原志，那得君王丈二殳。"]'),
('01e30ed2-fc2b-43d8-85db-c28a653ec2e8','呈廣西張提刑','樂雷發','宋','宋诗','song-poetry','','[]','陸續城邊按部歸，梅花隨處撲征騑。',64,'全唐诗/poet.song.229000.json','["陸續城邊按部歸，梅花隨處撲征騑。", "溪山有助吟題遍，獄市無冤訟牒稀。", "竹屋聽猿眠碎月，莎庭引鶴步斜暉。", "莫嫌瘴霧侵湘客，滿路風霜冷枲衣。"]'),
('a87c1126-9ceb-4505-b867-08b5a463fafa','罪言','樂雷發','宋','宋诗','song-poetry','','[]','愁殺瀟濱蟣虱臣，亂山斜照獨含情。',64,'全唐诗/poet.song.229000.json','["愁殺瀟濱蟣虱臣，亂山斜照獨含情。", "人才不似深衣古，國勢如何楮幣輕。", "石燕未蘇湘國旱，木牛那濟蜀川兵。", "幸無杜老流離苦，切莫吟詩到北征。"]'),
('c6f60ddc-13a7-4873-b3ad-cb1532e6e0b0','閒居自遣  其一','樂雷發','宋','宋诗','song-poetry','','[]','雨積桑樞長昔邪，誰能載酒訪揚家。',64,'全唐诗/poet.song.229000.json','["雨積桑樞長昔邪，誰能載酒訪揚家。", "漢庭用少臣今老，魯俗皆冠我獨髽。", "憂國苦無蠲忿草，看書喜對决明花。", "衰頹懶作江湖夢，擬鬢三椏養鬢華。"]'),
('2e3e18af-ee88-4627-b650-2acf07c42da6','閒居自遣  其二','樂雷發','宋','宋诗','song-poetry','','[]','許由溪上小屠蘇，紅樹蒼山對一臞。',64,'全唐诗/poet.song.229000.json','["許由溪上小屠蘇，紅樹蒼山對一臞。", "白髮功名惟劍在，青燈活計并錐無。", "誰言荆楚多奇士，却笑乾坤一腐儒。", "桐帽貂冠俱有分，寄言兒輩莫揶揄。"]'),
('dc55f933-5be8-44c2-8524-59be0303b9d1','寄樓居朱漕','樂雷發','宋','宋诗','song-poetry','','[]','住近江心古寺邊，幅巾應伴浙僧閒。',64,'全唐诗/poet.song.229000.json','["住近江心古寺邊，幅巾應伴浙僧閒。", "官銜自管金陵觀，冠業多依雁宕山。", "出處要留青史看，功名且逐白雲還。", "殷勤爲祝樓居月，好照橫舟漱碧灣。"]'),
('0df1aaf5-8fc1-43d9-9394-e0dd4ee26db2','呈姚雪蓬使君','樂雷發','宋','宋诗','song-poetry','','[]','祝融應自勝崆峒，且讀通書辦聖功。',64,'全唐诗/poet.song.229000.json','["祝融應自勝崆峒，且讀通書辦聖功。", "事可語人甘受謗，詩能名世不嫌窮。", "春邊採藥收湘芷，月下調弦送楚鴻。", "頼有行人碑尚在，棠陰依舊戀東風。"]'),
('b4d91375-6233-441e-ac08-bf1afb216316','雪蓬見示送趙東巖巡部詩','樂雷發','宋','宋诗','song-poetry','','[]','皇華歌徹酒杯忙，澤畔騷翁送范滂。',64,'全唐诗/poet.song.229000.json','["皇華歌徹酒杯忙，澤畔騷翁送范滂。", "琴带衡雲弦索潤，馬餐湘茝轡絲香。", "山中貍豹隨吟旆，部內豺狼入按章。", "却笑詩寒吟骨聳，愁看酬唱挾風霜。"]'),
('f8b97729-9ff2-4d43-9f8b-10e6f34b0921','書蕭千巖集','樂雷發','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','向來楊陸共崢嶸，吟到停雲趣轉清。',64,'全唐诗/poet.song.229000.json','["向來楊陸共崢嶸，吟到停雲趣轉清。", "古似洞庭張雅樂，嚴如即墨斂殘兵。", "茵蔯終不肥方朔，芣苡何堪病冉耕。", "細讀殘編搔白首，未應造物忌詩名。"]'),
('dedab71d-abb8-45d5-8e45-1478c8521c51','滕王閣下賦','樂雷發','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','越𦨰蜀艇亂相偎，風飽千帆带雨開。',64,'全唐诗/poet.song.229000.json','["越𦨰蜀艇亂相偎，風飽千帆带雨開。", "閣上鳴鑾今已往，江頭飛鶩只堪哀。", "柳汀絮滿河豚賤，桃塢花殘石首來。", "應接溪山吾不暇，自憐白髮欠詩才。"]'),
('0af3216e-e9ee-4f91-836d-47aabacd4e74','宿金灘','樂雷發','宋','宋诗','song-poetry','','[]','瀧吏崖翁是賞音，江流泯泯對秋吟。',64,'全唐诗/poet.song.229000.json','["瀧吏崖翁是賞音，江流泯泯對秋吟。", "天蝦撲火帆檣晚，水狗捎魚島嶼深。", "千里庭闈雲滿眼，十年湖海雁驚心。", "今宵客枕清如水，稱讀西山夜氣箴。"]'),
('37c5b761-7d04-4f84-8cbe-531192c67913','寄許介之','樂雷發','宋','宋诗','song-poetry','','[]','惹得詩名遍九州，酒徒棋伴半公侯。',64,'全唐诗/poet.song.229000.json','["惹得詩名遍九州，酒徒棋伴半公侯。", "離騷甘隠魚鱗屋，樂府多傳鳷鵲樓。", "醉葉幾窠藏菊徑，蠹荷三畝護漁舟。", "中原應有樓蘭國，空鎖吳鈎到白頭。"]'),
('fc60b681-4555-4f44-bd4a-98f0aedfeb30','聞邊報寄姚雪蓬','樂雷發','宋','宋诗','song-poetry','','[]','淮烽蜀燧照邊隅，白髮憂時我腐儒。',64,'全唐诗/poet.song.229000.json','["淮烽蜀燧照邊隅，白髮憂時我腐儒。", "楚客汀洲搴杜若，齊王沮澤索茈葫。", "躭吟自愛南遊好，久謫曾謀百事無。", "擬對祝融捫蝨話，何時重捋使君鬚。"]'),
('a124c8c2-89fa-492f-9065-2bafd3cd80a8','寄戴石屏','樂雷發','宋','宋诗','song-poetry','','[]','曾到元郎吟處吟，雪蓬烟艇欠相尋。',64,'全唐诗/poet.song.229000.json','["曾到元郎吟處吟，雪蓬烟艇欠相尋。", "鳳鳴道國空詩句，雁到衡峯只信音。", "拾橡祠邊寒聽雨，紉蘭院裏夜分衾。", "蹇馿倘遂黄花約，鴉觜敲烟共掘參。"]'),
('04fe0477-d51f-4d15-ad15-a0aa88390829','戊戌冬僕客桂林雪中趙叔愚書張司業逢賈島絕句爲寄今冬對雪感而有作','樂雷發','宋','宋诗','song-poetry','','[]','朔風于水浸瓊沙，曾共騷翁理釣槎。',64,'全唐诗/poet.song.229000.json','["朔風于水浸瓊沙，曾共騷翁理釣槎。", "對酒又吟端木葉，論詩還憶款冬花。", "饑能驅我瓶儲罄，老不饒人鏡影華。", "擬喚扁舟尋剡叟，嶺梅瀟菊各天涯。"]'),
('174dc896-46af-4cc2-b3aa-97244fe2bc75','寄仙巢先生鍾尚書','樂雷發','宋','宋诗','song-poetry','','[]','吹香亭上送飛鴻，且把行藏寄蜀桐。',64,'全唐诗/poet.song.229000.json','["吹香亭上送飛鴻，且把行藏寄蜀桐。", "老境只須尋遠志，世途還要避沙蟲。", "公於天地初何憾，道在丘園固未窮。", "曾是轅門投卷客，應憐聽雪卧蕯藭。"]'),
('48e71ebe-7bc4-483b-91f6-9b1ced63ca31','寄蕭大山兄弟','樂雷發','宋','宋诗','song-poetry','','[]','梅花好處共心期，曾擷天葩寄夢思。',64,'全唐诗/poet.song.229000.json','["梅花好處共心期，曾擷天葩寄夢思。", "兄弟自爲千古計，江湖方誦二蕭詩。", "貪泉定喜逢廉吏，倭國何因拜老師。", "賸擬尋君攀桂樹，路遥誰肯借馿騎。"]'),
('d3fe8e55-3ac0-4c71-8a5b-9e8dc5b6e839','送丁少卿自桂帥移鎮西蜀','樂雷發','宋','宋诗','song-poetry','','[]','瓊海收兵玉帳閒，又移齋艦泝涪灣。',64,'全唐诗/poet.song.229000.json','["瓊海收兵玉帳閒，又移齋艦泝涪灣。", "三邊形勢全憑蜀，四路封疆半是山。", "魏將舊聞侵劍閣，漢兵今欲卷函關。", "細傾瑞露論西事，想在元戎指畫間。"]'),
('25a98064-9162-4080-ad17-b98ee5900925','訾家洲','樂雷發','宋','宋诗','song-poetry','','[]','竹塢松灣遍履痕，斷碑無首野苔昏。',64,'全唐诗/poet.song.229000.json','["竹塢松灣遍履痕，斷碑無首野苔昏。", "江山應識前賢事，裴柳今存幾世孫。", "島霧海霞留古意，春猿秋鶴冷騷魂。", "何人會得登臨意，閒嚼梅花伴酒尊。"]'),
('b7a472d6-dd8f-4e45-9f1b-b8d645a3fb95','慈氏閣','樂雷發','宋','宋诗','song-poetry','','[]','崢嶸梵閣礙銀潢，且對畦衣問馬王。',64,'全唐诗/poet.song.229000.json','["崢嶸梵閣礙銀潢，且對畦衣問馬王。", "落日斷雲連楚粵，缺鐘壞像雜梁唐。", "英豪已往雄圖歇，棟宇猶存古意荒。", "惆悵石湖題柱在，倚欄無句獨淒涼。"]'),
('936e991a-d4d6-49b1-941a-12dd30d0210f','雉山寺宋永初中有僧西顒誦法華經于此白雉聽之而化至唐黄梅五祖弟子喜登告祖乞巡禮五祖應以遇雉即止後至此開山本朝王初寮有留題','樂雷發','宋','宋诗','song-poetry','','[]','蘚碑蘿石擁喦扃，獨倚筇枝問大乘。',64,'全唐诗/poet.song.229000.json','["蘚碑蘿石擁喦扃，獨倚筇枝問大乘。", "白雉苦無千歲種，青山空識六朝僧。", "詩傳北岳刊新帖，禪接西淮冷舊燈。", "擬鑿冰泓澆凍硯，禊亭閒借法華謄。"]'),
('2b47d8bc-826e-4c6d-906d-4b447a6c75a3','擬游長沙至零陵忽動歸興','樂雷發','宋','宋诗','song-poetry','','[]','擬尋禹柏過長沙，且泊愚溪問酒家。',64,'全唐诗/poet.song.229000.json','["擬尋禹柏過長沙，且泊愚溪問酒家。", "歲旱可能飛石燕，秋高還看落天蝦。", "乾坤納納催霜鬢，歧路悠悠又菊花。", "惆悵草黄騏驥病，歸心依舊繞烟霞。"]'),
('d4ad5af5-b945-4783-8c1a-a463c99f3876','袁家渴泊舟','樂雷發','宋','宋诗','song-poetry','','[]','往事誰能問水濱，停橈仍是薄西曛。',64,'全唐诗/poet.song.229000.json','["往事誰能問水濱，停橈仍是薄西曛。", "樵漁空自存袁姓，鳬雁何應識柳文。", "釣艇分燈歸客艇，嶺雲拖雨接溪雲。", "楩楠蘭芷今何在，空使行人誤舊聞。"]'),
('5b6d9d35-dad7-4ab6-82cf-d8294b98d6c3','小檥袁家窯竹居買酒','樂雷發','宋','宋诗','song-poetry','','[]','江繞衡門接旅津，鯉魚風歇水粼粼。',64,'全唐诗/poet.song.229000.json','["江繞衡門接旅津，鯉魚風歇水粼粼。", "湘醨三盞澆吟思，瀟碧千竿對老身。", "題筆未能行客醉，典琴不用主人貧。", "隔江誰掉高名麗，滿載鸕鷀捉錦鱗。"]'),
('bb68d203-f480-458b-960a-20e71aa78f17','餞雲壑唐使君赴邕州','樂雷發','宋','宋诗','song-poetry','','[]','𥯨簩竹畔擁雙旌，回首江蘺隔楚汀。',64,'全唐诗/poet.song.229000.json','["𥯨簩竹畔擁雙旌，回首江蘺隔楚汀。", "曾向前賢參學問，且教遠俗識儀型。", "安南兵息塞烽冷，羅殿馬來蠻草青。", "悵望鈴齋何處是，遥瞻朱雀認詩星。"]'),
('d131b38f-e9ba-4c54-b7c7-33aaf8b76c1a','歸侍','樂雷發','宋','宋诗','song-poetry','','[]','石田茅屋野苔春，喜對庭闈話苦辛。',64,'全唐诗/poet.song.229000.json','["石田茅屋野苔春，喜對庭闈話苦辛。", "客路本無如意事，瘴鄉難有却回身。", "且尋農耒耕湘雨，待看天戈洗韃塵。", "門外黄旗邊餉急，可堪杯酒各傷神。"]'),
('5824bf23-c902-4887-ba88-16b81a3ddceb','寄吳茂遠','樂雷發','宋','宋诗','song-poetry','','[]','蘇公堤畔繫吟馿，知在垂楊第幾株。',64,'全唐诗/poet.song.229000.json','["蘇公堤畔繫吟馿，知在垂楊第幾株。", "學校文章如畫餠，朝廷官爵似呼盧。", "春吟應欠梅花在，時事曾言楮幣無。", "惆悵湘湄分袂處，今看細雨長蘼蕪。"]'),
('00cc2275-62a1-46b4-841e-41fea54b4d8b','送史主簿之鄂就辟  其一','樂雷發','宋','宋诗','song-poetry','','[]','囊中秋卷逼唐賢，門外侯芭問太玄。',64,'全唐诗/poet.song.229000.json','["囊中秋卷逼唐賢，門外侯芭問太玄。", "才大豈堪棲枳棘，官清應只友蘭荃。", "湘行又泛君山月，淮績曾衝赤壁烟。", "擬借從君新句看，試尋黄帽寄綱船。"]'),
('72c88fbb-a2f7-4124-9704-4d64c6c7e3db','送史主簿之鄂就辟  其二','樂雷發','宋','宋诗','song-poetry','','[]','宦途捷徑在三邊，且住吟船贈馬鞭。',64,'全唐诗/poet.song.229000.json','["宦途捷徑在三邊，且住吟船贈馬鞭。", "壯士苦無橫草志，將軍還用撒花錢。", "韃兵猶未回燕鴨，蜀耗何應問杜鵑。", "今日送君無別話，看隨郤縠洗狼烟。"]'),
('62341789-e85c-416f-81a1-a6051e69612a','送邵瓜坡試湖南漕舉','樂雷發','宋','宋诗','song-poetry','','[]','槐花匝路促湘行，閩賦唐詩舊擅聲。',64,'全唐诗/poet.song.229000.json','["槐花匝路促湘行，閩賦唐詩舊擅聲。", "有志向曾言國事，論心何止在科名。", "畢方夜煽杭都火，大角秋纏蜀道兵。", "莫作腐儒場屋話，琅玕滿腹正須呈。"]'),
('f9777f39-39af-4ce1-8595-ed26c5bd2357','送李公洛游臨武','樂雷發','宋','宋诗','song-poetry','','[]','嶺梅瀟菊兩關情，歲晚江湖載酒行。',64,'全唐诗/poet.song.229000.json','["嶺梅瀟菊兩關情，歲晚江湖載酒行。", "客路欲依嚴挺子，瘴鄉已老少游兄。", "瓦盆且話田家事，肉食誰通鈍漢名。", "惆悵韓張亭畔路，雪鞭風帽又東征。"]'),
('6997b0e8-461e-4670-b592-1ab8ac5b0f55','贈江華熊伯巖','樂雷發','宋','宋诗','song-poetry','','[]','堂萱營柳伴吟哦，黄綬仙翁鬢未皤。',64,'全唐诗/poet.song.229000.json','["堂萱營柳伴吟哦，黄綬仙翁鬢未皤。", "對客不矜名第貴，輸心惟在簡編多。", "江頭魴鯉香晨膳，境內鴟梟冷夜窠。", "湘國詩盟今寂寞，衰頹猶喜識陰何。"]'),
('382ba5c6-1fdf-438a-81a9-ab21c06b2fe2','江華送熊清父遊廣州時予有衡陽之役','樂雷發','宋','宋诗','song-poetry','','[]','邂逅陽華且酒壺，海鵬衡雁各征途。',64,'全唐诗/poet.song.229000.json','["邂逅陽華且酒壺，海鵬衡雁各征途。", "閒身俱被饑寒役，老境還堪離別無。", "鄉夢定應思款段，客吟何用說娵隅。", "曾從仙叟參玄訣，好訪安期採澗蒲。"]'),
('76c1f5cd-e052-4a70-b8de-decbaaf01492','喜李景魏就熊伯巖縣尉招','樂雷發','宋','宋诗','song-poetry','','[]','長歌白石草廬深，今抱園絲就賞音。',64,'全唐诗/poet.song.229000.json','["長歌白石草廬深，今抱園絲就賞音。", "溫飽不爲兒輩計，行藏端在古人心。", "鱣魚堂上春開帳，鸂鶒灘前夜對衾。", "擬挂奚囊梅下聽，謫仙應共隠仙吟。"]'),
('5f861803-9b11-416e-8559-65fd4a39299c','送友人之辰州覲省','樂雷發','宋','宋诗','song-poetry','','[]','跕鳶東畔瘴雲低，山徑如梯去馬遲。',64,'全唐诗/poet.song.229000.json','["跕鳶東畔瘴雲低，山徑如梯去馬遲。", "正則自吟皇樹頌，廣微惟誦白華詩。", "春風採藥桃花國，落日尋碑薏苡祠。", "覓得丹砂能寄否，溪亭送客鬢毛衰。"]'),
('bd47be9f-45d1-4ff4-9dbe-b048c2be8cf7','謁李梅亭','樂雷發','宋','宋诗','song-poetry','','[]','九拔鯨牙氣貫虹，玉堂歸只守文窮。',64,'全唐诗/poet.song.229000.json','["九拔鯨牙氣貫虹，玉堂歸只守文窮。", "世無真魏扶吾道，人以乾淳望此翁。", "大地精靈藏筆下，國家命脈寄山中。", "縕袍羸駟崇仁路，正擬登門聽擊蒙。"]'),
('0e6f6fbf-303a-45f8-9296-536f3072da42','代送徐侍郎赴召','樂雷發','宋','宋诗','song-poetry','','[]','大厦誰堪任棟梁，試留齋艦問行藏。',64,'全唐诗/poet.song.229000.json','["大厦誰堪任棟梁，試留齋艦問行藏。", "朝廷議論如春雨，吳蜀人才似夕陽。", "三漸何曾投砭劑，五寒今望起膏肓。", "擬看相業磨崖在，却到浯溪話別觴。"]'),
('3c4053be-44a2-4e7a-a243-c87837bdf05f','聽友人談蜀道事','樂雷發','宋','宋诗','song-poetry','','[]','石棧天梯蕩戰塵，誰驅哨馬滿峨岷。',64,'全唐诗/poet.song.229000.json','["石棧天梯蕩戰塵，誰驅哨馬滿峨岷。", "盡看烏犬爲君子，誰問沙蟲化小人。", "韃智豈應强兀朮，蜀材正自欠吳璘。", "細吟猛虎長蛇句，空對西風淚滿巾。"]'),
('4fdb062b-5cf9-411d-9cc2-a93539e96e1c','送廣州劉叔治倅欽州兼守事','樂雷發','宋','宋诗','song-poetry','','[]','天涯亭畔擁提屏，丹荔黄柑滿去程。',64,'全唐诗/poet.song.229000.json','["天涯亭畔擁提屏，丹荔黄柑滿去程。", "皂蓋却迎新別駕，碧幢應憶老先生。", "象蹄印雨歸蠻國，鯨鬣掀潮撼海城。", "曾是鄉賢分守處，試尋醉石共題名。"]'),
('98445527-66bd-44df-8f49-870d004715bf','逢熊季可','樂雷發','宋','宋诗','song-poetry','','[]','暮雲春樹飽相思，今共秋風捋白髭。',64,'全唐诗/poet.song.229000.json','["暮雲春樹飽相思，今共秋風捋白髭。", "北闕未知鸚鵡賦，南州空誦鷓鴣詩。", "旗亭尚喜髠能飲，客路誰知朔獨饑。", "頼有湘翁生計在，且吟九辨擷江蘺。"]'),
('e2f02672-999c-479b-9a91-ddeecfe6b721','送李煥雲赴恭城主簿','樂雷發','宋','宋诗','song-poetry','','[]','恭城山水接三湘，應覺他鄉是故鄉。',64,'全唐诗/poet.song.229000.json','["恭城山水接三湘，應覺他鄉是故鄉。", "官況不妨棲枳棘，客程還見食檳榔。", "寒暄未定宜加愛，事業無窮要自强。", "千古忠魂如可問，試吟雛井漱吟腸。"]'),
('151c223f-322e-4b4c-8024-3dd125c8ebf7','寄李伯輝','樂雷發','宋','宋诗','song-poetry','','[]','石樓峯下寄吟身，靜掩桑樞琢楚珍。',64,'全唐诗/poet.song.229000.json','["石樓峯下寄吟身，靜掩桑樞琢楚珍。", "蘋草青莎招隠士，暮雲春樹憶詩人。", "門無車馬多嫌僻，家有圖書不似貧。", "擬借大鵬揩老眼，何時尊酒得相親。"]'),
('df75ecee-050d-4c91-bbda-d4b6da4e97ba','舜祠送桂林友人','樂雷發','宋','宋诗','song-poetry','','[]','堯山分手舜山逢，呼酒旗亭兩鬢蓬。',64,'全唐诗/poet.song.229000.json','["堯山分手舜山逢，呼酒旗亭兩鬢蓬。", "客思且須論契闊，詩交應不計窮通。", "兒曹富貴秋烟外，前輩風流落葉中。", "明日吟船又何處，渡江衣冷荻花風。"]'),
('bcb5f195-95a5-4397-98ff-9215e9481c90','送董炎震歸攸縣','樂雷發','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','千菊溪頭話別情，君行我住兩伶俜。',64,'全唐诗/poet.song.229000.json','["千菊溪頭話別情，君行我住兩伶俜。", "山中有酒招元亮，石上無禾養百齡。", "狼尾屋低苔漠漠，龍鬚菜長水泠泠。", "故鄉語燕應堪聽，莫放扁舟過洞庭。"]'),
('6b08c732-57ef-4896-84b4-0a71a429ce24','贈衡山侯霖','樂雷發','宋','宋诗','song-poetry','','["\u8861\u5c71"]','家住衡山茗塢深，軒轅道士是知音。',64,'全唐诗/poet.song.229000.json','["家住衡山茗塢深，軒轅道士是知音。", "窊尊酒好聊同醉，石鼎詩難莫浪吟。", "雨外虺隤寒食路，花邊格磔故鄉心。", "却懷世上揚雄少，腸斷侯芭何處尋。"]'),
('da5d1420-b02f-44c6-9907-03181dd661a0','送駱丞謁襄帥廣西憲','樂雷發','宋','宋诗','song-poetry','','["\u8861\u5c71"]','知君無地種江蘺，看了衡山看九疑。',64,'全唐诗/poet.song.229000.json','["知君無地種江蘺，看了衡山看九疑。", "客路不堪還話別，侯門何處可題詩。", "吟青羅带行離岸，唱白銅鞮過習池。", "呼酒試澆征馬足，繡臺油幕有相知。"]'),
('cc488fb1-37c1-4855-ad60-9ffc0f30f4e3','題豫章宋德父游湘詩卷','樂雷發','宋','宋诗','song-poetry','','[]','醉呼仙叟共浮湘，稛載風烟滿錦囊。',64,'全唐诗/poet.song.229000.json','["醉呼仙叟共浮湘，稛載風烟滿錦囊。", "名似浦雲山雨起，詩連沅芷澧蘭香。", "好吟秋月招元結，莫賦朝雲惱楚襄。", "吳巨老仙今寂寞，行人還解識珩璜。"]'),
('fd87165d-855d-4fdd-bc19-4216bf14e3c2','常寧道中懷許介之','樂雷發','宋','宋诗','song-poetry','','[]','雨過池塘路未乾，人家桑柘带春寒。',64,'全唐诗/poet.song.229000.json','["雨過池塘路未乾，人家桑柘带春寒。", "野巫豎石爲神像，稚子搓泥作藥丸。", "柳下兩姝爭餉路，花邊一犬吠征鞍。", "行吟不得東溪聽，借硯村廬自寫看。"]'),
('081c404c-8de4-4bd4-ad7c-792817120813','題許介之譽文堂  其一','樂雷發','宋','宋诗','song-poetry','','[]','曾佐元戎洗綠林，此翁何止擅詩聲。',64,'全唐诗/poet.song.229000.json','["曾佐元戎洗綠林，此翁何止擅詩聲。", "久辭驃騎尋瓢飲，誰引鳴騶聒耦耕。", "厚禮正羅溫處士，浮名還汙阮先生。", "衡茅那識絲綸美，尚擬升堂結社盟。"]'),
('0c568b28-decd-4b68-b7b3-5e6e7b8d6d5e','題許介之譽文堂  其二','樂雷發','宋','宋诗','song-poetry','','[]','姜夔劉過竟何爲，空向江湖老布衣。',64,'全唐诗/poet.song.229000.json','["姜夔劉過竟何爲，空向江湖老布衣。", "造物忌名從古有，詩人得位似君稀。", "聖朝自要求參朮，吾道何應賤蕨薇。", "晚節黄花須愛護，且教湘士挹芳菲。"]'),
('91adbac9-e969-4af7-8db1-59ce9d6fa78b','濂溪書院弔曾景建','樂雷發','宋','宋诗','song-poetry','','[]','太極樓頭霽月寒，斷弦綠綺不堪彈。',64,'全唐诗/poet.song.229000.json','["太極樓頭霽月寒，斷弦綠綺不堪彈。", "窗前自長濂溪草，澤畔還枯正則蘭。", "蒼野騷魂惟我弔，烏臺詩案倩誰刊。", "傷心空有金陵集，留與江湖灑淚看。"]'),
('0f93360d-5eff-40e4-9119-8a3b4fe0e754','許介之以丞相周益公所書古樂府四篇見寄敬題其後','樂雷發','宋','宋诗','song-poetry','','[]','紙上珊瑚間木難，曾敲黄閣卸吟鞍。',64,'全唐诗/poet.song.229000.json','["紙上珊瑚間木難，曾敲黄閣卸吟鞍。", "賞音今有平園否，得句堪尋岣嶁刊。", "鸚鵡夜棲金屋冷，的盧秋戰玉關寒。", "春風歸雁那知己，寄與深宮絕塞看。"]'),
('99f2deb3-dc56-450d-8d2b-6e58bf8f8e1e','讀繫年錄','樂雷發','宋','宋诗','song-poetry','','[]','婁敬金繒滿去輈，便看雷雨潤遐陬。',64,'全唐诗/poet.song.229000.json','["婁敬金繒滿去輈，便看雷雨潤遐陬。", "諸賢自抗排雲議，宰相方深偃月謀。", "湘國乍聞悲鵩鳥，秣陵還聽唱符鳩。", "九原晏老君知否，搔首青編恨未休。"]'),
('c0d5668d-87dc-493f-afb4-19cbed84eea3','櫟閘吳大帝廟','樂雷發','宋','宋诗','song-poetry','','[]','赤壁濡須事已虛，且依櫟閘酹芳壺。',64,'全唐诗/poet.song.229000.json','["赤壁濡須事已虛，且依櫟閘酹芳壺。", "九原尚擬吞銅雀，千載今惟記赤烏。", "湘浦有人修舊祀，荆州無地展雄圖。", "定知斫案英靈在，閒對祠前洗湛盧。"]'),
('2699d4fd-7213-4979-bf00-10edd7a322cf','昭陵渡馬伏波廟','樂雷發','宋','宋诗','song-poetry','','[]','功名要結後人知，馬革何妨死裹尸。',64,'全唐诗/poet.song.229000.json','["功名要結後人知，馬革何妨死裹尸。", "漢帝可能疑薏苡，湘民却解薦江蘺。", "紙錢撩亂巫分胙，粉壁闌斑客寫詩。", "墮水跕鳶無處問，灘頭斜照曬鸕鷀。"]'),
('bc490b6c-bd01-4629-a457-df5af1d60d60','記蕭大山父子','樂雷發','宋','宋诗','song-poetry','','[]','仙桂靈椿各典刑，飄飄姿韻激天鯨。',64,'全唐诗/poet.song.229000.json','["仙桂靈椿各典刑，飄飄姿韻激天鯨。", "家傳八葉鹽梅種，詩接三蘇父子名。", "四海盡將看縣譜，一堂那許與文盟。", "塵埃不敢相親炙，且汲渝溪濯客纓。"]'),
('2a79e160-f23b-468e-9801-651422f998ea','謁張兵部時守臨江新除湖南倉','樂雷發','宋','宋诗','song-poetry','','[]','東皇太一待新詩，共喜星槎泝楚涯。',64,'全唐诗/poet.song.229000.json','["東皇太一待新詩，共喜星槎泝楚涯。", "父老盡將看鸑鷟，使君應不問狐狸。", "江頭芳杜催行色，境內甘棠有去思。", "細讀詔書搔短髮，瓣香那識帝王師。"]'),
('60d97967-51c1-4328-af47-c42fa7d97ab6','蘇瑩中先往新淦過新喻訪之不遇賦詩爲寄','樂雷發','宋','宋诗','song-poetry','','[]','玉笥山前水拍空，知君何處繫吟篷。',64,'全唐诗/poet.song.229000.json','["玉笥山前水拍空，知君何處繫吟篷。", "敢輕奇士題凡鳥，漫有憂心咏阜螽。", "沅芷澧蘭猶可寄，江雲渭樹苦難同。", "門前草木皆詩卷，獨倚篔簹嘯晚風。"]'),
('a0f5dd4b-d4ae-46aa-836f-5ace76578925','送蕭大山赴新興令','樂雷發','宋','宋诗','song-poetry','','[]','翡翠芙蓉去路荒，許渾詩裏認封疆。',64,'全唐诗/poet.song.229000.json','["翡翠芙蓉去路荒，許渾詩裏認封疆。", "昔聞古佛傳宗印，今得吟仙綰縣章。", "魚婢蟹奴供俎豆，馬人龍戶雜耕桑。", "澹翁應解知心事，試汲寒泉薦瓣香。"]'),
('39f8f42a-d977-4129-91ed-37381c37acc6','訪菊花山人沈莊可','樂雷發','宋','宋诗','song-poetry','','[]','網盡珊瑚採盡珠，只餐秋菊養詩臞。',64,'全唐诗/poet.song.229000.json','["網盡珊瑚採盡珠，只餐秋菊養詩臞。", "永嘉同社聲名在，乾道遺民行輩孤。", "我恨朱門無食客，君言青史有窮儒。", "饑寒正用昌吾道，且對鈐岡共撚鬚。"]'),
('a52eebcb-6e3d-4fb8-a0f1-b40b35a44062','懷二蕭','樂雷發','宋','宋诗','song-poetry','','[]','未曾相見已相知，楚粵江山棣萼詩。',64,'全唐诗/poet.song.229000.json','["未曾相見已相知，楚粵江山棣萼詩。", "每恨乾坤催我老，却於湖海識君遲。", "機雲才藻今無幾，管鮑襟期說向誰。", "靡靡亂山嘶瘦馬，碧雲日暮正相思。"]'),
('7e2341bc-19fd-4862-924b-b28eac00e3a9','疏拙','樂雷發','宋','宋诗','song-poetry','','[]','越冠齊瑟事皆非，疏拙惟甘與世違。',64,'全唐诗/poet.song.229000.json','["越冠齊瑟事皆非，疏拙惟甘與世違。", "客路鶑花愁裏看，故山烟雨夢中歸。", "采薇有備淮南靜，移粟無謀浙右饑。", "納納乾坤須俊傑，湘翁祇合製荷衣。"]'),
('53e9f167-03a8-466b-a445-028fbbb1fc62','陳東甫酒閒舉作歸心只有杜鵑知之句猶未成篇因爲續之','樂雷發','宋','宋诗','song-poetry','','[]','歸心只有杜鵑知，且倚裴亭遍共撚髭。',65,'全唐诗/poet.song.229000.json','["歸心只有杜鵑知，且倚裴亭遍共撚髭。", "客路秋風吹杜若，故園春雨老辛夷。", "家貧未辦閒居賦，世濁空吟感寓詩。", "邂逅江湖還別去，岸花檣燕兩堪悲。"]'),
('6f2910c9-3bb6-4bd4-a8a4-55fd35ee50fc','贈別陳東甫呈尚書鍾公','樂雷發','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭濯足共題詩，今聽驪駒話別離。',64,'全唐诗/poet.song.229000.json','["洞庭濯足共題詩，今聽驪駒話別離。", "泣玉可能悲卞子，買金只合鑄鍾期。", "荷盤翦綠須棲鷺，䳷頂分絲補接䍦。", "斗酒彘肩聊自壯，古來騷客例寒饑。"]'),
('9fb9da0b-31b3-4078-a642-42f4909fd375','登潭州懷雪蓬姚使君','樂雷發','宋','宋诗','song-poetry','','[]','賈井裴亭遍短筇，紅塵歸騎又匆匆。',64,'全唐诗/poet.song.229000.json','["賈井裴亭遍短筇，紅塵歸騎又匆匆。", "我尋桂樹吟招隠，君對蓮花誦易通。", "今日江山勞別夢，他年燈火課新功。", "濂溪最念初平老，恨聽連牀話未終。"]'),
('347ea3b8-7375-4b1c-b81b-0d7d4550ca32','下攝市','樂雷發','宋','宋诗','song-poetry','','[]','吟到湘潭一葉黄，賈胡蹤跡正悲凉。',64,'全唐诗/poet.song.229000.json','["吟到湘潭一葉黄，賈胡蹤跡正悲凉。", "抱琴沽酒異鄉客，打鼓發船何郡郎。", "楚女越商相雜沓，淮鹽浙楮自低昂。", "塵埃市井無人識，濯足江頭望八荒。"]'),
('11c5df16-9062-4e24-bcbd-b07e54aa9ac2','雪峰寺','樂雷發','宋','宋诗','song-poetry','','[]','擬尋岣嶁看蟠螭，且解青鞋濯禹溪。',64,'全唐诗/poet.song.229000.json','["擬尋岣嶁看蟠螭，且解青鞋濯禹溪。", "弔古猶疑九枝柏，談禪且問一莖虀。", "虎抓崖樹供僧爨，猿摸廊碑認客題。", "應接溪山無好句，滿林空羨亂蟬嘶。"]'),
('33c922b8-63e0-40a4-8f02-e12c196e391d','到衡岳呈弟山長','樂雷發','宋','宋诗','song-poetry','','[]','閒依禹柏繫征驄，猿鳥應猶怪賤蹤。',64,'全唐诗/poet.song.229000.json','["閒依禹柏繫征驄，猿鳥應猶怪賤蹤。", "正擬開雲訪韓愈，可能避雨識茅容。", "朱陵洞裏秋呼鶴，紫蓋峯前曉聽鐘。", "欲踏青霞尋勝趣，倦游應許借吟筇。"]'),
('b7c9922a-fc88-4403-a2e5-f475a346787c','許介之館僕於東溪臨發贈別','樂雷發','宋','宋诗','song-poetry','','[]','洗耳泉頭漱晚凉，西風衣袂水花香。',64,'全唐诗/poet.song.229000.json','["洗耳泉頭漱晚凉，西風衣袂水花香。", "酒邊豪氣橫荆楚，燈下清談雜晉唐。", "天地每窮真俊傑，山林偏有好文章。", "試拈茹草同君舞，後夜聞鷄月滿牀。"]'),
('fcb9ace2-f1c1-417f-ad5e-9aab5faa1567','下第歸後李伯輝李景魏索近詩','樂雷發','宋','宋诗','song-poetry','','[]','吟遍吳頭楚尾春，多慚詞客問征塵。',64,'全唐诗/poet.song.229000.json','["吟遍吳頭楚尾春，多慚詞客問征塵。", "振衣天目尋黄獨，濯足湘江咏白蘋。", "宋五已慚稱進士，陳三何用作詩人。", "錦囊原屬君家有，分買魚經理釣輪。"]'),
('62b09bcd-bb42-4431-ad80-eda67b223aff','題李湛溪詩集後','樂雷發','宋','宋诗','song-poetry','','[]','楚砧岷葛飽清遊，金節銀菟照幾州。',64,'全唐诗/poet.song.229000.json','["楚砧岷葛飽清遊，金節銀菟照幾州。", "詩句多如姚少監，行程還似杜參謀。", "黄陵夜誦虞妃泣，白帝春吟杜宇愁。", "擬問湛溪何處是，夢隨閩國弄漁舟。"]'),
('05a35a08-d740-4410-93e4-d26405f5ac26','贈李伯輝家譜詩','樂雷發','宋','宋诗','song-poetry','','[]','盪寇將軍後，唐朝李郤家。',24,'全唐诗/poet.song.229000.json','["盪寇將軍後，唐朝李郤家。", "綠華雙薦者，況復古今誇。"]'),
('14abaf83-d0c2-4dd3-9f60-f4ef124fd1f8','詠史六首 高祖','樂雷發','宋','宋诗','song-poetry','','[]','逝騅走鹿各消磨，劍外功臣剩幾多。',32,'全唐诗/poet.song.229000.json','["逝騅走鹿各消磨，劍外功臣剩幾多。", "四皓兩生元不聽，故鄉枉費大風歌。"]'),
('17527d8d-f0d1-4c60-8994-10d23d70a9f4','詠史六首 陳勝吳廣','樂雷發','宋','宋诗','song-poetry','','[]','假號偷名只可憐，枉拋錢鎛弄戈鋋。',32,'全唐诗/poet.song.229000.json','["假號偷名只可憐，枉拋錢鎛弄戈鋋。", "隴頭燕雀應相笑，鴻鵠元來是項燕。"]'),
('bc3551f6-4a3d-442c-ac4a-2b06018f5e74','詠史六首 韓信','樂雷發','宋','宋诗','song-poetry','','[]','愁看鍾室劈良弓，何不當時殺蒯通。',32,'全唐诗/poet.song.229000.json','["愁看鍾室劈良弓，何不當時殺蒯通。", "今日真王成底事，只應娥姁是英雄。"]'),
('b3dc5414-9b8a-4970-b439-de59711f90e1','詠史六首 東方朔','樂雷發','宋','宋诗','song-poetry','','[]','蜥蜴盆邊解滑稽，且分社肉飽蛾眉。',32,'全唐诗/poet.song.229000.json','["蜥蜴盆邊解滑稽，且分社肉飽蛾眉。", "劉郎最怕秋風冷，那聽君言換殿帷。"]'),
('03f3a15a-2962-499f-8b7a-7f6d7b0b8490','詠史六首 司馬相如','樂雷發','宋','宋诗','song-poetry','','[]','狗監無端薦薄情，鸘裘犢鼻帝鄉塵。',32,'全唐诗/poet.song.229000.json','["狗監無端薦薄情，鸘裘犢鼻帝鄉塵。", "當時最有文君恨，不識長門買賦人。"]'),
('aa9b080e-7f9b-46a0-9e44-07069a8b1619','詠史六首 班固','樂雷發','宋','宋诗','song-poetry','','[]','請室冤魂叫不聞，神丘隆碣謾遺文。',32,'全唐诗/poet.song.229000.json','["請室冤魂叫不聞，神丘隆碣謾遺文。", "平生詞藻誰知己，腐鼠孤雛却悞君。"]'),
('967725b5-f5b9-48be-9fb5-4b272109b397','汴堤柳','樂雷發','宋','宋诗','song-poetry','','[]','萬縷春風窣汴堤，錦帆何處柳空垂。',32,'全唐诗/poet.song.229000.json','["萬縷春風窣汴堤，錦帆何處柳空垂。", "流鶑應有兒孫在，問著隋朝總不知。"]'),
('c33cddc2-8c8e-49bb-b90e-7386924638fb','讀李羣玉集  其一','樂雷發','宋','宋诗','song-poetry','','[]','光順門前繫馬吟，弘文館裏翠雲春。',32,'全唐诗/poet.song.229000.json','["光順門前繫馬吟，弘文館裏翠雲春。", "却憐白首河西尉，枉作蓬萊獻賦人。"]'),
('219de278-361c-47a6-ab87-4e5fdbd64134','讀李羣玉集  其二','樂雷發','宋','宋诗','song-poetry','','[]','捐玦江頭弄釣舟，蘭花杜若滿芳洲。',32,'全唐诗/poet.song.229000.json','["捐玦江頭弄釣舟，蘭花杜若滿芳洲。", "如何才子無騷思，只咏薔薇與石榴。"]'),
('5096e5e6-e2ec-4b4a-8c28-6684ac66b04f','與復古叔讀橫渠正蒙書  其一','樂雷發','宋','宋诗','song-poetry','','[]','惆悵枯株無晬盤，雲橫太白夢魂寒。',32,'全唐诗/poet.song.229000.json','["惆悵枯株無晬盤，雲橫太白夢魂寒。", "半生驕吝如蝸縮，自把西銘反覆看。"]'),
('f0c7ab4a-4e52-4ea1-80e6-60d3bde39be7','與復古叔讀橫渠正蒙書  其二','樂雷發','宋','宋诗','song-poetry','','[]','誰掘驪山起老師，竹林燈火共心期。',32,'全唐诗/poet.song.229000.json','["誰掘驪山起老師，竹林燈火共心期。", "年來後學輕前輩，看徹皋比罷講時。"]'),
('39f6acd4-9071-4ced-b66f-baa7f70c3a70','題楊從行湘詩卷  其一','樂雷發','宋','宋诗','song-poetry','','[]','仙雲寒鎖碧瑶天，突兀吟壇北斗邊。',32,'全唐诗/poet.song.229000.json','["仙雲寒鎖碧瑶天，突兀吟壇北斗邊。", "試問鳳凰誰得髓，竹林聽雪對牀眠。"]'),
('97942552-f8eb-4c76-9ad8-753632f10727','題楊從行湘詩卷  其二','樂雷發','宋','宋诗','song-poetry','','[]','叫雲吹玉舜祠邊，醉嚼瓊糜漱石泉。',32,'全唐诗/poet.song.229000.json','["叫雲吹玉舜祠邊，醉嚼瓊糜漱石泉。", "舊讀離騷今忘却，快披秋卷嗅蘭荃。"]'),
('fcc5c43a-c87d-4439-b600-3b54dea4a4f3','次韻熊雲瀑秋夜見寄  其一','樂雷發','宋','宋诗','song-poetry','','[]','吟落秋窗燭炧紅，想彈九辯入絲桐。',32,'全唐诗/poet.song.229000.json','["吟落秋窗燭炧紅，想彈九辯入絲桐。", "荃衡豈不如葵菽，誰繼豳風補楚風。"]'),
('99f7f85b-64c5-494e-bf9c-ad7977749601','次韻熊雲瀑秋夜見寄  其二','樂雷發','宋','宋诗','song-poetry','','[]','叫徹蒼梧望八荒，暮雲秋客各淒涼。',32,'全唐诗/poet.song.229000.json','["叫徹蒼梧望八荒，暮雲秋客各淒涼。", "此情未許旁人會，愁絕中庭月一方。"]'),
('af51704e-f19a-46eb-87cc-fdbb389f92d9','無題','樂雷發','宋','宋诗','song-poetry','','[]','大袖褒衣走浙淮，何人不識鶴山來。',32,'全唐诗/poet.song.229000.json','["大袖褒衣走浙淮，何人不識鶴山來。", "只今心印誰傳得，自摺通書撥篆灰。"]'),
('7fcfa5e7-c8cf-411d-aad4-02282c56329b','撫州偶題','樂雷發','宋','宋诗','song-poetry','','[]','金柅亭邊柳拂城，春風繫馬酒家吟。',32,'全唐诗/poet.song.229000.json','["金柅亭邊柳拂城，春風繫馬酒家吟。", "塵埃滿面無人識，却得黄鸝作賞音。"]'),
('e4f94a88-3038-49ab-b2e4-c497b27c3cf1','萍鄉病渴','樂雷發','宋','宋诗','song-poetry','','[]','犬子無從典鷫鸘，荒村忍渴望瀟湘。',32,'全唐诗/poet.song.229000.json','["犬子無從典鷫鸘，荒村忍渴望瀟湘。", "楚王萍實甜如蜜，不許詩人取次嘗。"]'),
('61fa7acb-c82b-40fd-8cf2-2abc51b1fe1c','甲午社日客桂林','樂雷發','宋','宋诗','song-poetry','','[]','卮酒豚蹄客裏歡，石尤風緊枲衣單。',32,'全唐诗/poet.song.229000.json','["卮酒豚蹄客裏歡，石尤風緊枲衣單。", "東陽病骨如鸚鵡，最怯南州社日寒。"]'),
('f1067c62-6259-4728-9613-5c2b74b4d680','桂林歲晚憶鍾尚書','樂雷發','宋','宋诗','song-poetry','','[]','塵滿湘翁薜荔衣，江湖歲晚鬢成絲。',32,'全唐诗/poet.song.229000.json','["塵滿湘翁薜荔衣，江湖歲晚鬢成絲。", "桂州楊五今何處，雪片梅花枉費詩。"]'),
('af7fc6b9-8773-442e-83ef-43f52c1c8d1c','醉中偶成','樂雷發','宋','宋诗','song-poetry','','[]','醉敲茶臼嘯秋烟，苦欠高陽買酒錢。',32,'全唐诗/poet.song.229000.json','["醉敲茶臼嘯秋烟，苦欠高陽買酒錢。", "擬入亂山餐柏葉，石牀閒對麝香眠。"]'),
('23336d1e-7381-46d5-b8eb-dd9308ef8264','送友人游昭州呈陳謙之僉判  其一','樂雷發','宋','宋诗','song-poetry','','[]','閬仙去補荔支譜，梅谷歸呈飛鶩秋。',32,'全唐诗/poet.song.229000.json','["閬仙去補荔支譜，梅谷歸呈飛鶩秋。", "惟有瓜坡共君在，馬蹄何苦又昭州。"]'),
('39c36673-f3ea-4544-8cfe-504161fff35d','送友人游昭州呈陳謙之僉判  其二','樂雷發','宋','宋诗','song-poetry','','[]','道鄉牽損衮龍衣，謫墮天涯咏楚蘺。',32,'全唐诗/poet.song.229000.json','["道鄉牽損衮龍衣，謫墮天涯咏楚蘺。", "莫放蹇馿游別處，拾青閣下有殘碑。"]'),
('6400db8c-d56c-46ea-a8e7-b424e14d5adc','送友人游昭州呈陳謙之僉判  其三','樂雷發','宋','宋诗','song-poetry','','[]','鵬運堂前話別愁，菭蘠三度楚江秋。',32,'全唐诗/poet.song.229000.json','["鵬運堂前話別愁，菭蘠三度楚江秋。", "近懷莫向元龍道，問舍求田是□頭。"]'),
('8db5aeb6-79e6-4143-9e18-19d6164c1974','夏日偶書','樂雷發','宋','宋诗','song-poetry','','[]','蜾蠃銜蟲入破窗，枕書一垛竹方牀。',32,'全唐诗/poet.song.229000.json','["蜾蠃銜蟲入破窗，枕書一垛竹方牀。", "家僮偶見草頭字，誤認離騷是藥方。"]'),
('a4105d05-aa6f-4bed-9efe-25406175e22d','秋日行村路','樂雷發','宋','宋诗','song-poetry','','[]','兒童籬落带斜陽，豆莢薑芽社肉香。',32,'全唐诗/poet.song.229000.json','["兒童籬落带斜陽，豆莢薑芽社肉香。", "一路稻花誰是主，紅蜻蜓伴綠螳螂。"]'),
('41bd63d2-4cfb-461b-87f3-3932883b5c52','新淦偶成','樂雷發','宋','宋诗','song-poetry','','[]','飛飛綠鳳挂梅梢，猶記來時雪擁袍。',32,'全唐诗/poet.song.229000.json','["飛飛綠鳳挂梅梢，猶記來時雪擁袍。", "今日歸舟新淦路，擔頭稚子賣櫻桃。"]'),
('d8a1f364-11ad-4b35-9f65-55f9f16e1e76','贈吳季詩','樂雷發','宋','宋诗','song-poetry','','[]','燕子樓頭一曲春，曾騎驕馬擲黄金。',32,'全唐诗/poet.song.229000.json','["燕子樓頭一曲春，曾騎驕馬擲黄金。", "如今世事漫頭雪，破屋孤燈忍凍吟。"]'),
('ca3ac758-0138-4a5e-a321-42ae6da9bcb7','演教寺弔樓居朱漕  其一','樂雷發','宋','宋诗','song-poetry','','[]','羅带江頭蛻繡衣，人歸香草謝家池。',32,'全唐诗/poet.song.229000.json','["羅带江頭蛻繡衣，人歸香草謝家池。", "祇今玉樹埋何處，惆悵僧房認得詩。"]'),
('373d054d-17a1-4fa5-9fc1-b8b7187f2d24','演教寺弔樓居朱漕  其二','樂雷發','宋','宋诗','song-poetry','','[]','穿塚難酬地下知，逢人多說項斯詩。',32,'全唐诗/poet.song.229000.json','["穿塚難酬地下知，逢人多說項斯詩。", "今朝痛灑西州淚，萬里梅花欲放時。"]'),
('853deaac-6095-4ead-8967-1937b44dc29e','延真道院','樂雷發','宋','宋诗','song-poetry','','[]','滄流翠竹接仙扃，靈菜丹虬拱上真。',32,'全唐诗/poet.song.229000.json','["滄流翠竹接仙扃，靈菜丹虬拱上真。", "擬就玄翁分半榻，閒聽秋雨守庚申。"]'),
('e9352ed0-ea58-47c4-a082-d6b2373af21e','訪趙愚齋不遇謁者云入幕抵晚方歸因成一絕奉寄','樂雷發','宋','宋诗','song-poetry','','[]','雪片梅花滿硯池，芙蓉幕裏客歸遲。',32,'全唐诗/poet.song.229000.json','["雪片梅花滿硯池，芙蓉幕裏客歸遲。", "今朝解了公家事，儘聽轅門報酉時。"]'),
('511b1009-0e55-4448-9e79-f1e4fb011453','史主簿以授菴習稿見示敬題其後并寄張宗瑞  其一','樂雷發','宋','宋诗','song-poetry','','[]','姜夔荒塚白蘋深，鸑鷟無聲結綠沈。',32,'全唐诗/poet.song.229000.json','["姜夔荒塚白蘋深，鸑鷟無聲結綠沈。", "擬向鄱陽尋後杜，只招張叟聽君吟。"]'),
('914e2289-ae58-4bca-9c84-b019856375b1','史主簿以授菴習稿見示敬題其後并寄張宗瑞  其二','樂雷發','宋','宋诗','song-poetry','','[]','吟了南樓到庫樓，塞雲邊月困雕鎪。',32,'全唐诗/poet.song.229000.json','["吟了南樓到庫樓，塞雲邊月困雕鎪。", "只今南北無詩禁，曾有新編遏韃不。"]'),
('b9142ed2-c339-4d6e-ab26-3e7a7ddc5620','術士醴陵丁夢榮將之舂陵有贈  其一','樂雷發','宋','宋诗','song-poetry','','[]','看盡槐花賣卜人，窊尊且認舊碑文。',32,'全唐诗/poet.song.229000.json','["看盡槐花賣卜人，窊尊且認舊碑文。", "只今世上無清惠，却恐元郎解笑君。"]'),
('1310bedf-5cfb-4a8d-b756-d8ab1a60f2ab','術士醴陵丁夢榮將之舂陵有贈  其二','樂雷發','宋','宋诗','song-poetry','','[]','綠水池邊舊釣磯，何時歸去濯征衣。',32,'全唐诗/poet.song.229000.json','["綠水池邊舊釣磯，何時歸去濯征衣。", "千年城郭應無恙，祇怕風塵老令威。"]'),
('f390db09-79fa-46ee-9947-d5b0ceb06a1f','送歐陽平仲起鬰林教官  其一','樂雷發','宋','宋诗','song-poetry','','[]','快把詩書洗瘴茅，雕題墨齒盡同胞。',32,'全唐诗/poet.song.229000.json','["快把詩書洗瘴茅，雕題墨齒盡同胞。", "天涯那得隨衿佩，試借升堂講義鈔。"]'),
('4870e8c7-816b-4f5d-9164-07887666e7fa','送歐陽平仲起鬰林教官  其二','樂雷發','宋','宋诗','song-poetry','','[]','古來節婦比忠臣，怊悵明珠一窖塵。',32,'全唐诗/poet.song.229000.json','["古來節婦比忠臣，怊悵明珠一窖塵。", "千古綱常君記取，題詩煩問墜樓人。"]'),
('2f93fd69-ae2d-4e94-9163-0fe84241a8c2','萍鄉和王堯章韻','樂雷發','宋','宋诗','song-poetry','','[]','征衲無人補舊綿，蕭條客枕楚萍邊。',32,'全唐诗/poet.song.229000.json','["征衲無人補舊綿，蕭條客枕楚萍邊。", "撥殘石炭西窗冷，却憶山家榾柮烟。"]'),
('1bf3f306-3878-4ab4-af79-f7dc62224cd0','趙司法詩集自題近道蓋取工部所貽元隠居詩中語也因書二絕  其一','樂雷發','宋','宋诗','song-poetry','','[]','和遍陶翁飲酒詩，醉籠天地入鴟夷。',32,'全唐诗/poet.song.229000.json','["和遍陶翁飲酒詩，醉籠天地入鴟夷。", "細看官爵成何物，肯带奚囊過九疑。"]'),
('4ab0a922-f52a-4547-a739-5dae435f73f3','趙司法詩集自題近道蓋取工部所貽元隠居詩中語也因書二絕  其二','樂雷發','宋','宋诗','song-poetry','','[]','浣花騷伯杳難□，世上寧無元隠居。',32,'全唐诗/poet.song.229000.json','["浣花騷伯杳難□，世上寧無元隠居。", "讀罷君詩三歎息，斷弦綠綺定何如。"]'),
('bfc8ef6d-7ff6-45df-942a-bda2af0dd480','聽廬山胡道士彈離騷  其一','樂雷發','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','廬山道士菊潭仙，前世滄浪握楚荃。',32,'全唐诗/poet.song.229000.json','["廬山道士菊潭仙，前世滄浪握楚荃。", "莫道離騷遺響絕，孤鈎寡珥尚能傳。"]'),
('932e7891-924b-4667-911f-8e5586ee7442','聽廬山胡道士彈離騷  其二','樂雷發','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','弔湘誰解薦江蘺，忠憤泠泠寫七絲。',32,'全唐诗/poet.song.229000.json','["弔湘誰解薦江蘺，忠憤泠泠寫七絲。", "愁絕九疑山下聽，重華應許就陳詞。"]'),
('37807659-4809-4b9c-8ec1-fd0c8df23adb','題王堯章佇香亭  其一','樂雷發','宋','宋诗','song-poetry','','[]','滿池蜀錦照深衣，盡日憑欄課楚詞。',32,'全唐诗/poet.song.229000.json','["滿池蜀錦照深衣，盡日憑欄課楚詞。", "要識此花香絕處，露凉風細雨晴時。"]'),
('0ba8ccfb-9682-494a-8315-8fea58f56aaa','題王堯章佇香亭  其二','樂雷發','宋','宋诗','song-poetry','','[]','對花味道興何長，好學顔家到坐忘。',32,'全唐诗/poet.song.229000.json','["對花味道興何長，好學顔家到坐忘。", "莫與紅塵兒輩道，心清正自得真香。"]'),
('e73c6ccb-b657-4f1e-83c8-b720908e15d1','題王堯章佇香亭  其三','樂雷發','宋','宋诗','song-poetry','','[]','故園荷屋傍濂溪，苦愛蓮花入夢思。',32,'全唐诗/poet.song.229000.json','["故園荷屋傍濂溪，苦愛蓮花入夢思。", "今日題詩還自笑，江湖塵土鬢成絲。"]'),
('d010f46d-8a40-45a2-bae8-0c62e675258e','題昭州田廷亮書稿後  其一','樂雷發','宋','宋诗','song-poetry','','[]','檳榔口裏吐參苓，折檻無門九虎深。',32,'全唐诗/poet.song.229000.json','["檳榔口裏吐參苓，折檻無門九虎深。", "家在道鄉亭畔住，定應千古有知音。"]'),
('8194e38a-3a0b-4e0b-b3c2-794eb5e50cfe','題昭州田廷亮書稿後  其二','樂雷發','宋','宋诗','song-poetry','','[]','少海無波鶴禁虛，滿朝閉口養曹蜍。',32,'全唐诗/poet.song.229000.json','["少海無波鶴禁虛，滿朝閉口養曹蜍。", "白袍烏帽和寧外，却有山人請建儲。"]'),
('73cbbbb6-22bc-4d85-b917-943cd322983e','訪伯父幽居','樂雷發','宋','宋诗','song-poetry','','[]','對坐如禪舍，閒燒石乳香。',48,'全唐诗/poet.song.229000.json','["對坐如禪舍，閒燒石乳香。", "書看新講義，藥問未傳方。", "僕語梅花裏，僧經竹案傍。", "題詩吾豈敢，窗戶半吟章。"]'),
('ed0209af-6e8e-417f-87f1-b41ff10a939e','桂林懷李景魏','樂雷發','宋','宋诗','song-poetry','','[]','陽華萬疊雲，無計得相尋。',48,'全唐诗/poet.song.229000.json','["陽華萬疊雲，無計得相尋。", "所學皆時好，何人知爾心。", "莎城百粵遠，雪嶠一翁吟。", "已是懷人極，天寒奈水深。"]'),
('ad8faa9c-3a4b-4ab6-90c6-f8d796943d38','桂林送人之瓊州招捕海寇','樂雷發','宋','宋诗','song-poetry','','[]','訾家洲畔路，別爾苦怱怱。',48,'全唐诗/poet.song.229000.json','["訾家洲畔路，別爾苦怱怱。", "說劍令人喜，耽吟與我同。", "旌旗楓鬼雨，舟楫鱟簰風。", "想到瓊峯頂，題詩更紀功。"]'),
('066bd0ae-b59b-4e12-93f9-c4f184a73319','與李盤翁知縣登七星山弔石道士','樂雷發','宋','宋诗','song-poetry','','[]','疊嶂矗空青，躭幽共一尋。',48,'全唐诗/poet.song.229000.json','["疊嶂矗空青，躭幽共一尋。", "苔荒碑意古，茗苦道情深。", "有興梯蒼壁，無才咏玉簪。", "吟仙何處去，我輩復登臨。"]'),
('aa4d0205-897c-443c-97db-e0f7f94079eb','次韻史主簿雨夜見寄','樂雷發','宋','宋诗','song-poetry','','[]','水長許由溪，春寒入竹扉。',48,'全唐诗/poet.song.229000.json','["水長許由溪，春寒入竹扉。", "幾人聽夜雨，惟我怯單衣。", "樹罅青燈耿，籬根白菌肥。", "明朝有忙事，推枕問漁磯。"]'),
('7e2f0363-7bb5-424e-b3d3-076cd930ada3','道中逢老儒由蜀出','樂雷發','宋','宋诗','song-poetry','','[]','丙穴魚應好，曾經問釣磯。',48,'全唐诗/poet.song.229000.json','["丙穴魚應好，曾經問釣磯。", "干戈今未定，城郭是耶非。", "詩社尊黄髮，侯門薄布衣。", "乾坤滿豺虎，見爾一歔欷。"]'),
('e31fad11-8419-474d-8aba-3cdfef0ffa83','時事','樂雷發','宋','宋诗','song-poetry','','[]','時事如頹屋，誰堪任棟梁。',48,'全唐诗/poet.song.229000.json','["時事如頹屋，誰堪任棟梁。", "國貧僧牒賤，邊病檄書忙。", "有分憂宗社，無才出舉場。", "未應王謝輩，揮淚送斜陽。"]'),
('30be58c9-021c-40d7-af46-e3d678d307bc','逃戶','樂雷發','宋','宋诗','song-poetry','','[]','租帖名猶在，何人納稅錢。',48,'全唐诗/poet.song.229000.json','["租帖名猶在，何人納稅錢。", "燒侵無主墓，地占沒官田。", "邊國干戈滿，蠻州瘴癘偏。", "不知携老稚，何處就豐年。"]'),
('2280716a-e736-4ab6-bb12-6337c6e3d4a4','登江華寒亭','樂雷發','宋','宋诗','song-poetry','','[]','到此脚跟酸，千峯迥不看。',48,'全唐诗/poet.song.229000.json','["到此脚跟酸，千峯迥不看。", "年深碑字淺，日薄樹陰寒。", "石罅巢蜂乳，籬根墮鳥殘。", "愛吟還畏嶮，不敢倚欄干。"]'),
('f94622a8-b58b-48ae-9098-11fad137bb35','訪表叔李竹齋','樂雷發','宋','宋诗','song-poetry','','[]','門庭接豆根，吟避市塵喧。',48,'全唐诗/poet.song.229000.json','["門庭接豆根，吟避市塵喧。", "每愛詩無敵，應知學有源。", "雲山供俎豆，筆硯長兒孫。", "愧我相過數，秋風酒一尊。"]'),
('ac8d993d-e1d8-44f7-a74d-fbffdd3f783b','擬長沙訪姚雪蓬至永返賦此爲寄','樂雷發','宋','宋诗','song-poetry','','[]','今傍南軒住，應知理趣精。',48,'全唐诗/poet.song.229000.json','["今傍南軒住，應知理趣精。", "通書多似易，論語不言誠。", "擬欲聽微論，猶能慰別情。", "江湖風浪隔，腸斷楚鴻聲。"]'),
('94ddd681-23fe-4dc0-8e72-4e70d5669da4','雨夜讀陸放翁集','樂雷發','宋','宋诗','song-poetry','','[]','爐冷童吹火，山房夜黯然。',48,'全唐诗/poet.song.229000.json','["爐冷童吹火，山房夜黯然。", "濕薪添茭爇，苦茗带芎煎。", "燈暗瀟江雨，詩吟笠澤烟。", "老仙何處去，搔首弔塵編。"]'),
('eefbc833-3d12-4e2d-896c-2eb1c4e2b373','送黄天河','樂雷發','宋','宋诗','song-poetry','','[]','天河那可到，山頂翠參差。',48,'全唐诗/poet.song.229000.json','["天河那可到，山頂翠參差。", "村屋煎黄蠟，官爐焙荔支。", "地蠻游宦少，縣小迓賓遲。", "鼻祖曾吟處，荒苔想滿碑。"]'),
('8177e10a-e066-49e3-ba0c-369f994cd758','呈趙叔愚司理','樂雷發','宋','宋诗','song-poetry','','[]','問戶垂楊句，江湖半世看。',48,'全唐诗/poet.song.229000.json','["問戶垂楊句，江湖半世看。", "不應求五嶺，却自建孤壇。", "浙社朋游盡，唐詩氣味寒。", "今朝流水譜，只可子期彈。"]'),
('b5d228a6-eed5-4f97-a2ac-6751fe4872eb','夢訪劉漫堂曾雪巢二先生','樂雷發','宋','宋诗','song-poetry','','[]','前輩風流歇，江湖欠賞音。',48,'全唐诗/poet.song.229000.json','["前輩風流歇，江湖欠賞音。", "向期行古道，誰解識余心。", "月浸金壇冷，雲歸玉笥深。", "瀟湘風雨夜，空得夢相尋。"]'),
('0f60c35f-dde8-436c-97fc-1def73d9b10c','青湘逢廷對人歸因問時事','樂雷發','宋','宋诗','song-poetry','','[]','南客帝鄉歸，青袍照綠髭。',48,'全唐诗/poet.song.229000.json','["南客帝鄉歸，青袍照綠髭。", "問知當世事，解誦聖君詩。", "淮蜀軍書急，湘深邸報遲。", "空傳廷試策，韋布說邊陲。"]'),
('395a7d86-b694-4132-95ea-7be542621f91','南林寺','樂雷發','宋','宋诗','song-poetry','','[]','律院僧應俗，亭荒草木刪。',48,'全唐诗/poet.song.229000.json','["律院僧應俗，亭荒草木刪。", "無碑堪考古，有客自看山。", "竹好惟嫌密，雲多不自閒。", "小溪知最近，童浴夜方還。"]'),
('99390b4c-2b11-4b00-8952-764fb9d87dc0','送客有感','釋行海','宋','宋诗','song-poetry','','[]','幾年不上越王臺，獨立津亭送客迴。',64,'全唐诗/poet.song.229000.json','["幾年不上越王臺，獨立津亭送客迴。", "風捲潮聲歸海去，雲排雨勢隔江來。", "山藏南渡諸陵樹，沙漲西興一岸苔。", "秋後風光圖畫裏，欄干十二憶蓬萊。"]'),
('4a057978-f1cf-4d89-911e-2a6beacac5d6','送石居上人歸別業','釋行海','宋','宋诗','song-poetry','','[]','不忍送君楊柳津，隔江相憶始相親。',64,'全唐诗/poet.song.229000.json','["不忍送君楊柳津，隔江相憶始相親。", "未能款曲論心事，翻似尋常識面人。", "一枕落花終夜雨，十年芳草故鄉春。", "栽松若有青山剩，借結茅廬作近鄰。"]'),
('0bab5577-b917-4268-a788-78f0612d5e4c','送寧道二友','釋行海','宋','宋诗','song-poetry','','[]','二友東歸我獨存，欲言心事恐消魂。',64,'全唐诗/poet.song.229000.json','["二友東歸我獨存，欲言心事恐消魂。", "片帆明日知何處，一路青山看到門。", "別後寄書期再見，靜中開卷憶同論。", "自憐不得相隨去，梅雨蕭蕭海氣昏。"]'),
('c2f1bdc8-62e6-414d-8400-517353bd8af3','送寧雪磯歸剡','釋行海','宋','宋诗','song-poetry','','[]','無緣同上浙東船，親老家貧每自憐。',64,'全唐诗/poet.song.229000.json','["無緣同上浙東船，親老家貧每自憐。", "蹤跡久留千里外，情懷不比十年前。", "客遊何處無芳草，人別他鄉有杜鵑。", "別後欲知鄉裏事，煩君千萬寄魚牋。"]'),
('8d79d09f-1433-4427-aadf-7da58f1c45d5','送曲江爲上人歸省','釋行海','宋','宋诗','song-poetry','','[]','蛩吟木落帝王州，我亦凄凉感旅遊。',64,'全唐诗/poet.song.229000.json','["蛩吟木落帝王州，我亦凄凉感旅遊。", "正起四方朋友念，又添一個別離愁。", "溪村棹急紅菱雨，山市砧催白雁秋。", "聞道北堂相憶久，西風吹柳曲江頭。"]'),
('d360e57e-3df9-4b64-b69a-8b883d622fac','送以道上人住常州王潜泉別業','釋行海','宋','宋诗','song-poetry','','[]','茫茫野水接秋天，載去蘋花月一船。',64,'全唐诗/poet.song.229000.json','["茫茫野水接秋天，載去蘋花月一船。", "世上豈無閑宇宙，吳中別有好林泉。", "田豐綠薺桃晨雨，爨老紅蘿閉夕烟。", "早晚亦歸王戴邑，谿房相對鷺鷥眠。"]'),
('28e962fd-6ab5-4acb-95a1-c6f194b852a9','送清上人歸暨陽','釋行海','宋','宋诗','song-poetry','','[]','中分吳越大江流，君自東歸我尚留。',64,'全唐诗/poet.song.229000.json','["中分吳越大江流，君自東歸我尚留。", "烟鎖白楊漁浦晚，風鳴黄葉鳳城秋。", "窮途散盡三千客，故國難忘十二樓。", "依舊團圓今夜月，照吟不照別離愁。"]'),
('b46745aa-fb28-478b-bd92-6ea923d5216a','送希晉還雲間','釋行海','宋','宋诗','song-poetry','','[]','暮蟬黄葉徧長安，澹泊交情別亦難。',64,'全唐诗/poet.song.229000.json','["暮蟬黄葉徧長安，澹泊交情別亦難。", "客路何時又相見，菊花今日更同看。", "一帆風露官河曉，十月蒹葭雁磧寒。", "別後相思那可免，水雲西望白漫漫。"]'),
('7f92740a-da42-4e18-aafa-e45abfc90fc6','送清上人歸苕溪','釋行海','宋','宋诗','song-poetry','','[]','尋常送客尚多愁，况是天涯寂寞秋。',64,'全唐诗/poet.song.229000.json','["尋常送客尚多愁，况是天涯寂寞秋。", "曉別蛩聲黄葉寺，夜分漁火白蘋洲。", "病餘骨肉添新夢，歸後風烟憶舊遊。", "何處何時又相見，青山長在水長流。"]'),
('587504b7-4b30-4ded-bdcf-69a93f70b47d','送立上人離天竺講席往依虎丘禪院','釋行海','宋','宋诗','song-poetry','','[]','心對青燈作死灰，劍池山色思徘徊。',64,'全唐诗/poet.song.229000.json','["心對青燈作死灰，劍池山色思徘徊。", "頂初試笠應嫌重，教有招書己懶開。", "楚塞數行春雁轉，吳天一片白雲來。", "定回月在松頭靜，還上生公舊講臺。"]'),
('35ff2ef3-443c-46ed-93c2-68c68a73b295','送無作上人之四明  其一','釋行海','宋','宋诗','song-poetry','','[]','老子窮通聽我吟，山中惟有我同心。',64,'全唐诗/poet.song.229000.json','["老子窮通聽我吟，山中惟有我同心。", "數莖白髮驚年老，幾度青燈戀夜深。", "冰鎖蛟龍盤大澤，雲遮蘭蕙託幽林。", "道行亦自東浮海，海國清風引梵音。"]'),
('fa113677-e6c4-4ed6-bed1-6b9c0ace1cfe','送無作上人之四明  其二','釋行海','宋','宋诗','song-poetry','','[]','天涯彼此一閑身，同看梅花幾度春。',64,'全唐诗/poet.song.229000.json','["天涯彼此一閑身，同看梅花幾度春。", "寒怕山川行色近，夜圍燈火別情真。", "君還西上當何日，我欲東歸未有因。", "鄉社只今寥落甚，豈堪相送老成人。"]'),
('5ec9c996-962d-4fa3-b904-e8afc43b678f','送無作上人之四明  其三','釋行海','宋','宋诗','song-poetry','','[]','天地蕭蕭萬木乾，獨摇金錫下長安。',64,'全唐诗/poet.song.229000.json','["天地蕭蕭萬木乾，獨摇金錫下長安。", "從來作客今如此，始欲留君亦自難。", "帆带北風潮信急，雪迷南國雁聲寒。", "分明一片相思意，湖上青山誰共看。"]'),
('cb7be1ea-f5c5-4aaa-b8f3-eefcb2a5c139','送秋谷蘭上人','釋行海','宋','宋诗','song-poetry','','[]','春來我亦夢家林，萬水千山不可尋。',64,'全唐诗/poet.song.229000.json','["春來我亦夢家林，萬水千山不可尋。", "白雪易侵遊子鬢，黄金難買故人心。", "夜船摇月平河穩，曉嶺登雲古樹深。", "湖上又期寒食後，倚欄同對落花吟。"]'),
('89c66cd6-5052-407e-8752-e185e3dd8a4c','送人之姑蘇','釋行海','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','片帆歸去百花洲，今日因君憶舊遊。',64,'全唐诗/poet.song.229000.json','["片帆歸去百花洲，今日因君憶舊遊。", "澤國風烟多好景，洞庭林壑最宜秋。", "垂虹未霽難收影，頑石如今不點頭。", "記得一番吟最苦，翻然惆悵爲吳鈎。"]'),
('0068ec6d-7e1e-486f-8b26-391f505507c8','送子謙皈松江','釋行海','宋','宋诗','song-poetry','','[]','秋風社燕忽辭梁，志士鷹揚在四方。',64,'全唐诗/poet.song.229000.json','["秋風社燕忽辭梁，志士鷹揚在四方。", "一曝十寒吾已老，寸陰尺璧子須忙。", "松於雪裏方知操，梅到春前便有香。", "此去莫忘燈下約，蠹書重整此山房。"]'),
('6b0fbf51-3647-4b72-abe9-3e602224c5d2','送先上人歸越','釋行海','宋','宋诗','song-poetry','','[]','蟋蟀聲中念故鄉，片帆風正渡錢塘。',64,'全唐诗/poet.song.229000.json','["蟋蟀聲中念故鄉，片帆風正渡錢塘。", "烟橫浦口魚謳晚，月湧潮頭蜃氣涼。", "一脈菲泉清夏后，千年酒甕醉秦皇。", "青鞋布襪秋歸早，猶有荷花鏡裏香。"]'),
('031688fb-57dd-4500-9796-86f323b8459c','送隆上人遊淮南','釋行海','宋','宋诗','song-poetry','','[]','欲向淮南作勝遊，如何却在雁來秋。',64,'全唐诗/poet.song.229000.json','["欲向淮南作勝遊，如何却在雁來秋。", "戰曾采石連青海，恨不回龍到白溝。", "山立金焦雙砥柱，地分吳楚一江流。", "憑君莫上新亭望，北面風烟只舊愁。"]'),
('3c371adb-012c-443b-81ff-7cb984fcac6b','送雲太虛禪師住台州報恩寺','釋行海','宋','宋诗','song-poetry','','[]','高卧北山長懶出，忽辭猿鶴上扁舟。',64,'全唐诗/poet.song.229000.json','["高卧北山長懶出，忽辭猿鶴上扁舟。", "此行爲道無榮念，相送於人有別愁。", "峰頂凉宵明月上，門前終日大江流。", "東南一路多奇觀，寒拾諸公盡舊遊。"]'),
('2067cb9b-f5dc-48e6-a873-61e93326a841','送人之姑蘇','釋行海','宋','宋诗','song-poetry','','[]','楓落吳江歸興濃，不知何日定相逢。',64,'全唐诗/poet.song.229000.json','["楓落吳江歸興濃，不知何日定相逢。", "山中獨對三生石，城外誰聽半夜鐘。", "金井露凉鳴蟋蟀，石池霜早歇芙蓉。", "新詩別後須相寄，只在雲深第一峰。"]'),
('4f352c91-ef87-4fba-b664-0f7bcdfd2432','送壽芳恭三友歸安吉','釋行海','宋','宋诗','song-poetry','','[]','此心偏向寂寥難，學至寂寥心自安。',64,'全唐诗/poet.song.229000.json','["此心偏向寂寥難，學至寂寥心自安。", "楊柳忽驚秋色晚，芭蕉不耐雨聲寒。", "白雲深處人相別，明月圓時我獨看。", "極目吳天征棹遠，渡頭斜日落楓丹。"]'),
('71c6fbe5-1701-49c2-ac5a-04c294c3aa88','送同里昂上人','釋行海','宋','宋诗','song-poetry','','[]','秋風何事趣歸期，人物凄凉渡欲垂。',64,'全唐诗/poet.song.229000.json','["秋風何事趣歸期，人物凄凉渡欲垂。", "學道須從年少日，苦心直到歲寒時。", "近來鄉國無消息，老去情懷怕別離。", "愧我徒增懷橘念，弊裘猶自客京師。"]'),
('4ceaaf3a-139b-4f10-afda-180a10d6cfe0','贈李隠士','釋行海','宋','宋诗','song-poetry','','[]','白苧爲衣草結廬，相逢猶問世何如。',64,'全唐诗/poet.song.229000.json','["白苧爲衣草結廬，相逢猶問世何如。", "每彈山水忘憂曲，懶上王侯自薦書。", "白眼鷗邊窺宇宙，清罇月下宴樵漁。", "時情任似長亭柳，纔向秋風日日疎。"]'),
('46c9fc98-b3bc-47e8-8808-997bbe3f37b6','贈王漁山','釋行海','宋','宋诗','song-poetry','','[]','冷觀天地只浮漚，勝水名山徧去遊。',64,'全唐诗/poet.song.229000.json','["冷觀天地只浮漚，勝水名山徧去遊。", "書劍傳家拋弟姪，漁樵作隊賤公侯。", "卧聽瀑布分僧榻，醉插梅花上酒樓。", "篋裏不留封禪稿，知心江上有沙鷗。"]'),
('d0673ef1-9cb9-4eb1-a857-5ad855d702bc','贈葉苔磯','釋行海','宋','宋诗','song-poetry','','[]','養竹栽花住玉京，已將功業付閑情。',64,'全唐诗/poet.song.229000.json','["養竹栽花住玉京，已將功業付閑情。", "太平世上無豪傑，大雅場中有老成。", "白日長思泉石趣，青樓空沸管絃聲。", "冷觀人事如碁局，誰肯忘機過一生。"]'),
('3ebe9f60-618c-4591-b890-a234e7bba648','寄新冶城','釋行海','宋','宋诗','song-poetry','','[]','客中情况果何如，消息傳來恐是虛。',64,'全唐诗/poet.song.229000.json','["客中情况果何如，消息傳來恐是虛。", "今歲又居何處寺，多時不得故人書。", "自憐南北身無定，相隔江山夢亦疎。", "若有便風須寄信，白雲深處是吾廬。"]'),
('ecac9769-20cb-44fa-b8c8-ed7aca76592e','寄陽羨山俊癯翁','釋行海','宋','宋诗','song-poetry','','[]','一曲相思斷玉絃，白芙蓉畔水生烟。',64,'全唐诗/poet.song.229000.json','["一曲相思斷玉絃，白芙蓉畔水生烟。", "自從上國人相別，每看中秋月不圓。", "蜀馬嘶風驚韃鼓，吳兒殺氣暗漁船。", "何當跨鶴來陽羨，同訪黄龍古洞天。"]'),
('45cfe76c-ca11-47db-a608-0d6bdbecb5cc','寄集慶寺瑞上人','釋行海','宋','宋诗','song-poetry','','[]','西遊今已十餘年，更涉波濤路半千。',64,'全唐诗/poet.song.229000.json','["西遊今已十餘年，更涉波濤路半千。", "燕度玉京逢社雨，雁回金斗沒晴烟。", "一春簫鼓多成市，五色樓臺半倚天。", "我爲思君忘不得，踏花須上北門船。"]'),
('927ef152-b151-4862-b5d0-1487f811f8f3','寄瑞天藴','釋行海','宋','宋诗','song-poetry','','[]','別時許有書相寄，望望江東是幾回。',64,'全唐诗/poet.song.229000.json','["別時許有書相寄，望望江東是幾回。", "霸越亡吳增感慨，登山臨水復徘徊。", "去秋同聽梧桐落，今日獨看鴻雁來。", "路隔半千烟靄外，爲誰頻上最高臺。"]'),
('18de28de-d334-49d1-9597-270161d8169c','寄象岑上人','釋行海','宋','宋诗','song-poetry','','[]','宴坐凌霄峰頂寺，時時音信得相聞。',64,'全唐诗/poet.song.229000.json','["宴坐凌霄峰頂寺，時時音信得相聞。", "十年寥落長爲客，四海交遊少似君。", "楊柳重青相送處，鷺鷥潔白自成羣。", "寒思會面知何日，百里溪山隔暮雲。"]'),
('620a66f8-0a14-4009-b841-a0350049ad94','寄一貫道','釋行海','宋','宋诗','song-poetry','','[]','別君容易見君難，三載無書去問安。',64,'全唐诗/poet.song.229000.json','["別君容易見君難，三載無書去問安。", "身在異鄉春又老，夢回孤館雨生寒。", "江山有待人皆往，桃李無言客自看。", "東望沃洲何處是，暮雲重疊鎖峰巒。"]'),
('df0b1044-1062-4d65-90df-cb75d536f598','寄隆虛岩行人','釋行海','宋','宋诗','song-poetry','','[]','藤花小朶插軍持，香篆輕烟裊裊移。',64,'全唐诗/poet.song.229000.json','["藤花小朶插軍持，香篆輕烟裊裊移。", "山鳥不啼禪定處，池魚偏集誦經時。", "風聲入戶松千樹，月影臨窗竹一枝。", "舊日寒山行道外，崖間葉上亦題詩。"]'),
('82cacf91-5727-42d2-9baf-7248de21b51a','寄耕雲先輩','釋行海','宋','宋诗','song-poetry','','[]','老子歸耕谷口雲，幾年音信不相聞。',64,'全唐诗/poet.song.229000.json','["老子歸耕谷口雲，幾年音信不相聞。", "青燈事業難忘處，白社蕭條又憶君。", "萬岳千岩雙鬢改，三吳百越一江分。", "何當亦用蒲輪起，智者遺編有蠹紋。"]'),
('5a7f92ea-fcc6-4e7e-b8e2-53e1c696a9cf','寄赤城新珩講師','釋行海','宋','宋诗','song-poetry','','[]','塔聳霞標在上頭，杖藜猶記昔年遊。',64,'全唐诗/poet.song.229000.json','["塔聳霞標在上頭，杖藜猶記昔年遊。", "月生丹井樹林靜，烟新碧桃溪澗幽。", "夜講石筵龍象集，晝吟岩宇鬼神愁。", "思君每欲尋君去，水闊山遥兩鬢秋。"]'),
('45eba912-9fca-4d35-9431-7cdba316b168','懷方山人','釋行海','宋','宋诗','song-poetry','','[]','養花天氣雨濛濛，意欲相尋去未通。',64,'全唐诗/poet.song.229000.json','["養花天氣雨濛濛，意欲相尋去未通。", "自少江湖同苦樂，如今燈火各西東。", "百年總是難忘日，一信無由托便風。", "曾共月明岩上坐，思君還在月明中。"]'),
('2f6cf48b-8b6f-44d8-aa07-3e95e03ea88b','得方山人書因有所懷','釋行海','宋','宋诗','song-poetry','','[]','三度寄書渾不到，故人書到我方聞。',64,'全唐诗/poet.song.229000.json','["三度寄書渾不到，故人書到我方聞。", "路歧南北成如此，聚散情懷恰似君。", "千里倍看今夜月，兩鄉遥認隔江雲。", "寒窗正自憐孤影，聽得斷鴻聲念羣。"]'),
('3bd53d41-6859-4f25-8e30-4644e0043d1f','自嘉興歸天竺懷同友','釋行海','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','九月遊吳菊盛開，洞庭不去爲君回。',64,'全唐诗/poet.song.229000.json','["九月遊吳菊盛開，洞庭不去爲君回。", "病歸故里留書在，約到明年看駕來。", "賓客過門題姓字，菖蒲別主染塵埃。", "誰知獨向秋風裏，靜倚山窗對綠苔。"]'),
('035b417d-c11e-445a-91c2-6818c5c4bd63','辛亥春別湖上諸友','釋行海','宋','宋诗','song-poetry','','[]','江南花信厭春寒，鄉路迢迢去亦難。',64,'全唐诗/poet.song.229000.json','["江南花信厭春寒，鄉路迢迢去亦難。", "不解趨時人笑拙，每懷歸計自求安。", "明朝芳草空相憶，何處青山復共看。", "二十八年清苦志，獨歌白雪對幽蘭。"]'),
('08ed3ee4-07a2-4f18-8825-ffc179ee3453','與中上人至雲間話別','釋行海','宋','宋诗','song-poetry','','[]','寒雲漠漠浦悠悠，短棹同登八月秋。',64,'全唐诗/poet.song.229000.json','["寒雲漠漠浦悠悠，短棹同登八月秋。", "一寸不磨心似鐵，四方無定迹如鷗。", "江鄉雁過蒹葭冷，雨館人分蟋蟀愁。", "相見有期還惜別，百年能得幾交遊。"]'),
('d2f5e69b-34d7-40f7-a927-25fbf049f1d6','逢舍弟','釋行海','宋','宋诗','song-poetry','','[]','兄弟相逢在浙西，問家言客思依依。',64,'全唐诗/poet.song.229000.json','["兄弟相逢在浙西，問家言客思依依。", "已難與汝淒涼別，終不教吾獨自歸。", "流落異鄉成老貌，別來無處寄寒衣。", "死生今日心方穩，消息相傳總是非。"]'),
('cf397f96-2b83-48c6-8ec7-9f6e54c02f4a','時在臨雲寄虎溪侃直山','釋行海','宋','宋诗','song-poetry','','[]','白首歸看舊種松，十年相別此相逢。',64,'全唐诗/poet.song.229000.json','["白首歸看舊種松，十年相別此相逢。", "近疎面會因多雨，似隔天涯只一峰。", "數樹綠烟鋪薜荔，半池紅露泣芙蓉。", "故鄉迢遞故人少，江北江南思萬重。"]'),
('1866e9c0-e806-4ab1-b3c0-e3ac4fb1c8b7','酬弘道夫','釋行海','宋','宋诗','song-poetry','','[]','人隔三州只自知，月明千里是相思。',64,'全唐诗/poet.song.229000.json','["人隔三州只自知，月明千里是相思。", "湖山秋後分題處，朋友叢中憶欠誰。", "百歲自完休獻玉，萬般如戲莫悲絲。", "餘生定有重逢日，雲水茫茫未可期。"]'),
('ae81b2d2-577f-4d75-8a4f-a357bb52283e','哭王秀岩  其一','釋行海','宋','宋诗','song-poetry','','[]','南湖天竺舊同遊，心戀青燈老未休。',64,'全唐诗/poet.song.229000.json','["南湖天竺舊同遊，心戀青燈老未休。", "梅塢春風吹夢破，竹堂秋雨滴人愁。", "鼎分角立英雄世，虎逝龍亡寂寞秋。", "天地獨教吾輩在，臨風三些涕橫流。"]'),
('11e583e3-28a2-4f49-a2e1-de42cd20b0d7','哭王秀岩  其二','釋行海','宋','宋诗','song-poetry','','[]','十年知己盡消磨，哭到秀岩愁更多。',64,'全唐诗/poet.song.229000.json','["十年知己盡消磨，哭到秀岩愁更多。", "顧我此生誰繾綣，問天今日事如何。", "雨聽蟋蟀成商調，露採芙蓉發楚歌。", "畢竟寸情哀不盡，但將榮辱付滄波。"]'),
('eeb2de14-055b-4496-8b6a-2ea3eb03c2f4','悼允上人','釋行海','宋','宋诗','song-poetry','','[]','白雲寺裏同聽講，卜得山齋竹樹幽。',64,'全唐诗/poet.song.229000.json','["白雲寺裏同聽講，卜得山齋竹樹幽。", "君已不來梅自發，世皆如夢水長流。", "寒燈苦志歸黄土，俗客輕人將白頭。", "萬惜少年多是死，靜思吾道轉堪愁。"]'),
('dc3e7e4a-e865-4855-a5ac-d748d1e967bf','懷珦潜山','釋行海','宋','宋诗','song-poetry','','[]','楚雨吳烟動客思，江梅發後失歸期。',64,'全唐诗/poet.song.229000.json','["楚雨吳烟動客思，江梅發後失歸期。", "傳來蹤跡渾無定，飄泊情懷已可知。", "鼓角每驚多事日，鶑花空度少年時。", "與君如此長相別，苦樂同心更有誰。"]'),
('2b897c39-4f40-4c18-bac8-f7ca616acf14','留癯翁','釋行海','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一載相思始見君，同心長是不同羣。',64,'全唐诗/poet.song.229000.json','["一載相思始見君，同心長是不同羣。", "因看世上多青草，只話山中好白雲。", "路遠寄書難得到，夜深別語豈堪聞。", "西湖正有梅花發，水堠官程且莫云。"]'),
('5ec30fdf-0c8a-4660-9cfb-16cd06fa7360','僧號利生','釋行海','宋','宋诗','song-poetry','','[]','心因愛物語慈悲，梵律鈔成解受持。',64,'全唐诗/poet.song.229000.json','["心因愛物語慈悲，梵律鈔成解受持。", "施茗唯燒無繭葉，助橋不伐有巢枝。", "忍看獵火巡山穴，貴買罾魚放石池。", "多少懷恩如父母，朱門彈鋏少逢知。"]'),
('291420ff-e45b-436f-9968-3111560fa4d9','喜方溪復歸白雲','釋行海','宋','宋诗','song-poetry','','[]','十載青燈自苦辛，懶將白眼顧浮塵。',64,'全唐诗/poet.song.229000.json','["十載青燈自苦辛，懶將白眼顧浮塵。", "鳳聲偏近瑶臺月，草色難連玉樹春。", "雲有去來非本意，世無榮辱是何人。", "幾番分坐梅邊石，却話桃源只避秦。"]'),
('bd15bb67-5bae-4bea-aee5-25b1dd42383a','喜招樵屋遠歸','釋行海','宋','宋诗','song-poetry','','[]','憶鳳求麟最可憐，白頭躑躅幾山川。',64,'全唐诗/poet.song.229000.json','["憶鳳求麟最可憐，白頭躑躅幾山川。", "塵昏泗水絃歌地，灰冷咸陽竹帛烟。", "萬里雲霄曾放鶴，五湖風月滿歸船。", "乾坤自有知音在，牙也何須便絕絃。"]'),
('4e2a321b-738f-49a5-abd0-d42c4e0ae8d9','雲泉禪師哀詞','釋行海','宋','宋诗','song-poetry','','[]','一片禪心無用處，蘋花溪上看垂綸。',64,'全唐诗/poet.song.229000.json','["一片禪心無用處，蘋花溪上看垂綸。", "也知白璧黄金貴，何似青鞋布襪貧。", "吟畔山川生哭泣，筆頭蘭竹露精神。", "如今雲散泉流去，淡日凄風雜野塵。"]'),
('844e2c07-6e90-416d-8df8-639f1296f7e6','留別陳藏一','釋行海','宋','宋诗','song-poetry','','[]','君住江西我浙東，偶然相識在吳中。',64,'全唐诗/poet.song.229000.json','["君住江西我浙東，偶然相識在吳中。", "知名彼此非今日，愛客情懷有古風。", "歷數山川遊已徧，苦吟風月趣還同。", "不須惜我匆匆別，約在天街看菊叢。"]'),
('694cbb69-279b-4d80-9cd3-6165e506edce','和湯秘書見寄韻','釋行海','宋','宋诗','song-poetry','','[]','書劍衝寒到日邊，烟霞曾結幾生緣。',64,'全唐诗/poet.song.229000.json','["書劍衝寒到日邊，烟霞曾結幾生緣。", "醉邀明月逢梅醒，嘯入青山對竹眠。", "老晤莊周爲蝶後，誰思腐草化螢前。", "新詩自有經綸志，乘興莫將紅葉偏。"]'),
('fa9e671f-5bc5-4bcb-864e-93716c0a1e54','和浩師書事','釋行海','宋','宋诗','song-poetry','','[]','平原漠漠带晴川，秋草秋風又一年。',64,'全唐诗/poet.song.229000.json','["平原漠漠带晴川，秋草秋風又一年。", "堯舜不知今日事，烟霞同結幾生緣。", "未聞世道如絃直，應怪鷗身似雪鮮。", "臨水登山情亦懶，枕書閑向北窗眠。"]'),
('21cc9bb0-701b-49aa-86e7-deb84fda3c54','和馨果二友見寄韻','釋行海','宋','宋诗','song-poetry','','[]','幾度懷歸浙水東，無端又下白雲中。',64,'全唐诗/poet.song.229000.json','["幾度懷歸浙水東，無端又下白雲中。", "當窗石色寒留雨，出洞猿聲靜带風。", "崖底碧烟生暮景，樹頭紅子落晴空。", "酷憐後夜薌林月，照我思君處不同。"]'),
('7fc21d72-c334-4672-838d-f6ae075ba5e5','湖上送志道歸金華','釋行海','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我住千巖萬岳州，金華佳處未曾遊。',64,'全唐诗/poet.song.229000.json','["我住千巖萬岳州，金華佳處未曾遊。", "心期小艇頻歸洞，夢带清風獨倚樓。", "野店霜深聞寒雁，水村月淡見沙鷗。", "明朝還憶西湖上，楊柳芙蓉正暮秋。"]'),
('cf2723ef-7a91-49aa-84be-d4f5d7849411','洞微翁挽章','釋行海','宋','宋诗','song-poetry','','[]','凄凉木末搴芙蓉，萬里鷹揚路忽窮。',64,'全唐诗/poet.song.229000.json','["凄凉木末搴芙蓉，萬里鷹揚路忽窮。", "箭到紅心翻墮地，花成綠子又隨風。", "可憐玉兔沉滄海，却放寒烏占碧桐。", "萬事看來都是夢，山林猶憶舊英雄。"]'),
('e10e5135-ba5f-442a-948d-8b2a8512949f','寓歸雲閣懷上竺聽雨齋馨果二友','釋行海','宋','宋诗','song-poetry','','[]','千金溪上歸雲閣，雙檜峰前聽雨齋。',64,'全唐诗/poet.song.229000.json','["千金溪上歸雲閣，雙檜峰前聽雨齋。", "兩地相思春冷淡，尺書難盡客情懷。", "風兼水氣寒吹帽，雨積簷聲夜滴階。", "想得梅邊舊行徑，履痕聞被落花埋。"]'),
('7c310439-cae0-4912-8516-2d7fc7d3b902','天竺浮尋小樓','釋行海','宋','宋诗','song-poetry','','[]','樓倚飛來小朶峰，每因動業思重重。',64,'全唐诗/poet.song.229000.json','["樓倚飛來小朶峰，每因動業思重重。", "三千日月欺王母，百二山河誤祖龍。", "石淺易知丹井味，洞深難見白雲蹤。", "自慚半座分花雨，無復人聽夜講鐘。"]'),
('d64fb4ff-39b7-4b58-bb17-061821af67b4','天竺謝竹心陳通判見訪  其一','釋行海','宋','宋诗','song-poetry','','[]','紫袍烏帽馬蹄輕，曉浥秋山桂露清。',64,'全唐诗/poet.song.229000.json','["紫袍烏帽馬蹄輕，曉浥秋山桂露清。", "慷慨劇談當世事，艱難方見故人情。", "杏園舊宴魁麟筆，蓮幙重開佐鳳城。", "青瑣玉堂殊有待，江淮何日可休兵。"]'),
('a4d96d09-694c-45b0-bd08-7aafacd33ec2','天竺謝竹心陳通判見訪  其二','釋行海','宋','宋诗','song-poetry','','[]','三十餘年別剡川，一瓢分飲葛洪泉。',64,'全唐诗/poet.song.229000.json','["三十餘年別剡川，一瓢分飲葛洪泉。", "當時玄度尋支遁，今日昌黎欠大顛。", "遊宦石頭懷往事，傷心瓜步梗來船。", "盍應借箸趨前列，北面風寒快著鞭。"]'),
('c41d89c7-f419-4338-9995-a7a0b7bcc9f6','鹿臺止作  其一','釋行海','宋','宋诗','song-poetry','','[]','九州烟景雜塵埃，自愛吾廬住鹿臺。',64,'全唐诗/poet.song.229000.json','["九州烟景雜塵埃，自愛吾廬住鹿臺。", "百計不如歸最好，五行只可問無災。", "野園日暖花爭發，貧屋春深燕自來。", "王戴風流千載下，水聲山色更徘徊。"]'),
('c62f930a-5087-44d7-bf89-ed240ce28a81','鹿臺止作  其二','釋行海','宋','宋诗','song-poetry','','[]','林下寥寥宇宙寬，孤懷懶與世相干。',64,'全唐诗/poet.song.229000.json','["林下寥寥宇宙寬，孤懷懶與世相干。", "窮通有限隨時好，仁義相拘作事難。", "故國不知春後信，他山頻在夢中看。", "棠梨花發幽窗下，遊蝶不來風雨寒。"]'),
('e0dfe51a-b02b-4c6d-a528-777e532d5f14','渡錢塘江','釋行海','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','東風曉出鳳凰城，烟棹悠悠春水平。',64,'全唐诗/poet.song.229000.json','["東風曉出鳳凰城，烟棹悠悠春水平。", "征雁北歸鄉有思，大江東去世無情。", "渡人來往青山在，霸業興亡白鳥驚。", "惆悵鯨吞心未死，至今朝暮逐潮生。"]'),
('61b3e4a1-b2bd-4b56-8b85-ae3dd85f43d9','赤城','釋行海','宋','宋诗','song-poetry','','[]','玉京仙額篆封苔，密密春雲洞不開。',64,'全唐诗/poet.song.229000.json','["玉京仙額篆封苔，密密春雲洞不開。", "白蟒降時憑鐵錫，紅霞飛處接瑶臺。", "林幽怪石如人立，夜靜空山有鬼哀。", "一曲鳳簫聲已斷，釋籤岩下獨徘徊。"]'),
('9032142e-6473-4a25-83e1-64f7ebce6c8a','天竺有懷','釋行海','宋','宋诗','song-poetry','','[]','白日閉門亦懶開，門前日日起塵埃。',64,'全唐诗/poet.song.229000.json','["白日閉門亦懶開，門前日日起塵埃。", "人無舊分言難託，道有同心信不來。", "黄菊一籬秋冷淡，碧雲千里暮徘徊。", "去年憶得寒江畔，君上孤舟我獨回。"]'),
('f3a66427-4b04-4c8c-9d26-de3079152bf4','西湖早春','釋行海','宋','宋诗','song-poetry','','["\u897f\u6e56"]','多時不向柳邊來，每箇幽亭坐一回。',64,'全唐诗/poet.song.229000.json','["多時不向柳邊來，每箇幽亭坐一回。", "春哢未容鶑燕閙，芳心猶待杏桃開。", "飄摇水面漁舟穩，宛轉風前玉笛哀。", "太乙清都五雲表，冷香空鎖御園梅。"]'),
('d757a494-5816-478a-8804-1aa993a51f8f','東掖懷天竺','釋行海','宋','宋诗','song-poetry','','[]','十年心事已蹉跎，吳越興亡付綠波。',64,'全唐诗/poet.song.229000.json','["十年心事已蹉跎，吳越興亡付綠波。", "衰鬢又驚黄葉落，故鄉遥認白雲多。", "葛洪井畔三生石，處士梅邊十里荷。", "總是平生快心處，夜長無奈月明何。"]'),
('9b1ba0d4-e75a-44fc-92a4-2bee56d8a507','湖上','釋行海','宋','宋诗','song-poetry','','[]','雨後湖光照綠蘋，岸行舟載苦吟身。',64,'全唐诗/poet.song.229000.json','["雨後湖光照綠蘋，岸行舟載苦吟身。", "恨無杯酒澆胸次，折得梅花插帽輪。", "流水六橋人自老，暖烟十里柳重新。", "飛來白鷺如相識，共樂羲皇世上春。"]'),
('f4693610-e4e1-4f64-982d-b38abcce07d5','題南岩','釋行海','宋','宋诗','song-poetry','','[]','昔年此地屬龍門，兩壁崖崖禹鑿痕。',64,'全唐诗/poet.song.229000.json','["昔年此地屬龍門，兩壁崖崖禹鑿痕。", "泉墮半空翻作雨，天藏一竅狹於村。", "蘿烟尚瘞仙人骨，磯月應招釣客魂。", "岩下住僧多白首，不聞塵世似桃源。"]'),
('8888d4dd-5f3c-4511-b95f-788f94cb145b','歸剡  其一','釋行海','宋','宋诗','song-poetry','','[]','此生書劍學無成，癖愛林泉夢亦清。',64,'全唐诗/poet.song.229000.json','["此生書劍學無成，癖愛林泉夢亦清。", "甘苦已知浮世味，親疎盡見舊交情。", "五湖風月隨閑客，十載冰霜對短檠。", "歸得又思滄海去，是誰堪結歲寒盟。"]'),
('b1938a73-198f-4128-8491-5a478b67335c','歸剡  其二','釋行海','宋','宋诗','song-poetry','','[]','三十將成道未成，菱花頻照意頻驚。',64,'全唐诗/poet.song.229000.json','["三十將成道未成，菱花頻照意頻驚。", "百年得趣非容易，萬事無心是太平。", "白雪陽春誰欲聽，青鞋布襪世相輕。", "天台廬岳難忘處，泉石皆知舊姓名。"]'),
('cb6af3b7-373d-413a-a008-757ba35144cd','歸剡  其三','釋行海','宋','宋诗','song-poetry','','[]','天地寬閑鼓角疎，江南烟景憶當初。',64,'全唐诗/poet.song.229000.json','["天地寬閑鼓角疎，江南烟景憶當初。", "乍歸故里仍如客，偏愛滄洲不爲魚。", "草木有心知雨露，樓臺回首作丘墟。", "夕陽詠罷餐秋菊，又放青山入弊廬。"]'),
('09119afd-84a5-4dea-803e-f16ec696ef96','歸剡  其四','釋行海','宋','宋诗','song-poetry','','[]','流水東流竟不回，已將心事作寒灰。',64,'全唐诗/poet.song.229000.json','["流水東流竟不回，已將心事作寒灰。", "窗前白鳥尋常過，籬下黄花寂寞開。", "玉珮金鞍渾是夢，鳳簫龍管只堪哀。", "多時不得中原信，暮雨西風雁自來。"]'),
('73c73c1c-feb7-4554-b1bb-c807c65bc443','歸剡  其五','釋行海','宋','宋诗','song-poetry','','[]','處處溪山得趣真，不曾富貴不曾貧。',64,'全唐诗/poet.song.229000.json','["處處溪山得趣真，不曾富貴不曾貧。", "夢中覓句渾如醒，秋後看花亦似春。", "未許黄金酬苦節，祇應白鳥伴閑身。", "門前一徑蒼苔色，終歲喜無車馬塵。"]'),
('32d5965d-65f4-41f4-8028-0e905ed4e0a0','天竺書懷','釋行海','宋','宋诗','song-poetry','','[]','滿山風露正秋深，石井欄邊蛩夜吟。',64,'全唐诗/poet.song.229000.json','["滿山風露正秋深，石井欄邊蛩夜吟。", "黄葉隨流如有約，白雲歸岫亦無心。", "擬同猿鳥消閑日，別卜烟霞入遠林。", "畢竟一榮還一辱，百年何用覓知音。"]'),
('3cbb2d9c-2c20-4d7d-a552-1471510bb193','臨清樓','釋行海','宋','宋诗','song-poetry','','[]','樓影斜侵賀鑑湖，月隨天遠極蒼梧。',64,'全唐诗/poet.song.229000.json','["樓影斜侵賀鑑湖，月隨天遠極蒼梧。", "青山不受秦封禪，白鳥猶驚越霸圖。", "烟带夕陽籠野樹，雨生春漲沒平蕪。", "好詩都在欄干上，最喜紅塵一點無。"]'),
('cf72ee4c-1718-47e6-befb-7f8a7daa3935','胥山','釋行海','宋','宋诗','song-poetry','','[]','子胥山上噪羣烏，舊日英靈在此無。',64,'全唐诗/poet.song.229000.json','["子胥山上噪羣烏，舊日英靈在此無。", "臣節已虧因撻楚，兵籌雖用奈亡吳。", "雲屯灌木疑烽戍，石列平城設陣圖。", "只可共憂難共樂，知君唯有一陶朱。"]'),
('d55eb99a-405f-4ffa-8b95-599a43f3d795','明暉閣','釋行海','宋','宋诗','song-poetry','','[]','霽色空明宇宙寬，江南佳趣在欄干。',64,'全唐诗/poet.song.229000.json','["霽色空明宇宙寬，江南佳趣在欄干。", "雲蒸列岸青山曉，露濕眠沙白鳥寒。", "極浦風帆侵樹杪，夕陽烟景聚簷端。", "目前有句吟難盡，幾度登臨月下看。"]'),
('1fa10888-baea-4af2-9252-99146a599d15','樓居','釋行海','宋','宋诗','song-poetry','','[]','秋光清接眼光寒，碧落茫茫碧海寬。',64,'全唐诗/poet.song.229000.json','["秋光清接眼光寒，碧落茫茫碧海寬。", "月墮樹根當嶽頂，天垂河氣濕欄干。", "元龍百尺情猶在，黄鶴千年迹未殘。", "最是夕陽烟雨後，不堪直北望長安。"]'),
('70be368c-1c37-4d5e-8177-8bc74563b80a','太后永壽寺方丈紫芝','釋行海','宋','宋诗','song-poetry','','[]','方丈山中草亦靈，參差小朶結菁英。',64,'全唐诗/poet.song.229000.json','["方丈山中草亦靈，參差小朶結菁英。", "玉團紫氣晴霞淡，金縷紅光曉日明。", "四皓自餐商谷穩，九莖曾見泰階平。", "蟠桃春色應同永，香比蟾枝此更清。"]'),
('977b474f-c4a3-4980-a2d9-6cdc283a6698','桂山再歸草堂','釋行海','宋','宋诗','song-poetry','','[]','不聽猿啼天竺樹，幾番春換馬塍花。',64,'全唐诗/poet.song.229000.json','["不聽猿啼天竺樹，幾番春換馬塍花。", "草堂白雪翻新句，蕙帳青氈屬故家。", "野火暫留明月住，好山多被亂雲遮。", "流行坎止人間事，握手相看兩鬢花。"]'),
('bfdb5af5-4aa1-4230-bf1b-dca37c701666','宿高岸庵','釋行海','宋','宋诗','song-poetry','','["\u5ce8\u7709\u5c71"]','溪房長對竹林清，日日思歸計未成。',64,'全唐诗/poet.song.229000.json','["溪房長對竹林清，日日思歸計未成。", "千里暮雲愁作客，一燈寒雨話浮生。", "白鷗沙上東西夢，黄葉階前聚散情。", "清曉又移烟艇去，峨嵋山下釣臺平。"]'),
('d3bac85a-2ab0-4e0c-8cd0-a95889f9ec48','吳中作','釋行海','宋','宋诗','song-poetry','','[]','吳王廢苑又逢秋，門外滄江日夜流。',64,'全唐诗/poet.song.229000.json','["吳王廢苑又逢秋，門外滄江日夜流。", "有淚不同兒女態，此心多爲聖賢愁。", "蓼開南浦雁離塞，月上前峰客倚樓。", "金戶玉堂無夢到，雲山亦足比封侯。"]'),
('fe0c6820-6c50-4066-aa8b-87695f8ae055','壬子七月','釋行海','宋','宋诗','song-poetry','','[]','茫茫宇宙事如何，夕菊朝蘭宛轉歌。',64,'全唐诗/poet.song.229000.json','["茫茫宇宙事如何，夕菊朝蘭宛轉歌。", "陌上柳條誰折盡，客中秋思夜來多。", "陽春欲奏朱絃斷，江水長流白鳥過。", "一自五湖人散後，更無魂夢出烟蘿。"]'),
('7b08d0e0-5af6-4472-a4ce-bc02b6156fee','元日','釋行海','宋','宋诗','song-poetry','','[]','北山猿鶴久爲鄰，閑裏生涯夢裏人。',64,'全唐诗/poet.song.229000.json','["北山猿鶴久爲鄰，閑裏生涯夢裏人。", "旅思經時偏感舊，物華今日又從新。", "棹歌堤上水烟晚，笛奏江南梅柳春。", "五道寂寥先輩盡，自慚無補面生塵。"]'),
('a97c624c-d078-41ce-85e2-39679ef74525','丁未昏  其一','釋行海','宋','宋诗','song-poetry','','[]','異鄉芳草故鄉情，聞道烟烽滿舊京。',64,'全唐诗/poet.song.229000.json','["異鄉芳草故鄉情，聞道烟烽滿舊京。", "林下豈無賢聖迹，城中唯有管絃聲。", "水流雲散成寥落，花笑鶑啼做太平。", "今日已無榮辱念，此山深處寄浮生。"]'),
('fad10849-ed02-47d4-a3ca-d2ce10fdc23f','丁未昏  其二','釋行海','宋','宋诗','song-poetry','','[]','極目東南王氣浮，雨餘春色滿皇州。',64,'全唐诗/poet.song.229000.json','["極目東南王氣浮，雨餘春色滿皇州。", "看花不飲翻如醉，聽角無心亦自愁。", "吳越是非殘客夢，山川今古白人頭。", "殷懃更向樓中望，只有孤雲得自由。"]'),
('ac828905-393b-48aa-9924-78e50222025f','春遊','釋行海','宋','宋诗','song-poetry','','[]','芳菲時節思悠悠，快與風光汗漫遊。',64,'全唐诗/poet.song.229000.json','["芳菲時節思悠悠，快與風光汗漫遊。", "萬物不如花富貴，一春唯有蝶風流。", "仙曾許我黄金骨，天不饒君白雪頭。", "隨處是家隨處客，夜來何事夢滄洲。"]'),
('c265563c-e9a3-4b7e-9464-3c0f1ec4058f','丁卯秋八月奉檄住嘉興先福寺','釋行海','宋','宋诗','song-poetry','','[]','無端檄下白雲中，水國迢迢宋梵宮。',64,'全唐诗/poet.song.229000.json','["無端檄下白雲中，水國迢迢宋梵宮。", "草入空齋隨意綠，花開野地向人紅。", "夕陽每感皈巢鳥，秋色偏憐出塞鴻。", "一個閑身閑不徹，風霜添得鬢成翁。"]'),
('bede14d7-1692-4096-be4e-f329b00da10e','戊辰閏正月書懷  其一','釋行海','宋','宋诗','song-poetry','','[]','一年風景兩逢新，老去情懷最惜春。',64,'全唐诗/poet.song.229000.json','["一年風景兩逢新，老去情懷最惜春。", "未有鶬鶊傳好語，豈無蛺蝶報芳辰。", "花林淑氣蒸香藹，柳岸遊絲惹麴塵。", "今日晴明聊引興，倚樓翻作望鄉人。"]'),
('bbe230b3-b5bb-4bab-ae21-fde3d2067875','戊辰閏正月書懷  其二','釋行海','宋','宋诗','song-poetry','','[]','茅屋風光總入詩，今年何事燕歸遲。',64,'全唐诗/poet.song.229000.json','["茅屋風光總入詩，今年何事燕歸遲。", "繁花猶未競春色，百舌最先啼曉枝。", "深導竹渠防雨漲，密扶花架恐風欹。", "人生三萬六千日，莫負芳菲少壯時。"]'),
('99274fbe-1399-4ee6-8001-dc11e7b73377','戊辰閏正月書懷  其三','釋行海','宋','宋诗','song-poetry','','[]','年年風雨作春愁，天氣晴明便出遊。',64,'全唐诗/poet.song.229000.json','["年年風雨作春愁，天氣晴明便出遊。", "陌上野梅飄趁屐，水邊楊柳礙行舟。", "踏青尚可酬佳節，拾翠如今愧白頭。", "近日貪眠長失曉，鴉啼猶擁黑貂裘。"]'),
('b5426a14-b623-4e06-8e3b-3f187740f2a5','春日寫懷','釋行海','宋','宋诗','song-poetry','','[]','三十餘年吳楚客，如今方覺負初心。',64,'全唐诗/poet.song.229000.json','["三十餘年吳楚客，如今方覺負初心。", "凌霄神駿懷支遁，高屐貂裘怪惠琳。", "洛浦春光花滿樹，渭川風景竹成林。", "歸來不用鳴長鋏，時復一吟梁甫吟。"]'),
('3d019981-9c0d-45cf-b6ef-e7b3686b0894','十月吳中感懷','釋行海','宋','宋诗','song-poetry','','[]','耳熱酣歌向朔風，山河澤國舊吳宮。',64,'全唐诗/poet.song.229000.json','["耳熱酣歌向朔風，山河澤國舊吳宮。", "人生莫羨倉中鼠，世事須知塞上翁。", "大雪風光寒草綠，小春天氣野花紅。", "高堂白首無來信，一點鄉心逐塞鴻。"]'),
('31017770-4bff-4d17-8320-2be435d5ec25','陪一胡府冬日山行','釋行海','宋','宋诗','song-poetry','','[]','筆床藥竈趁霜晴，閑向山中樂宦情。',64,'全唐诗/poet.song.229000.json','["筆床藥竈趁霜晴，閑向山中樂宦情。", "亭傍疎林看石坐，徑穿幽洞遶溪行。", "雁來紅葉我容老，御愛黄花晚節清。", "烟澹鳳城門欲掩，夕陽歸路竹兜輕。"]'),
('2ebe8b1b-f27a-46a5-9ae2-3c6fe28faf82','壬申春寓舊館偃山房有感而作','釋行海','宋','宋诗','song-poetry','','[]','舊館遲留春欲暮，小山林石带平原。',64,'全唐诗/poet.song.229000.json','["舊館遲留春欲暮，小山林石带平原。", "自憐萍迹隨流水，每到花時感故園。", "鳥啄雨牆紅落杏，蝶翻風砌綠抽萱。", "十年未遂東歸計，白髮慈親獨倚門。"]'),
('3f7fcb34-a9f2-44b5-be97-6d980b844a57','秋日紀感','釋行海','宋','宋诗','song-poetry','','[]','聞雞擊楫舊英雄，何處山河是洛中。',64,'全唐诗/poet.song.229000.json','["聞雞擊楫舊英雄，何處山河是洛中。", "龜土坼烟秋望雨，兔輪生暈夜占風。", "䕷蕪只爲王孫綠，菡萏難勝越女紅。", "今日最憐羊叔子，韃塵同污鹿門翁。"]'),
('31fd5585-c4fa-41d3-95b0-ce549b7b8e73','癸酉春僑居無爲寺歸雲閣以十五遊方今五十爲題信筆十首終在五首  其一','釋行海','宋','宋诗','song-poetry','','[]','十五游方今五十，羞將白髮對春風。',64,'全唐诗/poet.song.229000.json','["十五游方今五十，羞將白髮對春風。", "故園泉石情長在，近日江湖趣不同。", "鶑友怕寒拋柳巷，蜂臣探暖到花叢。", "芳菲時節偏多感，無奈歸心逐塞鴻。"]'),
('45746d50-bc26-469a-a1bc-02e74bc59bd1','癸酉春僑居無爲寺歸雲閣以十五遊方今五十爲題信筆十首終在五首  其二','釋行海','宋','宋诗','song-poetry','','[]','十五游方今五十，磨穿鐵硯又重磨。',64,'全唐诗/poet.song.229000.json','["十五游方今五十，磨穿鐵硯又重磨。", "江南自寄雙魚去，橋上誰乘駟馬過。", "春入桑麻驚老眼，冷思天地發長歌。", "山林亦是吾君賜，日望官軍盪白河。"]'),
('320acc22-997e-44ec-83a1-bc6502274fd6','癸酉春僑居無爲寺歸雲閣以十五遊方今五十爲題信筆十首終在五首  其三','釋行海','宋','宋诗','song-poetry','','[]','十五游方今五十，客亭楊柳感人多。',64,'全唐诗/poet.song.229000.json','["十五游方今五十，客亭楊柳感人多。", "江山是處逢春好，風月關情奈老何。", "冒雨花開新接樹，銜泥燕補舊營窠。", "故園昨夜思歸切，聽得櫂船人唱歌。"]'),
('4fa19812-c354-46d3-b572-cd13cc221ea1','癸酉春僑居無爲寺歸雲閣以十五遊方今五十爲題信筆十首終在五首  其四','釋行海','宋','宋诗','song-poetry','','[]','十五游方今五十，每嫌屈蠖苦求伸。',64,'全唐诗/poet.song.229000.json','["十五游方今五十，每嫌屈蠖苦求伸。", "許由不肯爲天子，文叔猶能念故人。", "幾處池塘初解凍，一時桃杏又爭春。", "五湖烟景雖然好，萱砌難忘白髮親。"]'),
('c5dd6b8e-56c7-46b3-9f3e-f6fd46804c62','癸酉春僑居無爲寺歸雲閣以十五遊方今五十爲題信筆十首終在五首  其五','釋行海','宋','宋诗','song-poetry','','[]','十五游方今五十，幾番坎止又流行。',64,'全唐诗/poet.song.229000.json','["十五游方今五十，幾番坎止又流行。", "生來不作千年調，死亦何須五鼎烹。", "周室黍離狼虎國，堯天花藹鳳凰城。", "看山欲跨山中馬，却怪一春無好晴。"]'),
('6a3f864b-9f63-462a-a259-a487d918c178','庚午春作  其一','釋行海','宋','宋诗','song-poetry','','[]','相逢處處說干戈，又報天驕走渡河。',64,'全唐诗/poet.song.229000.json','["相逢處處說干戈，又報天驕走渡河。", "鄉國不知音問少，友朋無奈別離多。", "楊花漠漠迷春思，芳草萋萋感暮歌。", "猿鳥亦移深樹隠，野人只在舊烟蘿。"]'),
('58eb9bdc-6f47-4859-8b11-4b77f75b759e','庚午春作  其二','釋行海','宋','宋诗','song-poetry','','[]','槜李當年是越鄉，客情何事忽清涼。',64,'全唐诗/poet.song.229000.json','["槜李當年是越鄉，客情何事忽清涼。", "霜催燕子歸南國，露逼蟲聲上北堂。", "野外幾重秋水白，天涯一片暮雲黄。", "年年有雁書難寄，無夢到家空夜長。"]'),
('a98e7ebf-222f-4e7f-b7fa-0bf93ea1dbbb','丁未','釋行海','宋','宋诗','song-poetry','','[]','獨住雲邊舊草堂，恨無微力答吾皇。',64,'全唐诗/poet.song.229000.json','["獨住雲邊舊草堂，恨無微力答吾皇。", "又驚烽火交丁未，暗惜山河到靖康。", "塞馬病銜秋草白，鄉兵泣對野花黄。", "年來喜報殘金滅，歌舜歌堯入樂章。"]'),
('e5c44d24-9ad7-4c31-8976-da04b7740ec2','次徐相公韻十首 老將','釋行海','宋','宋诗','song-poetry','','[]','戰曾無甲馬無鞍，諫獵書生賤武官。',64,'全唐诗/poet.song.229000.json','["戰曾無甲馬無鞍，諫獵書生賤武官。", "每憶雲中擒虜健，幾番雪裏枕戈寒。", "箙留響箭機心在，袍損團花血點乾。", "間拍舊弓憐臂力，更憐西北戰場寬。"]'),
('3d479301-0820-40e6-98f1-4d6555befa51','次徐相公韻十首 老馬','釋行海','宋','宋诗','song-poetry','','[]','瘦脊稜稜跨弊鞍，無騎北將服南官。',64,'全唐诗/poet.song.229000.json','["瘦脊稜稜跨弊鞍，無騎北將服南官。", "衰鬉不弁青絲脆，舊鐵猶銜白沫寒。", "料足雨催榮草長，蹄香春暾野花乾。", "可憐驕駿今無用，羞見新駒學步寬。"]'),
('42e9a42c-bd65-45d4-b3f5-8b028172e5ac','次徐相公韻十首 少將','釋行海','宋','宋诗','song-poetry','','[]','滿身鐵甲據金鞍，百戰功成始拜官。',64,'全唐诗/poet.song.229000.json','["滿身鐵甲據金鞍，百戰功成始拜官。", "盡陣解圍兵勢活，分旗奪地戟光寒。", "併吞北虜心長勇，未捷中原淚不乾。", "建立太平終有日，扁舟已愛五湖寬。"]'),
('c6011bc2-e618-4820-a4d6-974795209b0b','次徐相公韻十首 少馬','釋行海','宋','宋诗','song-poetry','','[]','龍堪鬭健鐵爲鞍，頻載將軍戰得官。',64,'全唐诗/poet.song.229000.json','["龍堪鬭健鐵爲鞍，頻載將軍戰得官。", "逐北蹄奔胡雪滑，嘶邊鬣聳朔風寒。", "金鐶轡上紅纓亂，火印輪中白汗乾。", "草滿沙場無暇喫，陣前韁勒不曾寬。"]'),
('60feda7b-3715-47ab-8b2f-7bc9e7205330','次徐相公韻十首 出塞','釋行海','宋','宋诗','song-poetry','','[]','紅羅抹額坐紅鞍，陣逐黄旗撥發官。',64,'全唐诗/poet.song.229000.json','["紅羅抹額坐紅鞍，陣逐黄旗撥發官。", "秋戍盧龍番鼓啞，夜屯白馬虜星寒。", "鐵毬步帳三軍合，火箭燒營萬骨乾。", "兵器徒知是凶器，止戈爲武帝心寬。"]'),
('5e51ec72-ee98-4af9-8611-6bb02012707f','次徐相公韻十首 入塞','釋行海','宋','宋诗','song-poetry','','[]','血戰胡兒盡墮鞍，一番奏凱一封官。',64,'全唐诗/poet.song.229000.json','["血戰胡兒盡墮鞍，一番奏凱一封官。", "兵梟鐵鷂威方猛，酒賜金蕉膽不寒。", "雁塞月陰青燐淡，漁陽雪苦紫茸乾。", "胡亡未必胡無種，韜略縈心不放寬。"]'),
('30d380e8-c80b-4da6-a0b8-8ce86402c063','次徐相公韻十首 劉錡','釋行海','宋','宋诗','song-poetry','','[]','五色戎旌百萬鞍，徒誇龍虎統兵官。',64,'全唐诗/poet.song.229000.json','["五色戎旌百萬鞍，徒誇龍虎統兵官。", "囂喧閃電蕃營亂，陣算回風虜帳寒。", "兵法用過黄石遠，血盟瀝盡赤心乾。", "太平弟子憂成病，安得征君舊業寬。"]'),
('1e7b51f1-d924-4c47-9de7-cf38502e4498','次徐相公韻十首 岳飛','釋行海','宋','宋诗','song-poetry','','[]','戰守京河不下鞍，臣圖恢復不圖官。',64,'全唐诗/poet.song.229000.json','["戰守京河不下鞍，臣圖恢復不圖官。", "十年南渡客頭白，萬里北征戎膽寒。", "叛檜班師金詔急，留飛赤子泪嘷乾。", "可憐身死莫須有，從此王基未得寬。"]'),
('0f45d558-ae14-40d9-9628-ee8e1e2b7c26','次徐相公韻十首 李顯忠','釋行海','宋','宋诗','song-poetry','','[]','五丈高原躍戰鞍，同州太守舊藩官。',64,'全唐诗/poet.song.229000.json','["五丈高原躍戰鞍，同州太守舊藩官。", "路挑野鬭皈南急，旗獵風鳴带北寒。", "采石盤中兵膽湧，橘紅袍上箭痕乾。", "雞豚放却西元帥，只要當時國步寬。"]'),
('39b40d07-728f-41a0-9eb1-99daadd27591','次徐相公韻十首 魏勝','釋行海','宋','宋诗','song-poetry','','[]','第一山東逐虜鞍，平淮命作守淮官。',64,'全唐诗/poet.song.229000.json','["第一山東逐虜鞍，平淮命作守淮官。", "英雄內比黄金貴，死鬭牙穿毒箭寒。", "雨灑紅刀胡血滴，風披斑甲虎皮乾。", "功高孤竹今如此，舊恨茫茫滄海寬。"]'),
('3d2f3be1-553d-4154-b876-a1d6df87a801','言詩','釋行海','宋','宋诗','song-poetry','','[]','句織天機字字難，冥搜長在寂寥間。',64,'全唐诗/poet.song.229000.json','["句織天機字字難，冥搜長在寂寥間。", "每驚白雪陽春變，未放光風霽月閑。", "子美到今誰是史，仲尼亡後不曾刪。", "衰吾欲話平生志，安得重逢飯顆山。"]'),
('b2ff05ec-60fa-4846-b5f0-246bf9fa887d','偶作','釋行海','宋','宋诗','song-poetry','','[]','乾坤獨往欲逢誰，只有文王識釣絲。',64,'全唐诗/poet.song.229000.json','["乾坤獨往欲逢誰，只有文王識釣絲。", "豪傑盡生龍鬭日，太平須見鳳來時。", "風前莫聽涼州曲，月下長歌白苧辭。", "自笑不如南海燕，年年秋社是歸期。"]'),
('5c19f264-1d99-4b1b-84cc-a057272620dc','寓懷','釋行海','宋','宋诗','song-poetry','','[]','此去茫茫幾度秋，南來猶在古杭州。',64,'全唐诗/poet.song.229000.json','["此去茫茫幾度秋，南來猶在古杭州。", "樓臺雨打歸魂冷，沙漠風吹殺氣浮。", "龍管鳳簫遺舊曲，吳花越草換新愁。", "相逢喜話中興事，今日胡家白骨丘。"]'),
('3cf48327-f0c0-46f0-9411-d0ba5aba4de4','閑吟','釋行海','宋','宋诗','song-poetry','','[]','不識朱門識五湖，客中清苦十年餘。',64,'全唐诗/poet.song.229000.json','["不識朱門識五湖，客中清苦十年餘。", "世無苟取心何愧，句自冥搜貌任癯。", "笋蕨春來肥雨露，林泉日用狎樵漁。", "雲蹤鶴性長如此，未必青天管得吾。"]'),
('e72db286-3b6a-425b-ad02-75248ea5a790','度南澗','蔡襄','宋','宋诗','song-poetry','','["\u63cf\u5199\u6c34", "\u5199\u666f", "\u6292\u60c5", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u7edd\u53e5", "\u5199\u6c34"]','隠隠飛橋隔野煙，石磯西畔問漁船。',32,'全唐诗/poet.song.23000.json','["隠隠飛橋隔野煙，石磯西畔問漁船。", "桃花盡日隨流水，洞在清溪何處邊。"]'),
('40346ca6-8995-40f5-96ae-2236258582bc','入天竺山留客','蔡襄','宋','宋诗','song-poetry','','["\u7559\u5ba2", "\u6625\u5929", "\u5199\u666f"]','山光物態弄春暉，莫爲輕陰便擬歸。',32,'全唐诗/poet.song.23000.json','["山光物態弄春暉，莫爲輕陰便擬歸。", "縱使晴明無雨過，入雲深處亦霑衣。"]'),
('317f5192-adce-4c33-b427-b5bfef26d258','十日西湖晚歸','蔡襄','宋','宋诗','song-poetry','','["\u897f\u6e56"]','清晨出郭又晴曛，已見空枝嫩葉新。',64,'全唐诗/poet.song.23000.json','["清晨出郭又晴曛，已見空枝嫩葉新。", "爭得山頭能閣日，且容湖上不歸春。", "人隨百戲波翻海，酒到三橋月滿身。", "只有牡丹纔半拆，未知何處可娛賓。"]'),
('a3e05863-44d5-4432-b35d-32e7f4439434','十二日晚','蔡襄','宋','宋诗','song-poetry','','[]','俗尋軒檻倒清尊，江上烟雲向晚昏。',32,'全唐诗/poet.song.23000.json','["俗尋軒檻倒清尊，江上烟雲向晚昏。", "須倩東風吹散雨，明朝却待入花園。"]'),
('c8dc59a9-d047-43cc-8e72-1d86ff464d05','十三日吉祥探花','蔡襄','宋','宋诗','song-poetry','','[]','花未全開月未圓，看花候月思依然。',32,'全唐诗/poet.song.23000.json','["花未全開月未圓，看花候月思依然。", "明知花月無情物，若使多情更可憐。"]'),
('377e0373-501a-4d94-bbf2-9605bf007157','十三日出趙園觀花','蔡襄','宋','宋诗','song-poetry','','[]','水際開花千萬窠，初鶑時逐麗人歌。',32,'全唐诗/poet.song.23000.json','["水際開花千萬窠，初鶑時逐麗人歌。", "欲知太守行春樂，只向東城得最多。"]'),
('52013497-aad2-4d3d-b8fb-3879a11d1dcf','十五日遊龍華浄明兩院值雨','蔡襄','宋','宋诗','song-poetry','','[]','垂楊修竹半藏山，一徑紆回暮雨間。',64,'全唐诗/poet.song.23000.json','["垂楊修竹半藏山，一徑紆回暮雨間。", "綠滿野田看渺渺，白飛巖溜自潺潺。", "空村鮐背行歌去，古寺頭陀乞食還。", "却羨幽人在深僻，斷無來客扣禪關。"]'),
('e9b4e31d-eb5f-4cdb-a9f6-819ef41aceb1','十六日會飲駱園','蔡襄','宋','宋诗','song-poetry','','[]','名園何事却居鄽，永晝游蜂乳燕喧。',32,'全唐诗/poet.song.23000.json','["名園何事却居鄽，永晝游蜂乳燕喧。", "不計陰晴與風雨，卷簾花蘤在尊前。"]'),
('19c20aa6-b40f-4275-9037-54e05c390a23','十八日陪提刑郎中吉祥院看牡丹','蔡襄','宋','宋诗','song-poetry','','[]','節候初臨穀雨期，滿天風日助芳菲。',64,'全唐诗/poet.song.23000.json','["節候初臨穀雨期，滿天風日助芳菲。", "生來已占妙香國，開處全烘直指衣。", "攬照儘從烏帽重，放歌須遣羽觴飛。", "前騶不用傳呼寵，待與遊人一路歸。"]'),
('c0b8cbb7-dfe3-41fb-bf47-66dc1c1e8688','又往鄭園','蔡襄','宋','宋诗','song-poetry','','[]','小小園亭細細風，千枝淺白間深紅。',32,'全唐诗/poet.song.23000.json','["小小園亭細細風，千枝淺白間深紅。", "誰知狹徑無人到，留得青春向此中。"]'),
('47c6482b-85d0-4506-be45-7c514e56ff23','十九日奉慈親再往吉祥院看花','蔡襄','宋','宋诗','song-poetry','','[]','天意應偏與，春工已盡歸。',72,'全唐诗/poet.song.23000.json','["天意應偏與，春工已盡歸。", "來如從月下，去似逐雲飛。", "艷絕聲名遠，清多香氣微。", "輕陰資潤澤，斜照動光輝。", "劇飲千鍾醉，相鮮五綵衣。", "曾非重芳物，庶以奉慈闈。"]'),
('db4430c8-f2a3-4cb5-a015-d892aba46490','二十二日山堂小飲和元郎中牡丹向謝之什','蔡襄','宋','宋诗','song-poetry','','[]','幾家園館見千枝，白髮雖多意不衰。',64,'全唐诗/poet.song.23000.json','["幾家園館見千枝，白髮雖多意不衰。", "香澤最深風靜處，醉紅須在月明時。", "已知佳節無餘日，更向殘芳卷一巵。", "擬放春歸還自語，來年老信莫先期。"]'),
('b558649e-fe6d-40cd-87dc-b1156a2a7918','寄錢塘春遊詩呈南陽郭待制','蔡襄','宋','宋诗','song-poetry','','["\u897f\u6e56"]','一春遊攬足詩歌，寄與南陽語思多。',32,'全唐诗/poet.song.23000.json','["一春遊攬足詩歌，寄與南陽語思多。", "若憶錢塘曾到處，西湖仍是舊烟波。"]'),
('d5594dbe-b67d-418e-beee-ac37f7db8699','答孫推官','蔡襄','宋','宋诗','song-poetry','','[]','不是窮輪始問途，肯將全璧混泥污。',64,'全唐诗/poet.song.23000.json','["不是窮輪始問途，肯將全璧混泥污。", "尚平婚嫁何時畢，陶令田園先自蕪。", "羈旅且甘家四壁，牢愁須借酒千壚。", "唯應抒素推文富，落筆詞章氣象麄。"]'),
('946ee21b-e018-4d16-b3f0-b997f9c6b8c8','和孫推官憶徑山遊','蔡襄','宋','宋诗','song-poetry','','[]','三十年前浙右行，徑山纔稱愛山情。',64,'全唐诗/poet.song.23000.json','["三十年前浙右行，徑山纔稱愛山情。", "油幢悚悚絲杉翠，環珮涓涓石澗鳴。", "極峻只疑天上黨，遥臨初覺地東傾。", "分符不得重遊賞，碣石巖邊記姓名。"]'),
('42a5478f-3ca5-4bdb-a6cc-8bc7c9a77aa8','奉答孫推官南屏舊遊','蔡襄','宋','宋诗','song-poetry','','[]','已憐叢翠在湖邊，最勝濃嵐返照前。',64,'全唐诗/poet.song.23000.json','["已憐叢翠在湖邊，最勝濃嵐返照前。", "未省天工能刻飾，祇應山骨自清堅。", "巖端下溜添春澗，穴底來風送野煙。", "欲仗何人安屐齒，更尋幽徑一攀緣。"]'),
('4d291155-4642-4bdd-8e58-281277bc7bc0','和登安濟亭','蔡襄','宋','宋诗','song-poetry','','[]','亭上風吹藤帽簷，爲憐清勝得安恬。',64,'全唐诗/poet.song.23000.json','["亭上風吹藤帽簷，爲憐清勝得安恬。", "驚濤觸岸層瀾碎，落日銜山半景尖。", "遥認犀奔知鹿角，忽逢龍挂見胡髯。", "城南一去通滄海，無限春寒向晚添。"]'),
('94eff0ce-c4b5-4d51-a53e-3b69aa9e0ab3','和運使王學士舟次德清見寄','蔡襄','宋','宋诗','song-poetry','','[]','洛陽平昔誇文會，君已勝冠我壯夫。',64,'全唐诗/poet.song.23000.json','["洛陽平昔誇文會，君已勝冠我壯夫。", "談道最先稱賈誼，憂時曾見哭唐衢。", "敢將膠漆論同志，幸得湖山可共娛。", "須向餘春迴馬足，柳堤相逐踏青蕪。"]'),
('a78a7fce-020e-4b8f-904f-e41b34ad1e08','和運使學士芍藥篇','蔡襄','宋','宋诗','song-poetry','','[]','密葉陰沈夏景新，朱欄紅藥自爲春。',64,'全唐诗/poet.song.23000.json','["密葉陰沈夏景新，朱欄紅藥自爲春。", "香於蘭芷偏饒艷，畫入縑綃未逼真。", "已恨芳華難駐景，可堪愁卧動經旬。", "三年想愛須留戀，不爲江頭酒味醇。"]'),
('8dfdfac5-5b37-4655-a29f-591bbbe8f095','遊煙霞洞','蔡襄','宋','宋诗','song-poetry','','[]','新晴特地入煙霞，道並南山轉更賒。',64,'全唐诗/poet.song.23000.json','["新晴特地入煙霞，道並南山轉更賒。", "幽磬過鄰溪口寺，衆鷄鳴午野人家。", "洞深隨溜先如雨，石古籠藤亂放花。", "潘岳小園猶作賦，輕軒選勝樂無涯。"]'),
('e3b1cb38-45e6-4ef0-9d73-f4d8a2d9bde2','寄來安孫推官','蔡襄','宋','宋诗','song-poetry','','[]','我愛孫公子，安貧無所營。',48,'全唐诗/poet.song.23000.json','["我愛孫公子，安貧無所營。", "相逢雖邂逅，一見即平生。", "黑電揮詩筆，黄河瀉酒觥。", "輕舟何處在，別思若摇旌。"]'),
('b8e8057f-7de4-4e85-8c9c-de39c8714074','段家堤西望晚山','蔡襄','宋','宋诗','song-poetry','','[]','月下西山千萬重，日光山氣鬰葱籠。',32,'全唐诗/poet.song.23000.json','["月下西山千萬重，日光山氣鬰葱籠。", "鮫綃數幅須移得，惆悵如今無畫工。"]'),
('b5475744-1abf-4a11-9d48-5602d38efbf6','孫武篇','蔡襄','宋','宋诗','song-poetry','','[]','入官無所解，因笑得君憐。',24,'全唐诗/poet.song.23000.json','["入官無所解，因笑得君憐。", "豈知孫武子，自欲逞威權。"]'),
('a5a8f2cb-513c-4d5c-adb5-ffa3b89f1a07','西施篇','蔡襄','宋','宋诗','song-poetry','','[]','越國無雙艷，吳宮未始知。',24,'全唐诗/poet.song.23000.json','["越國無雙艷，吳宮未始知。", "誰言勾踐黠，不自愛西施。"]'),
('de6cdc29-3ddf-472f-b7fc-3db466ee33c8','唐彥猷挽詞  其一','蔡襄','宋','宋诗','song-poetry','','[]','骾亮馳名久，孤高進路難。',48,'全唐诗/poet.song.23000.json','["骾亮馳名久，孤高進路難。", "富文平日業，勸學晚年官。", "隧外春江靜，林邊曉露漙。", "唯應墳上土，猶解是芝蘭。"]'),
('7026e59f-a65e-41c8-85d6-ea820b36bfe0','唐彥猷挽詞  其二','蔡襄','宋','宋诗','song-poetry','','[]','舊德推當代，新悲入故鄉。',48,'全唐诗/poet.song.23000.json','["舊德推當代，新悲入故鄉。", "直當冠獬豸，清可濯滄浪。", "美研精煤色，文甌晝茗香。", "生平無復見，流涕送幽堂。"]'),
('12adc027-4eee-4e89-a2ae-3ba57866ee77','六月八日山堂試茶','蔡襄','宋','宋诗','song-poetry','','[]','湖上畫船風送客，江邊紅燭夜還家。',32,'全唐诗/poet.song.23000.json','["湖上畫船風送客，江邊紅燭夜還家。", "今朝寂寞山堂裏，獨對炎暉看雪花。"]'),
('1fbb27a2-4a4f-4212-927b-7774a37ed416','和錢端明遊南屏山','蔡襄','宋','宋诗','song-poetry','','[]','新秋初變一天清，急雨仍添萬木聲。',64,'全唐诗/poet.song.23000.json','["新秋初變一天清，急雨仍添萬木聲。", "山勢不根空外起，湖光無際槩來平。", "錦衣應有徘徊戀，金地聊開燕樂情。", "衰暮典城何所用，願公雲路羽翰生。"]'),
('d0748a30-ff71-418f-ae3c-001afd7f9010','送錢端明還京','蔡襄','宋','宋诗','song-poetry','','[]','禁墀初別紫霄端，故國生光里俗懽。',128,'全唐诗/poet.song.23000.json','["禁墀初別紫霄端，故國生光里俗懽。", "二世家聲聯將相，百年廟貌儼衣冠。", "躬臨州戟迎門下，人喜曾孫夾道觀。", "石照老苔封舊迹，錦溪喬木涕清瀾。", "東趨越嶺興懷遠，夕聽胥濤入夢間。", "江上馳心思魏闕，日邊歸路指長安。", "香深離渚花重疊，涼滿行舟酒半闌。", "應念非才持虎契，平時相繼入金鑾。"]'),
('733a20ed-7253-41fe-bc49-cb112bcc7f3b','清暑堂會同年','蔡襄','宋','宋诗','song-poetry','','[]','當年綠髮上天衢，三紀于今雪滿鬢。',64,'全唐诗/poet.song.23000.json','["當年綠髮上天衢，三紀于今雪滿鬢。", "榮路風波多契闊，畫堂歌吹蹔懽娛。", "杯中明月時摇動，草際飛螢乍有無。", "莫問更籌須劇醉，四翁同籍亦難俱。"]'),
('eec26c52-55c9-40a3-a40a-e2fa4b385f2b','清暑堂中秋夜飲','蔡襄','宋','宋诗','song-poetry','','[]','江國初凉夕漏均，青天無翳地無塵。',64,'全唐诗/poet.song.23000.json','["江國初凉夕漏均，青天無翳地無塵。", "蓮花翦綵燈光燦，蕉葉傾金酒味新。", "時節暗遷應不再，懽娛難得莫辭頻。", "明年今夜中庭月，依舊寒光別照人。"]'),
('a3521f0b-7b5f-49c8-a83d-2182acd8b7a0','宋君輔許當世陳彥謙蘇宣甫自遠還鄉上元同飲','蔡襄','宋','宋诗','song-poetry','','[]','故國逢君慰喜偏，清宵行醼重留連。',64,'全唐诗/poet.song.23000.json','["故國逢君慰喜偏，清宵行醼重留連。", "山樓上火人初合，天漢無雲月自圓。", "樂色時聞花院裏，春風都在酒旗邊。", "莫辭徹曉須沈醉，後會還應不計年。"]'),
('0f93aba3-d8b3-46e3-8bbe-073b03d7cd6f','李閣使新種洛花  其一','蔡襄','宋','宋诗','song-poetry','','[]','堂下朱闌小魏紅，一枝濃艷占春風。',32,'全唐诗/poet.song.23000.json','["堂下朱闌小魏紅，一枝濃艷占春風。", "新聞洛下傳佳種，未必開時勝舊叢。"]'),
('101e48f5-3c36-4780-93e6-7529273f00da','李閣使新種洛花  其二','蔡襄','宋','宋诗','song-poetry','','[]','園館春遊只帝京，可憐哀悴海邊城。',32,'全唐诗/poet.song.23000.json','["園館春遊只帝京，可憐哀悴海邊城。", "縱然得酒心猶在，若也逢花眼亦生。"]'),
('4da96535-927a-4a24-89cd-7ea88f6fabf1','客有至自京師言諸公春間多會于元伯園池因念昔遊輒形篇詠','蔡襄','宋','宋诗','song-poetry','','[]','綠渠春水走潺湲，畫閣嵩巒映碧鮮。',64,'全唐诗/poet.song.23000.json','["綠渠春水走潺湲，畫閣嵩巒映碧鮮。", "酒令已行金盞側，樂聲初急翠裙圓。", "清遊勝事傳京下，多麗新詞到海邊。", "曾是罇前沈醉客，天涯回望重依然。"]'),
('988c222c-2d49-4391-9958-295d69138aee','秋日','蔡襄','宋','宋诗','song-poetry','','[]','城頭蔓草受新霜，天外孤鴻叫夕陽。',32,'全唐诗/poet.song.23000.json','["城頭蔓草受新霜，天外孤鴻叫夕陽。", "送客情懷楓樹老，著人襟袖菊花香。"]'),
('1e632920-2600-4928-9e24-cbbd9497fb1f','秋日登郡樓二首  其一','蔡襄','宋','宋诗','song-poetry','','[]','秋水已復漕，秋風初怒號。',24,'全唐诗/poet.song.23000.json','["秋水已復漕，秋風初怒號。", "天容霜後凈，山勢北來高。"]'),
('e5fe86d7-62cd-4136-8876-a7145e9d5141','秋日登郡樓二首  其二','蔡襄','宋','宋诗','song-poetry','','[]','落葉隨飛鳥，疎砧答暮蟬。',24,'全唐诗/poet.song.23000.json','["落葉隨飛鳥，疎砧答暮蟬。", "悠悠戍樓角，悽切萬家傳。"]'),
('6567067e-dad4-49ea-8722-cbedffbe7f08','七月二十四日射弓','蔡襄','宋','宋诗','song-poetry','','[]','破的心仍在，爭豪力不堪。',48,'全唐诗/poet.song.23000.json','["破的心仍在，爭豪力不堪。", "開弓初覺顫，盈貫未離貧。", "衰病先期老，中年豈分甘。", "唯應罇酒在，萬事一醺酣。"]'),
('3e328999-a789-4c62-b397-d3c2cbdfd2fb','七月二十四日食荔枝','蔡襄','宋','宋诗','song-poetry','','[]','絳衣仙子過中元，別葉空枝去不還。',32,'全唐诗/poet.song.23000.json','["絳衣仙子過中元，別葉空枝去不還。", "應是天人知憶念，再生朱實慰衰顔。"]'),
('ccad4f2b-04b9-4cd9-a368-0434c287b305','中秋夕猶坐望月','蔡襄','宋','宋诗','song-poetry','','[]','萬里凄凝魄，幽深在處通。',72,'全唐诗/poet.song.23000.json','["萬里凄凝魄，幽深在處通。", "清流河漢盡，寒入水雲空。", "踰久方全白，彌高適正中。", "開書還自卷，把酒復誰同。", "泫葉溥宵露，吹衣變暑風。", "更看庭樹影，漸過粉牆東。"]'),
('77a33b57-df60-4628-9444-5e5909612ee3','九日許當世以詩見率登高','蔡襄','宋','宋诗','song-poetry','','[]','霜雲明凈海山隈，一歲登臨始此回。',64,'全唐诗/poet.song.23000.json','["霜雲明凈海山隈，一歲登臨始此回。", "堂上壽觴淋浪滿，欄邊佳菊似疑開。", "故鄉情味人人好，今日榮恩節節來。", "正是秋風洗煩暑，力將衰颯上高臺。"]'),
('9349e529-3518-4c28-8802-a0b8a5dd4cd9','杭州璘上人以花栽數種見寄','蔡襄','宋','宋诗','song-poetry','','[]','名品參差十數窠，商船千里任風波。',64,'全唐诗/poet.song.23000.json','["名品參差十數窠，商船千里任風波。", "土花分破根株小，春色隨來意氣多。", "欲種更看移樹法，將開須與傍欄歌。", "中年漸不勝杯酌，紅翠他時奈爾何。"]'),
('c67b6df3-4d2b-4597-8cec-3c2ffcf865be','冬溫','蔡襄','宋','宋诗','song-poetry','','[]','海曲封疆僻，冬溫氣序差。',48,'全唐诗/poet.song.23000.json','["海曲封疆僻，冬溫氣序差。", "蟲蛇誰閉戶，草木自開花。", "霧重朝迷日，風號夕卷沙。", "可憐天地雪，偏解舞京華。"]'),
('87a10097-9913-44f7-b765-202fe9d2b73e','庚子上元即事','蔡襄','宋','宋诗','song-poetry','','[]','老去年華只自驚，又逢佳節向山城。',64,'全唐诗/poet.song.23000.json','["老去年華只自驚，又逢佳節向山城。", "春臨半夜寒猶重，月到中天色更清。", "上客風流連宿醉，遊人歌調得新聲。", "遥思鳳闕行時令，紅繖朱欄萬燭明。"]'),
('1946b66b-d717-430b-9a5a-20b50b0fffbb','醉後','蔡襄','宋','宋诗','song-poetry','','[]','醉後歸來月滿衣，重重花影帽簷欹。',32,'全唐诗/poet.song.23000.json','["醉後歸來月滿衣，重重花影帽簷欹。", "行人路畔猶相笑，未似山翁倒接䍦。"]'),
('8fb81ae3-4529-4220-a269-b48332d9dbc9','朱樓','蔡襄','宋','宋诗','song-poetry','','[]','朱樓燈燭一聲歌，臘後天街月色和。',32,'全唐诗/poet.song.23000.json','["朱樓燈燭一聲歌，臘後天街月色和。", "平昔黄公酒壚下，誰知跬步邈山河。"]'),
('dad883fa-edfc-47ec-8d84-fa2887afd56e','一百五日開千葉間金','蔡襄','宋','宋诗','song-poetry','','[]','西園花蘤過中春，微雨初晴不受塵。',32,'全唐诗/poet.song.23000.json','["西園花蘤過中春，微雨初晴不受塵。", "莫怪芳叢開發早，欲將紅艷送行人。"]'),
('36390784-23d8-48b3-b69c-058f3bf9cc69','庭松安靜堂','蔡襄','宋','宋诗','song-poetry','','[]','偏愛堂東砌下松，三年瀟灑伴衰翁。',64,'全唐诗/poet.song.23000.json','["偏愛堂東砌下松，三年瀟灑伴衰翁。", "寒聲動蕩潮初上，疎影孤圓月正中。", "清徹紗帷延晝夢，綠涵金盞带春風。", "自緣多病饒歸思，便覺山林野意通。"]'),
('fb4c7d9b-3528-4feb-ac00-32d8ab5024c5','四月池上','蔡襄','宋','宋诗','song-poetry','','[]','風下平池水暈開，池邊露坐水風來。',64,'全唐诗/poet.song.23000.json','["風下平池水暈開，池邊露坐水風來。", "草香冉冉生吟席，雲影飛飛度酒杯。", "荷葉偶成雙翠蓋，荔枝纔似小青梅。", "人間物靜兩相得，月色蒼凉始肯迴。"]'),
('657372c5-cf1e-4d07-801d-0beb34df540c','乞雨題西方院','蔡襄','宋','宋诗','song-poetry','','[]','年年乞雨問山神，羞見耕耘隴上人。',32,'全唐诗/poet.song.23000.json','["年年乞雨問山神，羞見耕耘隴上人。", "太守自知才德薄，彼蒼何事罪斯民。"]'),
('ccb3c780-8759-43a6-992e-01ba190460c5','北園登高即事呈諸同僚','蔡襄','宋','宋诗','song-poetry','','[]','江雲寒薄不成霜，九月登高菊未黄。',64,'全唐诗/poet.song.23000.json','["江雲寒薄不成霜，九月登高菊未黄。", "飛鏑有聲弓已力，小槽分溜酒初嘗。", "秋容行見丹楓老，客意難勝紫陌長。", "曾是禁園風物好，故鄉時節可能忘。"]'),
('dae906ac-a7aa-4c50-a156-14b4ef8decd8','送馴鹿與東禪長老','蔡襄','宋','宋诗','song-poetry','','[]','二年馴擾傍山家，欲領東還道路賒。',32,'全唐诗/poet.song.23000.json','["二年馴擾傍山家，欲領東還道路賒。", "送汝給孤園裏去，此生長伴大牛車。"]'),
('df5f63f1-f895-420d-95e5-74e6ef859d04','畫生李維寫予像今已十年對鑑觀之因題其側','蔡襄','宋','宋诗','song-poetry','','[]','清眸綠髮十年前，朴野風神不易傳。',32,'全唐诗/poet.song.23000.json','["清眸綠髮十年前，朴野風神不易傳。", "今日青銅莫相照，白髭垂頷面雙顴。"]'),
('4f9ba715-c69b-410a-a0d4-09f0218d975a','將赴京留題山莊西壁','蔡襄','宋','宋诗','song-poetry','','[]','禁林京尹荷恩光，三上螭頭乞郡章。',32,'全唐诗/poet.song.23000.json','["禁林京尹荷恩光，三上螭頭乞郡章。", "貧薄奉親須仰祿，此心安敢繫軒裳。"]'),
('56c6e1c1-4e46-4327-9351-f6196ab9c78a','燕司封同年以詩見迎','蔡襄','宋','宋诗','song-poetry','','[]','寄問閩州明使君，十年蹉跌路岐分。',64,'全唐诗/poet.song.23000.json','["寄問閩州明使君，十年蹉跌路岐分。", "帳前約束承嚴節，按下文書接署雲。", "北去最先趨畫戟，老來應免醉紅裙。", "新篇一攬思遊舊，搔首孤吟日又曛。"]'),
('bb0d5123-b48b-45f6-83e9-d8d9fad278e7','題共樂亭','蔡襄','宋','宋诗','song-poetry','','[]','層巒高與赤霄通，節歲歡娛衆庶同。',64,'全唐诗/poet.song.23000.json','["層巒高與赤霄通，節歲歡娛衆庶同。", "庭有美音非獨樂，會當炎暑自多風。", "山川勝勢欄桿下，井徑追遊月色中。", "私幸編民居客右，使君樽酒未應空。"]'),
('8702b361-47c9-48fb-be3f-275cfa98d7fd','徐虞部以龍尾石硯邀予第品仍授來使持還書府','蔡襄','宋','宋诗','song-poetry','','[]','玉質純蒼理緻精，鋒芒都盡墨無聲。',32,'全唐诗/poet.song.23000.json','["玉質純蒼理緻精，鋒芒都盡墨無聲。", "相如間道還持去，肯要秦人十五城。"]'),
('72387fa7-a9dd-49fd-bfe8-8fd2763db7d4','過囊山寄宏師','蔡襄','宋','宋诗','song-poetry','','[]','三十年間登第初，青衫羸馬叩禪居。',32,'全唐诗/poet.song.23000.json','["三十年間登第初，青衫羸馬叩禪居。", "鬢毛白盡猶奔走，慚愧高人得自如。"]'),
('07dedc3b-14aa-45ae-879d-1aefded70c38','人日立春舟行寄福州燕二司封','蔡襄','宋','宋诗','song-poetry','','[]','清溪潮上送行船，回望高城隔曉烟。',64,'全唐诗/poet.song.23000.json','["清溪潮上送行船，回望高城隔曉烟。", "景色似看名畫展，醉魂猶憶壽杯傳。", "春盤食菜思三九，人日書幡誦百千。", "南國逢君唯道舊，後時何處笑今年。"]'),
('82b2f982-9fa8-41d9-b6a4-6c07ac384e25','又寄興化徐虞部','蔡襄','宋','宋诗','song-poetry','','[]','梅花狼籍拂輕舟，人日溪行動客愁。',64,'全唐诗/poet.song.23000.json','["梅花狼籍拂輕舟，人日溪行動客愁。", "上晝去程初北首，故山歸思滿東流。", "垂垂朝雨隨雙槳，草草春蔬送一甌。", "不獨懷鄉便多感，看人難似府君侯。"]'),
('3404e83f-f3ce-426a-8485-a8f90b13a3c6','上元至南劍州大雨寄泉州許通判','蔡襄','宋','宋诗','song-poetry','','[]','路遶溪回不計程，行郵今復宿延平。',64,'全唐诗/poet.song.23000.json','["路遶溪回不計程，行郵今復宿延平。", "陰雲藏月不知處，急雨落天無數聲。", "病起尚疑羣蟻鬭，夢飲初聽一雞鳴。", "泉山去歲同遊賞，惟有神君識此情。"]'),
('86a16610-cbd8-4878-9f8f-e7069b27f30b','大湖驛寄建州同年竇職方','蔡襄','宋','宋诗','song-poetry','','[]','別驛臨溪曲，清寒結曉陰。',48,'全唐诗/poet.song.23000.json','["別驛臨溪曲，清寒結曉陰。", "灘聲生亂石，雨意在閒林。", "登第年華久，相逢禮愛深。", "茶山春物近，那得共追尋。"]'),
('46b1a8c9-4fce-4931-89e2-e14a4c439ac0','嘉祐辛丑蒙召還京二月八日道過陸氏之門因觀小欄花卉','蔡襄','宋','宋诗','song-poetry','','[]','風色微和日晝明，小欄花卉新芽生。',32,'全唐诗/poet.song.23000.json','["風色微和日晝明，小欄花卉新芽生。", "行人不是愛春物，一見芳叢似有情。"]'),
('fe151fec-81af-4287-a93e-8ab941e87a71','題嚴先生祠堂','蔡襄','宋','宋诗','song-poetry','','[]','遵此巢由志，誰希公相權。',48,'全唐诗/poet.song.23000.json','["遵此巢由志，誰希公相權。", "人瞻祠樹古，天作釣壇圓。", "高節千秋外，遺蹤一水邊。", "孤風敦薄俗，豈是愛林泉。"]'),
('55d4ac15-5f8f-4716-bacc-ddc6a81c49eb','杭州過璘上人花圃','蔡襄','宋','宋诗','song-poetry','','[]','封培剪剝奪天工，欄下長年見萬紅。',32,'全唐诗/poet.song.23000.json','["封培剪剝奪天工，欄下長年見萬紅。", "投老暗知心力少，自開還落信春風。"]'),
('d4548b2b-6cfc-429d-a888-44b4f4ab1fc5','雪','蔡襄','宋','宋诗','song-poetry','','[]','六年守郡在天涯，冬暖無因見雪華。',32,'全唐诗/poet.song.23000.json','["六年守郡在天涯，冬暖無因見雪華。", "今日復看千里白，强憐寒色作詩誇。"]'),
('bd73f3ce-9f79-4752-8e21-03d1f30cb3ec','寄題華藏院清軒','蔡襄','宋','宋诗','song-poetry','','[]','湖邊無地有塵埃，況復虛明向此開。',64,'全唐诗/poet.song.23000.json','["湖邊無地有塵埃，況復虛明向此開。", "山色每隨朝氣變，水光長共夕陽來。", "船行天上遊人散，樹沒雪中宿鳥回。", "一到便應離火宅，不須花雨拂經臺。"]'),
('a5b42f5a-8b67-40a9-8d79-e92ac6e4e73c','提刑司封以鄰霄臺佳什垂示輒成拙篇以答厚貺','蔡襄','宋','宋诗','song-poetry','','[]','峭拔幾千仞，孤高無四憐。',120,'全唐诗/poet.song.23000.json','["峭拔幾千仞，孤高無四憐。", "低回傾北斗，突兀起東閩。", "締結青雲上，登臨滄海濱。", "溪山來面勢，歌吹徹穹旻。", "子夜先看日，陰崖後得春。", "三韓空瑣碎，萬落自埃塵。", "使者風流在，詩人格調新。", "驪珠忽投我，神筆動驚人。", "平昔持州契，于今識路津。", "去天知不遠，咫尺仰威神。"]'),
('03e7b123-f5f5-40ae-b40b-913f584e375b','過楊樂道宅西桃花盛開','蔡襄','宋','宋诗','song-poetry','','[]','城隈遶舍似山家，舍下新桃已放花。',64,'全唐诗/poet.song.23000.json','["城隈遶舍似山家，舍下新桃已放花。", "無限幽香風正好，不勝狂艷日初斜。", "自憐馬上空愁望，誰向樽前與醉誇。", "京國難逢春氣味，莫隨塵事度年華。"]'),
('513f7eb1-6c32-4608-83b4-dd31c1e6418f','和龐公謝子魚荔枝','蔡襄','宋','宋诗','song-poetry','','[]','霜鱗分不登枯肆，丹實全應勝木奴。',32,'全唐诗/poet.song.23000.json','["霜鱗分不登枯肆，丹實全應勝木奴。", "欲效野芹羞獻去，敢期佳什墜驪珠。"]'),
('5e298d8a-f5d0-4f57-9dd5-e7fd5bb55f7b','宋宣獻公夫人畢氏哀詞二首  其一','蔡襄','宋','宋诗','song-poetry','','[]','世閥推台路，嬪賢秉國鈞。',48,'全唐诗/poet.song.23000.json','["世閥推台路，嬪賢秉國鈞。", "生緣隨迹化，歸處覺空真。", "訓子清風在，傳家令德新。", "九原終一致，悲喜盡成塵。"]'),
('2c487b95-33c7-4511-9060-10a8caddc785','宋宣獻公夫人畢氏哀詞二首  其二','蔡襄','宋','宋诗','song-poetry','','[]','國賦雖千乘，身期未百年。',48,'全唐诗/poet.song.23000.json','["國賦雖千乘，身期未百年。", "箴圖遺舊机，簫吹向新阡。", "行哭追前日，超生定幾天。", "寂寥原上樹，薄晚起寒烟。"]'),
('a7496991-dd03-4efb-a185-f98c0a99df55','和張唐公約遊名園遇雪輒止','蔡襄','宋','宋诗','song-poetry','','[]','京塵官事日區區，擬出芳郊佩一壺。',64,'全唐诗/poet.song.23000.json','["京塵官事日區區，擬出芳郊佩一壺。", "樓外陰雲迎曉合，陌頭霏霰與風俱。", "翩翩珍騎曾來否，種種名花更在無。", "若得縱遊休秉燭，月中沈醉倩人扶。"]'),
('bf220c0e-5ed2-4864-834b-caff7c04e35d','和宋次道宴日不赴有懷','蔡襄','宋','宋诗','song-poetry','','[]','殿中佳氣带春容，天上雲謠落晚風。',32,'全唐诗/poet.song.23000.json','["殿中佳氣带春容，天上雲謠落晚風。", "獨向下陳霑醉斝，羨君清卧寄詩筒。"]'),
('9b590dad-0d7d-4bf3-9403-82604bfcd38a','春日','蔡襄','宋','宋诗','song-poetry','','[]','東風吹雨濕鞦韆，紅點棠梨爛欲然。',32,'全唐诗/poet.song.23000.json','["東風吹雨濕鞦韆，紅點棠梨爛欲然。", "擬買芳華贈年少，紫榆春淺未成錢。"]'),
('2507cd14-1f7f-430d-a655-f9b4950fa4d5','唐公以公累出知濠州','蔡襄','宋','宋诗','song-poetry','','[]','湛湛清渠風力微，濠梁行客布帆歸。',32,'全唐诗/poet.song.23000.json','["湛湛清渠風力微，濠梁行客布帆歸。", "到官應過莊生廟，試問鷦鵬兩是非。"]'),
('60b3c699-0043-4178-8a74-5966cee03c15','桃杏園  其一','蔡襄','宋','宋诗','song-poetry','','[]','上有繁葩下落英，紅波動蕩逐風行。',32,'全唐诗/poet.song.23000.json','["上有繁葩下落英，紅波動蕩逐風行。", "夕陽開處猶光艷，何況今宵值月明。"]'),
('64c7f002-af30-45b5-ae47-8b8cce8a6e93','桃杏園  其二','蔡襄','宋','宋诗','song-poetry','','[]','送客來仙館，清幽處處尋。',48,'全唐诗/poet.song.23000.json','["送客來仙館，清幽處處尋。", "春風行酒面，晝日到花心。", "獨厭歸期促，難忘野意深。", "歸鞍更回顧，檜柏自陰森。"]'),
('b9b4bb7c-996e-46ce-b6f5-4597035dbf7d','三月出城別張唐公會玉仙觀','蔡襄','宋','宋诗','song-poetry','','[]','隴麥青青溝柳新，春歸聚落少逢人。',32,'全唐诗/poet.song.23000.json','["隴麥青青溝柳新，春歸聚落少逢人。", "如何試與持鞭手，拂却向來身上塵。"]'),
('8162f1b7-c409-4681-bee8-f7ca17b6cb59','玉仙池','蔡襄','宋','宋诗','song-poetry','','[]','洞府花飛不減春，輕雲成片玉成塵。',32,'全唐诗/poet.song.23000.json','["洞府花飛不減春，輕雲成片玉成塵。", "香軿縹緲知何在，無限池頭再拜人。"]'),
('fffc8420-0df5-4186-8a46-d25cd9b73ed3','凝祥池上晚歸','蔡襄','宋','宋诗','song-poetry','','[]','綠徑陰陰落景微，楊花零亂上人衣。',32,'全唐诗/poet.song.23000.json','["綠徑陰陰落景微，楊花零亂上人衣。", "長烟似愛滄波面，風色雖豪不肯飛。"]'),
('3d07791d-8fbc-41c7-98aa-2c0258bd8f50','和楊龍圖蘆鴈屏','蔡襄','宋','宋诗','song-poetry','','[]','何事高堂秋思生，野蘆寒鴈畫工精。',64,'全唐诗/poet.song.23000.json','["何事高堂秋思生，野蘆寒鴈畫工精。", "風前挺立孤根老，雲外相從去意輕。", "不似丹青能借色，若逢霜月定聞聲。", "研桑心術都無取，回望江鄉計未成。"]'),
('6b00a5bd-a431-4264-b442-dd0acd96167c','和楊龍圖獐猿屏','蔡襄','宋','宋诗','song-poetry','','[]','畫莫難於工寫生，獐猿移得上幽屏。',64,'全唐诗/poet.song.23000.json','["畫莫難於工寫生，獐猿移得上幽屏。", "相逢平野初驚顧，共向薰風適性靈。", "引子晝遊新草綠，嘯羣時望故山青。", "可憐官省沈迷處，每到中軒頓覺醒。"]'),
('c6be48e0-0d5d-4fad-ac17-03b0cf437987','和吳省副北軒湖山之什','蔡襄','宋','宋诗','song-poetry','','[]','誰於素壁寫江流，雲樹疎疎映荻洲。',64,'全唐诗/poet.song.23000.json','["誰於素壁寫江流，雲樹疎疎映荻洲。", "盡日清虛全却暑，一川摇落似輕秋。", "暫逢明畫心猶在，終向扁舟老去休。", "只有遊鯈能自適，莫懷香餌重遲留。"]'),
('3a292c0c-d169-42f1-96e6-46711f1b4c10','送仲庶待制知澤州','蔡襄','宋','宋诗','song-poetry','','[]','十年臺省獻嘉謀，新總兵符鎮上遊。',64,'全唐诗/poet.song.23000.json','["十年臺省獻嘉謀，新總兵符鎮上遊。", "琴有薰絃多舜俗，地連沙尾舊湘州。", "江邊行色船千丈，塞外威聲馬萬頭。", "宣室夜談思賈誼，未應鄉國久遲留。"]'),
('0237f11f-0189-4fed-8ee4-fb16eabfa387','送子真給事出守常山','蔡襄','宋','宋诗','song-poetry','','[]','安得長材護北州，蹔煩儒將擁輕裘。',64,'全唐诗/poet.song.23000.json','["安得長材護北州，蹔煩儒將擁輕裘。", "聲名不啻一敵國，功業何須萬里侯。", "設館高牙延永晝，獵場飛騎入清秋。", "天樞嚴近恩榮重，歸夢應思帝所遊。"]'),
('42a560f4-9975-49e0-b846-708631f28c4a','送程刑部出守洪州','蔡襄','宋','宋诗','song-poetry','','[]','何事名郎出計臺，鍾陵都會久須才。',64,'全唐诗/poet.song.23000.json','["何事名郎出計臺，鍾陵都會久須才。", "江山不是人間有，旗鼓初從日下來。", "列郡五符歸總制，故鄉三組少徘徊。", "勿嗟南國多懷感，寶氣還應徹斗魁。"]'),
('7feb3787-293f-4dfc-a544-8296b1757fe4','遊靈峰院龍龕山','蔡襄','宋','宋诗','song-poetry','','[]','天柱支南極，蓬山壓巨鰲。',48,'全唐诗/poet.song.23000.json','["天柱支南極，蓬山壓巨鰲。", "雲崩石道險，潮落海門高。", "客館聞鼉鼓，秋風憶蟹螯。", "凭欄望鄉樹，千里楚江臯。"]'),
('637b21cb-38c1-44b7-b2a1-0c9d947f2cf3','遊九鯉湖','蔡襄','宋','宋诗','song-poetry','','[]','何嶺巍峨欲插天，回頭人與白雲連。',32,'全唐诗/poet.song.23000.json','["何嶺巍峨欲插天，回頭人與白雲連。", "桃花不點尋常路，從此依稀度九仙。"]'),
('6be7b21d-a5bf-4099-98a5-7b534910eecd','錢唐題壁','蔡襄','宋','宋诗','song-poetry','','[]','綽約新嬌生眼底，侵尋舊事上眉尖。',32,'全唐诗/poet.song.23000.json','["綽約新嬌生眼底，侵尋舊事上眉尖。", "問君別後愁多少，得似春潮夜夜添。"]'),
('50466d86-276b-4b46-91aa-8b1c6d94d94a','洛陽詩帖  其一','蔡襄','宋','宋诗','song-poetry','','[]','洛陽風景實堪誇，幾處樓臺處處花。',32,'全唐诗/poet.song.23000.json','["洛陽風景實堪誇，幾處樓臺處處花。", "盡是齊王修種得，如今惆悵似無家。"]'),
('80f134b4-b31d-41a3-9c4a-9eafccdb035d','洛陽詩帖  其二','蔡襄','宋','宋诗','song-poetry','','[]','洛陽風景實堪珍，到此經今三紀春。',32,'全唐诗/poet.song.23000.json','["洛陽風景實堪珍，到此經今三紀春。", "無限歡娛榮樂事，一時迴施少年人。"]'),
('5b9f577d-0edd-414b-b996-37ee9946f019','稼村詩帖  其一','蔡襄','宋','宋诗','song-poetry','','[]','隠居何事可謀生，堯舜難周畎畝情。',32,'全唐诗/poet.song.23000.json','["隠居何事可謀生，堯舜難周畎畝情。", "若得一犂膏雨足，石田茅屋起歌聲。"]'),
('afe2c143-3d76-4510-8f63-57e2529b8466','稼村詩帖  其二','蔡襄','宋','宋诗','song-poetry','','[]','布穀聲中雨滿籬，催耕不獨野人知。',32,'全唐诗/poet.song.23000.json','["布穀聲中雨滿籬，催耕不獨野人知。", "荷鋤莫道春耘早，正是披蓑叱犢時。"]'),
('756b9b45-1413-4000-a3df-a0ab8fd2ab56','詩一首','蔡襄','宋','宋诗','song-poetry','','["\u5e90\u5c71", "\u957f\u6c5f"]','萬疊青山拔空起，一道長江清澈底。',128,'全唐诗/poet.song.23000.json','["萬疊青山拔空起，一道長江清澈底。", "隔岸蒼茫不見人，人家多在晴雲裏。", "匡廬五老蓬萊山，滄洲白鷺烟波間。", "隨風客棹任來去，落日樵歌自往還。", "絕澗孤亭倚烟樹，彷彿天台石橋路。", "欲訪羣仙跨鶴游，寧乘五馬專城去。", "雨過棠陰滿路蹊，春深草色連庭砌。", "窮簷蔀屋有惸獨，待爾重臨慰客饑。"]'),
('9a574fd2-1a34-4ecd-a94b-d80d066cbcbd','詩一首','蔡襄','宋','宋诗','song-poetry','','[]','紫綬金章被寵榮，筆牀茶竈伴參苓。',64,'全唐诗/poet.song.23000.json','["紫綬金章被寵榮，筆牀茶竈伴參苓。", "只知江海能行道，未識朝廷舊有名。", "笑我病去相榮□，圭刀小試即春生。", "瘡痍未復君知否，國手于今數老成。"]'),
('1d178c72-a46e-4407-8709-60b88544fc90','句  其一','蔡襄','宋','宋诗','song-poetry','','[]','陳亞有心終是惡。',8,'全唐诗/poet.song.23000.json','["陳亞有心終是惡。"]'),
('03cf47ff-fa87-4451-8634-d3f4dc4a3022','句  其二','蔡襄','宋','宋诗','song-poetry','','[]','園林窮勝事，鐘鼓樂清時。',12,'全唐诗/poet.song.23000.json','["園林窮勝事，鐘鼓樂清時。"]'),
('869adabb-0abf-4742-b69e-af2f3403ed18','句  其三','蔡襄','宋','宋诗','song-poetry','','[]','綉衣中使動輜車，黄紙封林遍阡陌。',16,'全唐诗/poet.song.23000.json','["綉衣中使動輜車，黄紙封林遍阡陌。"]'),
('1962c5ee-9527-4149-bb34-53e9fd532ec7','句  其四','蔡襄','宋','宋诗','song-poetry','','[]','時平生戰地，農惰入春田。',12,'全唐诗/poet.song.23000.json','["時平生戰地，農惰入春田。"]'),
