('2c4e3c79-c706-4496-a315-8291c2244ed7','遊栖霞宮','張奕','宋','宋诗','song-poetry','','[]','尊師乃高道，有意出塵寰。',48,'全唐诗/poet.song.23000.json','["尊師乃高道，有意出塵寰。", "佩劍文垂斗，橫琴意在山。", "靈龜調浩氣，醇酒發朱顔。", "最得時賢許，詩牌滿棟間。"]'),
('0dec0df3-2216-4ccd-b4b0-b7b8a99bb88d','偈二首  其一','釋洪英','宋','宋诗','song-poetry','','[]','阿家嘗醋三赤喙，新婦洗面摸著鼻。',32,'全唐诗/poet.song.23000.json','["阿家嘗醋三赤喙，新婦洗面摸著鼻。", "道吾答話得腰裩，玄沙開書是白紙。"]'),
('12525b03-0e97-448c-bcf9-3859373b836f','偈二首  其二','釋洪英','宋','宋诗','song-poetry','','[]','萬鍛鑪中鐵蒺藜，直須高價莫饒伊。',32,'全唐诗/poet.song.23000.json','["萬鍛鑪中鐵蒺藜，直須高價莫饒伊。", "橫來豎去呵呵笑，一任旁人鼓是非。"]'),
('e9b684ca-5066-4c3f-a6b2-e2bb8538cf5a','偈三首  其一','釋洪英','宋','宋诗','song-poetry','','[]','青山重疊疊，綠水響潺潺。',24,'全唐诗/poet.song.23000.json','["青山重疊疊，綠水響潺潺。", "未到懸崖處，抬頭子細看。"]'),
('32f451e3-83cf-4a6b-bc0a-b04a856dd098','偈三首  其二','釋洪英','宋','宋诗','song-poetry','','[]','寶峰高士罕曾到，巖前雪壓枯松倒。',32,'全唐诗/poet.song.23000.json','["寶峰高士罕曾到，巖前雪壓枯松倒。", "嶺前嶺後野猿啼，一條古路清風掃。"]'),
('6d155333-a788-4145-ba5b-cc54c550f18e','偈三首  其三','釋洪英','宋','宋诗','song-poetry','','[]','石門巇嶮鐵關牢，舉目重重萬仞高。',32,'全唐诗/poet.song.23000.json','["石門巇嶮鐵關牢，舉目重重萬仞高。", "無角鐵牛衝得破，毗盧海內作波濤。"]'),
('4c28b629-9801-4c7f-8c45-93bf128718cc','句  其一','釋洪英','宋','宋诗','song-poetry','','[]','喜得狼煙息，弓弰壁上懸。',12,'全唐诗/poet.song.23000.json','["喜得狼煙息，弓弰壁上懸。"]'),
('c20b2145-43ac-4073-9542-9ad890e95f89','句  其二','釋洪英','宋','宋诗','song-poetry','','[]','不到烏江畔，知君未肯休。',12,'全唐诗/poet.song.23000.json','["不到烏江畔，知君未肯休。"]'),
('2bce84cc-b055-4c9b-821e-7ffcb35b1b24','句  其三','釋洪英','宋','宋诗','song-poetry','','[]','天際雪埋千尺石，洞門凍折數株松。',16,'全唐诗/poet.song.23000.json','["天際雪埋千尺石，洞門凍折數株松。"]'),
('be8c95a1-74d6-4630-9505-2bdf4fb0941d','句  其四','釋洪英','宋','宋诗','song-poetry','','[]','一句不遑無著問，迄今猶作野盤僧。',16,'全唐诗/poet.song.23000.json','["一句不遑無著問，迄今猶作野盤僧。"]'),
('57829524-cbd3-4ba3-b416-cf7569ad9b91','興安乳洞','陸詵','宋','宋诗','song-poetry','','[]','深沈三洞啟真都，萬乳千葩狀絕殊。',32,'全唐诗/poet.song.23000.json','["深沈三洞啟真都，萬乳千葩狀絕殊。", "馳驛方朝金闕去，滌塵來飲碧琳腴。"]'),
('bd2f063a-ed89-44e0-89c5-a671d3166478','老蘇先生挽詞','王拱辰','宋','宋诗','song-poetry','','[]','氣得岷峨秀，才推買馬優。',48,'全唐诗/poet.song.23000.json','["氣得岷峨秀，才推買馬優。", "未承宣室間，空有茂陵求。", "玩易窮三聖，論書正九疇。", "欲知歆向學，二子繼弓裘。"]'),
('c0a44356-09df-4ad2-8942-276a515dc0e3','和堯夫先生安樂窩中好打乖吟','王拱辰','宋','宋诗','song-poetry','','[]','安樂窩中名隠君，腹藏經笥富多聞。',64,'全唐诗/poet.song.23000.json','["安樂窩中名隠君，腹藏經笥富多聞。", "一廛水竹爲生計，三徑琴觴混世紛。", "婉畫舊嘗辭幕府，少微今已應星文。", "了心便是棲真地，何必煙霞卧白雲。"]'),
('de458da0-4fb9-4b48-aac9-f4e07eecc546','耆英會詩','王拱辰','宋','宋诗','song-poetry','','[]','西都山水天下奇，神嵩景室環清伊。',384,'全唐诗/poet.song.23000.json','["西都山水天下奇，神嵩景室環清伊。", "甫申間氣秀不絕，生賢會聖昌明時。", "衣冠占數盛文雅，台符卿月光離離。", "魏京雄奧壓幽朔，遊宮御府嚴天威。", "膏田千里翳桑柘，犀甲萬旅馴熊羆。", "公當緩带名三鎮，懸赤繼軫承保釐。", "追推契遇最深舊，加復雍孟交旌麾。", "仁皇一莊龍虎榜，桂堂先後攀高枝。", "宦遊出處五十載，鸞臺驥路俱騰夷。", "三公極位固遼隔，五年以長猶肩隨。", "公今復主鳳門鑰，僕亦再撫侗臺圻。", "二京相望阻河廣，三徑不克陪遊嬉。", "忽聞幹步踵門至，投我十二耆英詩。", "整冠肅貌諷章句，若坐寶肆羅珠璣。", "爲言白傅有高躅，九尹結社真可師。", "欲令千載著風迹，亟就僧館圖神姿。", "詞宗端殿序篇目，滂灑大筆何淋灕。", "眷言履道靡充詘，菟裘近邑將營歸。", "敢云繪素得精筆，願列霜壁如唐規。", "退居舊相國元老，十年還政瀍之涯。", "康寧富貴備五福，靈寶盛氣如虹霓。", "昔年大對繼晁董，登科賜第同一期。", "紫垣步武既通接，金沙里閈還鄰比。", "探禪論道劇訓對，摩軋太古窮天機。"]'),
('01556a7d-a35b-4f45-a76b-0cd257e393ca','送會稽何從事','王拱辰','宋','宋诗','song-poetry','','[]','行行岐路出塵閒，從事猶勝執戟間。',64,'全唐诗/poet.song.23000.json','["行行岐路出塵閒，從事猶勝執戟間。", "景象徧經江左地，封疆全得浙中山。", "侯藩蹔列談賓位，綸閣看隨墨客班。", "到郡莫爲經歲計，詔書非久急徵還。"]'),
('870edff9-9a24-4995-81b5-3dc8b87312c8','史院席上奉和吳相公原韻','王拱辰','宋','宋诗','song-poetry','','[]','累聖千春統，編年四紀餘。',48,'全唐诗/poet.song.23000.json','["累聖千春統，編年四紀餘。", "官歸柱史筆，經約魯麟書。", "班馬才長矣，仁英道偉歟。", "恩招宴東觀，釃酒荷盈車。"]'),
('316f0b84-33bd-46f5-a772-aa01b6097736','詩一首','王拱辰','宋','宋诗','song-poetry','','[]','聖神深意念遐方，前後皆馳諭蜀郎。',32,'全唐诗/poet.song.23000.json','["聖神深意念遐方，前後皆馳諭蜀郎。", "從此郵亭爲盛事，乘軺相繼有三王。"]'),
('b85e49d4-ee3b-414e-8355-0608b95d4693','句','王拱辰','宋','宋诗','song-poetry','','[]','棋墅風煙清早夏，禊亭蘭茝暗殘春。',16,'全唐诗/poet.song.23000.json','["棋墅風煙清早夏，禊亭蘭茝暗殘春。"]'),
('053b93ef-b061-4dbf-bd6e-c92c132225db','答寄堯夫先生','韓絳','宋','宋诗','song-poetry','','[]','君子志於道，出處非一端。',240,'全唐诗/poet.song.23000.json','["君子志於道，出處非一端。", "伊尹負鼎俎，顔淵樂瓢簞。", "斯自理適當，匪緣情所安。", "超然達者致，邈矣誰可攀。", "嗟嗟狂若狷，狥已缺其完。", "軒冕死不釋，山林趨不還。", "我愛邵夫子，醇氣充見顔。", "羣經究彼邃，古史閱而刪。", "不爲詭異行，已蹈時俗難。", "逃名去其奧，築室伊洛間。", "抱業舍仕進，竭心奉親歡。", "修竹當環堵，寒流日潺潺。", "問誰從之遊，結駟款其關。", "茲予久欣慕，欲往良獨艱。", "幸君適河內，至此解征鞍。", "僚友恃交舊，屈致及門闌。", "前迎倒我屣，布席羅雕盤。", "高談未一二，長揖忽歸騫。", "不意饋雙鯉，剖腴出琅玕。", "何以報嘉惠，永懷金與蘭。"]'),
('6000802c-6d1a-4f87-829b-2999fb14fad3','跋文正公手書伯夷頌墨蹟','韓絳','宋','宋诗','song-poetry','','[]','高賢忠義古今同，手笑遺編法甚工。',32,'全唐诗/poet.song.23000.json','["高賢忠義古今同，手笑遺編法甚工。", "寶軸傳家當不朽，追懷餘思凜生風。"]'),
('1b709429-868a-4e2c-860f-3dc5ac4d64e3','和范蜀公題蜀中花圖','韓絳','宋','宋诗','song-poetry','','[]','徑尺千餘朵，矜誇古復今。',48,'全唐诗/poet.song.23000.json','["徑尺千餘朵，矜誇古復今。", "錦城春物異，粉面瑞雲深。", "賞愛難忘酒，珍奇不費金。", "應知色空理，夢幻即懽心。"]'),
('550e0271-379a-4877-ad26-f5d67624a1d7','送周知監  其一','韓絳','宋','宋诗','song-poetry','','[]','唐家諭巴蜀，通道至邛僰。',24,'全唐诗/poet.song.23000.json','["唐家諭巴蜀，通道至邛僰。", "列郡徼西南，夷居半巖壁。"]'),
('08659cd5-1094-4fb6-9d76-692684e7c79a','送周知監  其二','韓絳','宋','宋诗','song-poetry','','[]','土瘠事刀耕，家無終歲蓄。',24,'全唐诗/poet.song.23000.json','["土瘠事刀耕，家無終歲蓄。", "所資鹽井利，持易他州粟。"]'),
('8c94adec-928e-4624-8937-b50754f4b7e6','復修府學故事','韓絳','宋','宋诗','song-poetry','','[]','文翁石室已千秋，世有興衰化自流。',64,'全唐诗/poet.song.23000.json','["文翁石室已千秋，世有興衰化自流。", "賢嶲相望承學粹，朝廷繇此得人優。", "太平典禮當傳習，盛際文章正講求。", "師友琢磨期不勌，岷峨秀氣與雲浮。"]'),
('ad46cd03-9efc-45e5-9cb2-36f9d4805a34','題琴臺','韓絳','宋','宋诗','song-poetry','','[]','車騎擁客安在哉，綺琴何事有遺臺。',64,'全唐诗/poet.song.23000.json','["車騎擁客安在哉，綺琴何事有遺臺。", "當時卒困臨邛辱，異日寧知諭蜀才。", "園令官閒多病後，茂陵書奏侈心開。", "文章火燄留千古，陳迹猶存尚可哀。"]'),
('9292a127-ffc5-4e15-98e1-05dc83daefe4','游鴻慶寺','韓絳','宋','宋诗','song-poetry','','[]','久旱雨初足，樂游春正深。',96,'全唐诗/poet.song.23000.json','["久旱雨初足，樂游春正深。", "喧闐觀士女，清曠入山林。", "佛界雲成寶，僧園地布金。", "方塘探子石，高閣會賓簪。", "沙水通溪白，松筠逐徑陰。", "紛華從滿目，幽寂自虛心。", "印組端爲累，巖扃得暫尋。", "晚風吹綠野，歸騎已駸駸。"]'),
('6423675e-4984-4bcd-8f34-043664df48cf','教授秘書見示學館唱酬詩稿輒書累句以謝','韓絳','宋','宋诗','song-poetry','','[]','兌悅無如會友朋，况多吟咏思飛騰。',64,'全唐诗/poet.song.23000.json','["兌悅無如會友朋，况多吟咏思飛騰。", "塤箎雅正無它間，孔翠光華不自勝。", "好事僮兒歌已遠，爭傳牋紙價還增。", "羣居豈弟吾儒行，鄒魯風流喜重興。"]'),
('2a923a90-d5e8-49c6-9f2f-eef9c28e4fc3','奉酬宋君見詒之作','韓絳','宋','宋诗','song-poetry','','[]','非才衰晚玷恩榮，假節西來鎮錦城。',64,'全唐诗/poet.song.23000.json','["非才衰晚玷恩榮，假節西來鎮錦城。", "遠慕文翁興舊學，竊希何武見諸生。", "銀袍冉冉朝先聖，玉樹森森識衆英。", "傳道喜將師席正，尚稱官閥禮爲輕。"]'),
('97f24ad7-bf97-4e03-b452-49a129db3d8c','謁仙翁祠書山蓀亭','韓絳','宋','宋诗','song-poetry','','[]','玉井不可到，玉泉聊可尋。',48,'全唐诗/poet.song.23000.json','["玉井不可到，玉泉聊可尋。", "馬行穿亂石，人語入深林。", "川迥沙明色，溪喧谷響音。", "我來方六月，雲榭一披襟。"]'),
('b6d9d931-f5a6-4d4b-9e11-fd61108b264d','聯句','韓絳','宋','宋诗','song-poetry','','[]','古木含清吹，池上增晚凉。',98,'全唐诗/poet.song.23000.json','["古木含清吹，池上增晚凉。", "余懷本達曠，聯此傲羲皇。", "孤鷗可與狎，幽岸足以觴。", "幸有彭澤酒，堯臣便同永嘉堂。", "潘生起爲壽，王子齊陳章。", "林端見新月，草際聞寒螿。", "照水螢影亂，拂筵蓼花香。", "徘徊戀嘉境，坐使歸興忘。"]'),
('0405029c-c1e0-48ed-91a6-1ce62e7e8644','來燕堂聯句','韓絳','宋','宋诗','song-poetry','','[]','賢侯謝郡歸，從游樂吾黨。',240,'全唐诗/poet.song.23000.json','["賢侯謝郡歸，從游樂吾黨。", "林泉富餘地，卜築疏陳莽。", "是時春正中，來燕音下上。", "若賀大厦成，喜留衆賓賞。", "得名因談笑，揮墨粲題榜。", "所夸賢豪盛，豈止池榭廣。", "人心樂且閒，鳥意頡而頏。", "吟罇敞花軒，醉枕酣風幌。", "輕雲薄藻棟，初日麗珠網。", "紅袂生暗香，清絃泛餘響。", "林深隠飛蓋，岸曲遲去槳。", "波光欄檻明，竹氣衣巾爽。", "虛容凉樾入，影與文漣蕩。", "晨飈轉綠蕙，夕雨滋膏壤。", "嘉辰喜盍朋，命駕期屢往。", "觴詠陶淑真，世俗豈吾倣。", "得以爲勝游，蕭然散煩想。", "公子固好士，世德復可象。", "今此大基構，不圖專奉養。", "美哉風流存，來葉足師仰。"]'),
('465c5e6c-32dc-4cca-a1a4-c6dbb9282686','送周知監','韓繹','宋','宋诗','song-poetry','','[]','蜀土風景信不好，君之所治兼蠻夷。',32,'全唐诗/poet.song.23000.json','["蜀土風景信不好，君之所治兼蠻夷。", "山高地仄江水惡，刀耕火種黎民疲。"]'),
('a9bfbd28-42aa-42e2-85fb-7b8d05b1e747','句  其一','周式','宋','宋诗','song-poetry','','[]','花前嫫母醜，雪裏屈原醒。',12,'全唐诗/poet.song.23000.json','["花前嫫母醜，雪裏屈原醒。"]'),
('730cc435-ab0b-4730-94f8-35933e74dc5b','句  其二','周式','宋','宋诗','song-poetry','','[]','珠簾繡戶遲遲日，柳絮梨花寂寂春。',16,'全唐诗/poet.song.23000.json','["珠簾繡戶遲遲日，柳絮梨花寂寂春。"]'),
('48777270-69f8-40e5-a4a1-705bbf33ebec','吏隠堂','劉舜臣','宋','宋诗','song-poetry','','[]','事因是僻方知少，官得公餘始信閑。',32,'全唐诗/poet.song.23000.json','["事因是僻方知少，官得公餘始信閑。", "且喜詩同文史樂，不須身與利名關。"]'),
('7dd79320-8bd1-44c7-adcf-d6cd402e71a0','東掖四絕句 入天台','石象之','宋','宋诗','song-poetry','','[]','溪岑縈繞紅塵外，殿閣欹危翠靄間。',32,'全唐诗/poet.song.23000.json','["溪岑縈繞紅塵外，殿閣欹危翠靄間。", "我見老僧無一事，老僧更羨白雲閒。"]'),
('a10914d7-3b60-4191-b476-fe5899e2a70a','不見如師','石象之','宋','宋诗','song-poetry','','[]','洗除塵垢訪名藍，不得相逢益自慚。',32,'全唐诗/poet.song.23000.json','["洗除塵垢訪名藍，不得相逢益自慚。", "松桂陰森香火冷，亂雲空鎖白蓮庵。"]'),
('8eb06299-0081-4c3d-b000-ff297e536c91','不見如師 隔塵亭','石象之','宋','宋诗','song-poetry','','[]','山椒亭榭適徘徊，病膜煩襟斗頓開。',32,'全唐诗/poet.song.23000.json','["山椒亭榭適徘徊，病膜煩襟斗頓開。", "若有塵埃何處隔，此中自是少塵埃。"]'),
('a31ad4c0-b63f-43c9-8f71-06312a0bbcca','不見如師 白蓮庵','石象之','宋','宋诗','song-poetry','','[]','結社當年號白蓮，師心應欲繼前賢。',32,'全唐诗/poet.song.23000.json','["結社當年號白蓮，師心應欲繼前賢。", "有時中夜初回定，清磬一聲秋月圓。"]'),
('70524345-9e96-4515-9712-2f59986ec2a1','詠愁','石象之','宋','宋诗','song-poetry','','["\u548f\u7269\u8bd7", "\u548f\u7269", "\u5fe7\u6101"]','來何容易去何遲，半在心頭半在眉。',64,'全唐诗/poet.song.23000.json','["來何容易去何遲，半在心頭半在眉。", "門掩落花春去後，窗窺殘月酒醒時。", "柔如萬頃連天草，亂比千尋匝地絲。", "除却五侯歌舞地，人間何處不相隨。"]'),
('31dea00d-1d15-4536-b789-1e8be0579afe','遊南明山','石聲之','宋','宋诗','song-poetry','','[]','祇應尋勝到林泉，四抱危峯萬朶蓮。',64,'全唐诗/poet.song.23000.json','["祇應尋勝到林泉，四抱危峯萬朶蓮。", "僧過不知山隠寺，客來方見洞開天。", "浮圖照水光相映，古木依崖影倒懸。", "風露了非人世界，濯纓秋後玉壺仙。"]'),
('7139b787-0a89-42d0-9a9d-3480c6ee98f2','閑居','張諮','宋','宋诗','song-poetry','','[]','兀兀浮生水上萍，百年那得眼長青。',64,'全唐诗/poet.song.23000.json','["兀兀浮生水上萍，百年那得眼長青。", "醉中但愛杯呼月，鏡裏驚看髩易星。", "瓶膽插花時過蝶，石拳栽草也留螢。", "瑶音到手知音少，默誦南華一卷經。"]'),
('a3986a2c-dcd4-4688-bcc5-7737feca82f7','邵武','上官凝','宋','宋诗','song-poetry','','[]','江上臘梅村，人家半掩門。',24,'全唐诗/poet.song.23000.json','["江上臘梅村，人家半掩門。", "夕陽連野色，落葉破煙痕。"]'),
('4ded441b-0769-4b3f-b0c6-34db12703b51','題共樂堂','汪泌','宋','宋诗','song-poetry','','[]','臨海城東湖，氣象清且奇。',240,'全唐诗/poet.song.23000.json','["臨海城東湖，氣象清且奇。", "無風綠色淨，十頃澄琉璃。", "中有共樂堂，今其名者誰。", "人有答我問，太定下車時。", "訪民所疾苦，民曰水最危。", "其水或暴至，城壞民流屍。", "公謀得上策，疊石完城基。", "外遺數百家，室屋鱗參差。", "水至無所障，適與漂溺期。", "又欲隄其東，苦乏土石資。", "開湖足取用，隄勢橫虹蜺。", "湖光占空闊，物從鑑中窺。", "紫翠前後山，環列如屏帷。", "構堂就虛曠，與俗同遊嬉。", "太守宴堂上，遊人歌水湄。", "歌云從公來，除患補瘡痍。", "況有此觀壯，不樂何以爲。", "有如登春臺，人心舉熙熙。", "從事能文者，作辭書之碑。", "庶其不朽功，上徹堯軒墀。"]'),
('b522e148-aee7-445a-be31-f443c7e9d51d','碁山院','董淵','宋','宋诗','song-poetry','','[]','風際有雲多世態，海中無底是人心。',32,'全唐诗/poet.song.23000.json','["風際有雲多世態，海中無底是人心。", "可堪更問碁山話，一局閑爭古到今。"]'),
('043688d0-a971-4dd4-9392-31df25233153','瑞峯院','董淵','宋','宋诗','song-poetry','','[]','石屏樹幄白雲端，溪路生苔樹石間。',32,'全唐诗/poet.song.23000.json','["石屏樹幄白雲端，溪路生苔樹石間。", "閑訪禪家問塵世，總言塵事不相干。"]'),
('f7ee2a35-bfef-4826-8f0b-bfcec23f25ae','靈峯院龍龕山和蔡君謨','董淵','宋','宋诗','song-poetry','','[]','礧硌彌沙界，谽谺古洞天。',72,'全唐诗/poet.song.23000.json','["礧硌彌沙界，谽谺古洞天。", "門鄰金布地，橋枕玉鳴泉。", "庭鶴歸迷主，龕龍去失年。", "掃雲嫌俗駕，題壁詫詩仙。", "勝景無今古，居人有後先。", "不知遊者馭，誰見海爲田。"]'),
('8fbeca45-6ae2-421a-99da-3bc58cad37a9','太常山','董淵','宋','宋诗','song-poetry','','[]','勢凌籌谷接蒼蒼，十二交龍繡作裳。',64,'全唐诗/poet.song.23000.json','["勢凌籌谷接蒼蒼，十二交龍繡作裳。", "虎豹關中千樹色，鳳凰池上萬花香。", "白雲路隔青雲暮，金澗泉通玉澗凉。", "聖代君臣忻際會，安知磐石鎮無疆。"]'),
('fe728ac0-6184-40ac-b0e1-7e0b1e0cb37e','麻源靈豐祠','蔡若水','宋','宋诗','song-poetry','','[]','偶因乞雨到麻源，碧澗縈紆亂石間。',32,'全唐诗/poet.song.23000.json','["偶因乞雨到麻源，碧澗縈紆亂石間。", "未省謝公吟賞後，更誰乘月弄潺湲。"]'),
('ca5d11e7-3ba7-416a-afeb-8935af0df35e','題廳壁','陸起','宋','宋诗','song-poetry','','[]','驅雞政府本來無，剛被人呼邑大夫。',32,'全唐诗/poet.song.23000.json','["驅雞政府本來無，剛被人呼邑大夫。", "及至五更侵早起，算來却是被雞驅。"]'),
('d116621d-94af-494e-934b-2f7740b4c3b0','題公署','陳嶠','宋','宋诗','song-poetry','','[]','當默任言言地垢，當言任默默爲塵。',32,'全唐诗/poet.song.23000.json','["當默任言言地垢，當言任默默爲塵。", "當默當言俱無任，塵埃何由得到身。"]'),
('d8d8f7cd-a498-4089-abcf-de6f475ffdd1','句  其一','陳嶠','宋','宋诗','song-poetry','','[]','彭祖尚聞年八百，陳郎猶是小孩兒。',16,'全唐诗/poet.song.23000.json','["彭祖尚聞年八百，陳郎猶是小孩兒。"]'),
('7daea9f4-76e9-4b70-9f8a-461a3f017120','句  其二','陳嶠','宋','宋诗','song-poetry','','[]','小橋風月年年事，爭奈潘安老去何。',16,'全唐诗/poet.song.23000.json','["小橋風月年年事，爭奈潘安老去何。"]'),
('4433b7e8-7b61-47cd-9e2d-19af68593564','吳江太湖笠澤虹橋','俞可','宋','宋诗','song-poetry','','["\u592a\u6e56"]','范蠡避名湖上去，季鷹乘興日邊歸。',32,'全唐诗/poet.song.23000.json','["范蠡避名湖上去，季鷹乘興日邊歸。", "洲連笠澤春遊遠，路入松陵夜釣稀。"]'),
('8d2874ea-9bd1-406a-aa0c-8330640306d0','句','俞可','宋','宋诗','song-poetry','','[]','拂座好風來橘社，隔汀長笛過松江。',16,'全唐诗/poet.song.23000.json','["拂座好風來橘社，隔汀長笛過松江。"]'),
('1e9f0575-b6ed-449d-a678-4221384b64fd','廳壁山水','雙漸','宋','宋诗','song-poetry','','[]','澗邊芳草連天碧，山下錦濤無丈尺。',64,'全唐诗/poet.song.23000.json','["澗邊芳草連天碧，山下錦濤無丈尺。", "鶑稀燕少蝶未知，蜜意尋芳與誰惜。", "我有春情方似織，萬緒千頭難求覓。", "富貴榮華不早來，眼前光景空拋擲。"]'),
('404b1dff-6b17-4fc0-98d7-6b476ae04b0a','豫章逢故人歌','雙漸','宋','宋诗','song-poetry','','[]','樂天嘗日潯陽渚，舟中曾遇商人婦。',320,'全唐诗/poet.song.23000.json','["樂天嘗日潯陽渚，舟中曾遇商人婦。", "坐間因感琵琶聲，爲託微詞寫深訴。", "因重佳人難再得，故言何必曾相識。", "今日相逢相識人，青衫拭淚應無極。", "我因從官臨川去，豫章城下風帆駐。", "續有翩翩畫舸來，斜陽共繫垂楊樹。", "綠窗相近未多時，紅簾半動聞私語。", "認得舟中是故人，從人來自韶陽路。", "柔情脉脉不得通，餘時冉冉時聞度。", "借問舟中是誰氏，長自廬江佳麗地。", "蘇姓從來字小卿，桃葉桃根皆姊妹。", "十歲清歌已遏雲，十一朱顔妬桃李。", "十二能描新月眉，十三解綰烏雲髻。", "亂花溪上偶相逢，一託深心許爲壻。", "翠鬟曾翦繫平生，暗斷金釵爲盟誓。", "無何官難兩相忘，因茲流落來天際。", "揚州一夢今何處，風月心情向誰訴。", "筭來爭似不相逢，空感當時無限事。", "昔日風光曾作主，今日風光如驀路。", "腸斷江頭夜不眠，風帆明日東西去。"]'),
('c6b34e04-396f-485b-8035-c49d7d50823c','題三角亭','俞汝尚','宋','宋诗','song-poetry','','[]','奇哉山中人，搆此池上宇。',48,'全唐诗/poet.song.23000.json','["奇哉山中人，搆此池上宇。", "蕙徑斜映带，林煙盡吞吐。", "春無四面花，夜欠一簷雨。", "寄傲足有餘，何須循廣廡。"]'),
('552935a0-ca30-402e-9f8c-ea4bdc6897a7','過淮陰侯廟','俞汝尚','宋','宋诗','song-poetry','','[]','當時謀戰不謀安，將衆多多是禍端。',64,'全唐诗/poet.song.23000.json','["當時謀戰不謀安，將衆多多是禍端。", "萬壘在前攻掠易，四方無事保全難。", "曉堂鍾鼓修淮祀，古壁旌旗擁漢官。", "天下息肩兵革定，一瞻祀宇一長歡。"]'),
('c7036d51-7a96-48eb-81c2-0caa5b190d8e','夏日閑居','俞汝尚','宋','宋诗','song-poetry','','[]','無人到窮巷，長日守閑居。',48,'全唐诗/poet.song.23000.json','["無人到窮巷，長日守閑居。", "宿火惟烘藥，新晴還曬書。", "鄰翁伴村酒，稚子課園蔬。", "門外蒿萊地，泥深不用鋤。"]'),
('812cefb5-4efb-424f-a376-bcd5a48e24d5','久客','俞汝尚','宋','宋诗','song-poetry','','[]','久客西城裏，人家似舊鄰。',48,'全唐诗/poet.song.23000.json','["久客西城裏，人家似舊鄰。", "衆知趨事懶，僧厭打門頻。", "倦枕費窗竹，開書破硯塵。", "陰晴消白日，門巷忽青春。"]'),
('88be54da-3375-433f-86ae-a5d1a959946f','東山招復古','俞汝尚','宋','宋诗','song-poetry','','[]','聞道廣文客，東來欲載書。',48,'全唐诗/poet.song.23000.json','["聞道廣文客，東來欲載書。", "志勤甘淡薄，情舊免生疏。", "野飯多無萊，溪羹或有魚。", "小心新買得，且遂带經鋤。"]'),
('42b8f03b-095d-4709-b1c3-80bb519463d6','贈張伯玉倅古睦','俞汝尚','宋','宋诗','song-poetry','','[]','新定烟霞外，溪山清可依。',48,'全唐诗/poet.song.23000.json','["新定烟霞外，溪山清可依。", "夜風泉溜響，春雨藥苗肥。", "野鶴眠花圃，晴嵐溼案衣。", "預知公暇日，垂釣子陵磯。"]'),
('55349bf7-6e69-47e9-869e-3656cd61b216','題蒙泉','俞汝尚','宋','宋诗','song-poetry','','[]','幽人斸寒泉，井甃名日蒙。',216,'全唐诗/poet.song.23000.json','["幽人斸寒泉，井甃名日蒙。", "井貴德不改，蒙以養爲功。", "非徒玩清冷，潤液幽芳叢。", "說築傅巖下，伊耕莘野中。", "靜守一夫事，勤政王道隆。", "孔孟不得志，日月經高穹。", "休哉聖賢心，養私而用公。", "宇宙間生民，草木與昆蟲。", "仁漸而穠郁，義慘而龐洪。", "泓泓此中泉，與物資天功。", "勿謂短綆淺，海底淵源通。", "勿謂一勺輕，洗滌人心空。", "近林鬰青蒼，遠澗與沖融。", "往往中間雲，霶霈起天風。", "汲引即所利，孰遣榛莽豐。", "有道無得喪，孰患番險濛。", "君子修諸業，慮初而圖終。", "爲君賦此詩，勿厭吾道窮。"]'),
('4e1594ad-0fd8-4887-ad65-dc9405ff1d48','汝尚將歸吳興齊州記室蘇子由辱詩爲送因逐韻謝之','俞汝尚','宋','宋诗','song-poetry','','[]','釋屨從軍蚤濫官，已衰能復尚盤桓。',64,'全唐诗/poet.song.23000.json','["釋屨從軍蚤濫官，已衰能復尚盤桓。", "邇來齒髮羞相問，乞有衡茅覓自安。", "使我襟懷遺內熱，誦君詩句襲人寒。", "知誰便是知音者，且作巖溪雪景看。"]'),
('2e4234ec-64c0-4b96-8f63-6a04e3f78410','戒香院','俞汝尚','宋','宋诗','song-poetry','','[]','崎嶇窮谷翠屏圍，却訝遊人到此稀。',64,'全唐诗/poet.song.23000.json','["崎嶇窮谷翠屏圍，却訝遊人到此稀。", "修竹带雲當戶聳，暗泉鳴玉遶亭飛。", "春風欲老茶含旆，暑雨初收水带磯。", "擾擾紅塵何處好，令人回首重忘歸。"]'),
('91f384cf-a83e-4343-9bc9-5d0c3987369f','和范公希文懷慶朔堂','曹經','宋','宋诗','song-poetry','','[]','池館名公舊日栽，幾番零落又春開。',32,'全唐诗/poet.song.23000.json','["池館名公舊日栽，幾番零落又春開。", "誰人解識紅芳意，猶有多情五馬來。"]'),
('018bbb2d-6abb-44f8-95d7-1ddb8e5a2c04','贈蔡君謨赴漳南幕','葛密','宋','宋诗','song-poetry','','[]','藻思舊傳青管夢，哲科新試碧雞才。',32,'全唐诗/poet.song.23000.json','["藻思舊傳青管夢，哲科新試碧雞才。", "乍依仲寶蓮花幕，更下溫郎玉鏡臺。"]'),
('7fd6683b-9ac6-4767-85e7-7452b65a4eb6','四并堂','葛密','宋','宋诗','song-poetry','','[]','華圃控弦秋習射，寒窗留燭夜鈔書。',32,'全唐诗/poet.song.23000.json','["華圃控弦秋習射，寒窗留燭夜鈔書。", "良辰美景饒心事，觀日相并樂起予。"]'),
('7405fc6a-2ad5-40a8-8b53-7a39ea03c193','讀道藏  其一','葛密','宋','宋诗','song-poetry','','[]','仙莖屢隕三危露，真館常開四照花。',32,'全唐诗/poet.song.23000.json','["仙莖屢隕三危露，真館常開四照花。", "鵲渚曉煙飛玉洞，琅池秋水接星槎。"]'),
('1d72615b-00d6-46b3-a59f-f67e30ee5a69','讀道藏  其二','葛密','宋','宋诗','song-poetry','','[]','鍊成真氣發雙華，還向囊中秘玉霞。',32,'全唐诗/poet.song.23000.json','["鍊成真氣發雙華，還向囊中秘玉霞。", "咒水夜潭龍怖劍，弄雲秋嶺鶴看家。"]'),
('d08c0b7e-bba9-4d43-8d00-3617423f8e4c','喜子書思登第','葛密','宋','宋诗','song-poetry','','[]','傳家何用富金籝，教子何如只一經。',32,'全唐诗/poet.song.23000.json','["傳家何用富金籝，教子何如只一經。", "慶曆科名今已繼，更教來葉嗣前馨。"]'),
('aee6548f-7f48-49f1-8c79-88322f29b744','和李都官春日見寄','葛密','宋','宋诗','song-poetry','','[]','聞說年來絕世榮，更將高節傲時明。',64,'全唐诗/poet.song.23000.json','["聞說年來絕世榮，更將高節傲時明。", "詩腴偏得味中味，琴的靜彈聲外聲。", "宴榭日長花影駐，春池風細水紋生。", "相望空欲閒相見，彼此閑居懶送迎。"]'),
('0adaa4d8-fa0f-4ae7-b6e0-0d7d11113c44','近造浮屠之悟空者睹君謨省主給事留題詩板列楣棟間粲然可誦因摭方袍之意成拙句以寄','葛密','宋','宋诗','song-poetry','','[]','昔年詩板著蓮宮，筆力雄豪墨彩豐。',32,'全唐诗/poet.song.23000.json','["昔年詩板著蓮宮，筆力雄豪墨彩豐。", "不日三階平國政，山僧應待碧紗籠。"]'),
('33da8948-04d3-40e8-be4e-0f7b1b7a78f2','冬夜宿演教院','葛密','宋','宋诗','song-poetry','','[]','槭槭嚴風夕，煙含蕙炷清。',48,'全唐诗/poet.song.23000.json','["槭槭嚴風夕，煙含蕙炷清。", "燈和花裏艷，雨作雪時聲。", "旅夢回殘角，吟懷繞廢城。", "寂然群動息，吾亦世紛平。"]'),
('b424efc5-deff-41b0-a2c9-2c80c4bd02d0','壽凝院呈山主志師','葛密','宋','宋诗','song-poetry','','[]','一徑直巖隈，亭軒四面開。',48,'全唐诗/poet.song.23000.json','["一徑直巖隈，亭軒四面開。", "濤頭轉山急，雨脚滿江來。", "怪石生雲氣，修篁待鳳材。", "他年白蓮社，應許繼宗雷。"]'),
('937788db-317b-4d7d-8708-761a33ad7ea9','句  其一','葛密','宋','宋诗','song-poetry','','[]','色空了了空還執，體相如如相即非。',16,'全唐诗/poet.song.23000.json','["色空了了空還執，體相如如相即非。"]'),
('913a4f9e-f14a-4572-97ef-a503733432e2','句  其二','葛密','宋','宋诗','song-poetry','','[]','山禽啼曉四時別，林藪戰秋千里空。',16,'全唐诗/poet.song.23000.json','["山禽啼曉四時別，林藪戰秋千里空。"]'),
('e126857a-ba56-4951-a474-9ada26095734','句  其三','葛密','宋','宋诗','song-poetry','','[]','我悟戃來空世界，師知休去忘形骸。',16,'全唐诗/poet.song.23000.json','["我悟戃來空世界，師知休去忘形骸。"]'),
('41f3356f-fb29-422d-8502-48bfdb63bb92','送程給事知越州','潘及甫','宋','宋诗','song-poetry','','[]','積年欣慕逸羣才，今日皇都喜重陪。',64,'全唐诗/poet.song.23000.json','["積年欣慕逸羣才，今日皇都喜重陪。", "行著繡衣歸茂苑，醉攙仙履上蓬萊。", "青雲有路千峯見，碧海無波萬里開。", "我欲傍淮先卜築，隔江招隠望胥臺。"]'),
('e38e1f5f-7f9c-4a7f-ad29-077b1caba76d','送友','潘及甫','宋','宋诗','song-poetry','','[]','聚首渾無益，送君將奈何。',48,'全唐诗/poet.song.23000.json','["聚首渾無益，送君將奈何。", "已經貧病後，一任別離多。", "鬢髮新霜雪，衣裳舊薜蘿。", "不堪明月夜，揮手唱驪歌。"]'),
('0c346865-26fe-42d2-9535-d934838cc4a9','送程給事知越州二首  其一','張唐民','宋','宋诗','song-poetry','','[]','瑣闥修文極禁清，蓬萊宮闕擁旄行。',64,'全唐诗/poet.song.23000.json','["瑣闥修文極禁清，蓬萊宮闕擁旄行。", "舳艫所至笙歌鬧，里閈重來道路榮。", "舉世幾人居我地，全吳無限讀書生。", "受恩老吏攀轅切，滿肚埃塵詩不成。"]'),
('bc12fbfe-ca3f-4663-b257-09be9827edfb','送程給事知越州二首  其二','張唐民','宋','宋诗','song-poetry','','[]','夕郎賢撰固清崇，公若居之受未充。',64,'全唐诗/poet.song.23000.json','["夕郎賢撰固清崇，公若居之受未充。", "節似冰霜文似錦，才如風雨氣如虹。", "仙舟菡萏香來枕，鈴閣江山秀入空。", "薄俗莫輕量用捨，吾民時自有窮通。"]'),
('da5fab72-2790-46bf-b730-e404fd1a13fb','題捫參閣','張唐民','宋','宋诗','song-poetry','','[]','訟簡民淳羨小州，兩衙纔退似歸休。',32,'全唐诗/poet.song.23000.json','["訟簡民淳羨小州，兩衙纔退似歸休。", "一懷山果三勝酒，暮掩青峯即下樓。"]'),
('91b85cf1-d8b2-41a8-8fb7-b623a900698a','詩一首','張唐民','宋','宋诗','song-poetry','','[]','陰風碧裏鱗鱗瓦，落日紅中縷縷煙。',48,'全唐诗/poet.song.23000.json','["陰風碧裏鱗鱗瓦，落日紅中縷縷煙。", "無訟正如高隠地，隆冬方似早春天。", "州民富庶風光好，誰信常憂滿二年。"]'),
('57288205-59d2-447f-b267-00a1bf3a3246','湘江秋夕','鄭蒨','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','嶽麓長雲合，湘江暮靄收。',48,'全唐诗/poet.song.23000.json','["嶽麓長雲合，湘江暮靄收。", "鴻鳴沙渚夜，葉脫洞庭秋。", "霜竹千業密，風弦一曲愁。", "獨醒人不見，西岸水悠悠。"]'),
('65e478fb-4ad7-4ca3-92a9-ff9445cbd8de','睡覺','鄭蒨','宋','宋诗','song-poetry','','[]','玉爐香斷瑞煙微，小院陰岑夾幕垂。',64,'全唐诗/poet.song.23000.json','["玉爐香斷瑞煙微，小院陰岑夾幕垂。", "一枕清風人寂後，半窗明月酒醒時。", "漆園蝴蜨難成夢，巫峽行雲想有期。", "欲曙凄凉精氣爽，漏殘燈燼畫屏欹。"]'),
('0f16df05-162d-494d-bc43-3adcb00ab493','興慶池禊宴','趙寅','宋','宋诗','song-poetry','','[]','斗城初霽媚春暉，託乘尋芳鶴蓋飛。',64,'全唐诗/poet.song.23000.json','["斗城初霽媚春暉，託乘尋芳鶴蓋飛。", "修禊波深輕急槳，舞雩風暖薄更衣。", "香車寶馬嬉遊盛，別館離宮往事非。", "因憶鳳池新溜躍，黑轓看逐節函歸。"]'),
('0d6e6526-760d-4ef3-9797-bf03f80e2f7a','興慶池禊宴','史瑜','宋','宋诗','song-poetry','','[]','池館春光欲禁煙，芳辰修禊集羣賢。',64,'全唐诗/poet.song.23000.json','["池館春光欲禁煙，芳辰修禊集羣賢。", "茂林深處森冠劍，清籟鳴時當管弦。", "召伯甘棠分陝地，羊公風景峴山前。", "詩成莫訝天機俊，潛握人間造化權。"]'),
('93b60a03-6f72-4c7c-baa6-16532699bc91','頌蔡君謨  其一','福建士人','宋','宋诗','song-poetry','','[]','道邊松，大義渡至漳泉東。',60,'全唐诗/poet.song.23000.json','["道邊松，大義渡至漳泉東。", "問誰植之我蔡公，歲久廣陰如雲濃。", "甘棠蔽芾安可同，委蛇天矯騰蒼龍。", "行人六月不知暑，千古萬古長清風。"]'),
('3b0be0ad-1d01-4408-96a2-cee33a53f2c7','頌蔡君謨  其二','福建士人','宋','宋诗','song-poetry','','[]','洛陽橋，一望五里排琨瑶。',60,'全唐诗/poet.song.23000.json','["洛陽橋，一望五里排琨瑶。", "行人不憂滄海潮，衝衝往來乘仙飆。", "蔡公作成去還朝，玉虹依舊橫青霄。", "考之溱洧功何遼，千古萬古無傾摇。"]'),
('64bda502-2876-464d-a14c-7829c1a755e5','送義青偈','釋圓鑑','宋','宋诗','song-poetry','','[]','須彌立太虛，日月輔而轉。',48,'全唐诗/poet.song.23000.json','["須彌立太虛，日月輔而轉。", "羣峯漸倚他，白雲方改變。", "少林風起叢，曹溪洞簾卷。", "金鳳宿龍巢，宸苔豈車碾。"]'),
('07e52120-a083-4e1d-a17e-ae3032ce5d54','送天柱馮先生','李絢','宋','宋诗','song-poetry','','[]','閑馳風馭恣飄飄，因失仙班幾度朝。',64,'全唐诗/poet.song.23000.json','["閑馳風馭恣飄飄，因失仙班幾度朝。", "紫閣舊憐秦樹老，赤城新別海山遥。", "飛鳬又說春經嶽，叱橘曾令夜探潮。", "不是桃源不歸去，故人多半在烟霄。"]'),
('51a7958d-ffb7-477c-9d14-0c37a92cd3e1','句  其一','李絢','宋','宋诗','song-poetry','','[]','收得桑榆歸物外，種成桃李滿人間。',16,'全唐诗/poet.song.23000.json','["收得桑榆歸物外，種成桃李滿人間。"]'),
('04a17b7f-3096-4f87-a772-d6e6a89e7aa6','句  其二','李絢','宋','宋诗','song-poetry','','[]','吾宗天下著。',6,'全唐诗/poet.song.23000.json','["吾宗天下著。"]'),
('d26e34c5-bda8-4ab8-ae0b-878daaea65a6','句  其三','李絢','宋','宋诗','song-poetry','','[]','日迴龍並影，風過鳳聯聲。',12,'全唐诗/poet.song.23000.json','["日迴龍並影，風過鳳聯聲。"]'),
('c98e8b8e-e90c-420d-ac64-f13d5b5e3d70','綠珠渡','徐噩','宋','宋诗','song-poetry','','[]','早出綠蘿村，晚過綠珠渡。',52,'全唐诗/poet.song.23000.json','["早出綠蘿村，晚過綠珠渡。", "日落白州城，草荒梁女墓。", "江水流古今，滔滔不相顧。", "今人不見古時人，依舊青山路如故。"]'),
('875c5557-aa9e-4b60-a185-0aea866c889c','寄唐子方殿院','陳洙','宋','宋诗','song-poetry','','[]','子方簪筆侍丹墀，憂國忘家世所知。',64,'全唐诗/poet.song.23000.json','["子方簪筆侍丹墀，憂國忘家世所知。", "三諫未終先竄逐，一身雖賤繫安危。", "火中圭璧含真彩，雪外杉松挺直枝。", "荆楚秋風共誰語，勸君頻訪賈生祠。"]'),
('50a44f18-faca-48e1-9485-20e43e614988','遊雲際山','陳洙','宋','宋诗','song-poetry','','[]','清曉捫蘿踏嶺雲，寒風飛溜溼衣巾。',64,'全唐诗/poet.song.23000.json','["清曉捫蘿踏嶺雲，寒風飛溜溼衣巾。", "上攀霄漢無多地，直視城闉幾點塵。", "古木半陰藏宿霧，山禽相語厭遊人。", "明年更補閩中吏，來看桃花爛漫春。"]'),
('0c1291a8-d2a8-4997-8854-8a60180aec28','吳耿先生還北山舊居','陳洙','宋','宋诗','song-poetry','','[]','蒼浪兩鬢斑，盡意六經間。',48,'全唐诗/poet.song.23000.json','["蒼浪兩鬢斑，盡意六經間。", "有術佐明主，無官歸故山。", "釣臺春水碧，吟榭暮雲閑。", "見說還家後，重將舊史刪。"]'),
('b28c58bb-b37e-4578-a7d5-70e8ae22c7b8','書御史臺壁','陳洙','宋','宋诗','song-poetry','','[]','清朝無事諫書疏，竊祿經年卧直廬。',32,'全唐诗/poet.song.23000.json','["清朝無事諫書疏，竊祿經年卧直廬。", "惆悵平生不如夢，春來三度到溪居。"]'),
('f33b99b5-3bb7-490c-872f-110ab587f557','靖安寺','陳洙','宋','宋诗','song-poetry','','[]','處士亡來二百年，故居牢落變祇園。',64,'全唐诗/poet.song.23000.json','["處士亡來二百年，故居牢落變祇園。", "詩名長共江山在，寃氣尚磨星斗昏。", "臺榭幾人留好句，漁樵何處問曾孫。", "昔時泉石生涯地，日暮寒雲遶寺門。"]'),
('2e706c5a-da39-4a58-8955-9e4e1b480af0','雉山','黄照','宋','宋诗','song-poetry','','[]','爲愛空門息世機，儒衣不著著僧衣。',32,'全唐诗/poet.song.23000.json','["爲愛空門息世機，儒衣不著著僧衣。", "淵魚林鳥已聞法，更待當年瑞雉歸。"]'),
('f7a20966-7483-4d11-adaf-8400d1a17528','題五龍廟','蕭注','宋','宋诗','song-poetry','','[]','五龍兄弟古英名，今日拏舟過悅城。',32,'全唐诗/poet.song.23000.json','["五龍兄弟古英名，今日拏舟過悅城。", "莫向草茅久盤屈，早施霖雨活蒼生。"]'),
('af2aeada-5417-48c6-af55-9dddd3d665aa','句','邵迎','宋','宋诗','song-poetry','','[]','鹽鼓調羹金液膩，橙齏薦鱠玉絲肥。',16,'全唐诗/poet.song.23000.json','["鹽鼓調羹金液膩，橙齏薦鱠玉絲肥。"]'),
('e26d8ccb-00ad-4357-bc1d-3deb4c3fae97','龍隠巖','李師中','宋','宋诗','song-poetry','','[]','春波飽微綠，斗柄涵虛明。',204,'全唐诗/poet.song.23000.json','["春波飽微綠，斗柄涵虛明。", "方舟貫岩腹，鵝鸛相酬鳴。", "仰窺穹窿頂，宛轉百怪呈。", "僅餘鱗甲碎，不見頭角獰。", "下闖清冷淵，演迤萬頃澄。", "但同魚鳥參，勿遣蛟龍驚。", "抉苔撫奇篆，倚棹看題名。", "三將標殊勛，自與山不傾。", "誰與贅小築，政恐山靈嗔。", "南洞更幽絕，仙佛依崢嶸。", "太虛可爲室，豈復資欒楹。", "乳泉助茗盌，中有冰雪清。", "何須驂鸞去，此即白玉京。", "鼎來不速客，抱琴忽逢迎。", "愛此無絃曲，岩溜同一聲。", "爲君洗塵耳，喚我詩魂醒。", "祗恐白衣至，好句亡由成。"]'),
('399a1b68-79e9-43de-9eea-e725007dccf0','留題龍隠巖','李師中','宋','宋诗','song-poetry','','[]','過江緣磴尋溪垠，隠然絕壁天開門。',64,'全唐诗/poet.song.23000.json','["過江緣磴尋溪垠，隠然絕壁天開門。", "傳云此處昔龍隠，陰岩凜凜猶疑存。", "風雲已與時變會，苔蘚尚迹初潛痕。", "嗟余出處不自重，過事輕發難爲神。"]'),
('f9fdfcbb-a485-4de1-a248-03e0280b8cb0','遞中得先之兄書取邕欽宜柳歸約十二月到此年節已近未聞來朝寄奉  其一','李師中','宋','宋诗','song-poetry','','[]','我在灕江上，君行瘴海潯。',48,'全唐诗/poet.song.23000.json','["我在灕江上，君行瘴海潯。", "因勞南去夢，暫望北歸心。", "別後年華改，新來雨露深。", "憑欄望書信，一字抵千金。"]'),
('85c03eba-323d-498a-a39a-06e635415616','遞中得先之兄書取邕欽宜柳歸約十二月到此年節已近未聞來朝寄奉  其二','李師中','宋','宋诗','song-poetry','','[]','遠宦良多感，新來更可悲。',48,'全唐诗/poet.song.23000.json','["遠宦良多感，新來更可悲。", "春隨斗柄動，人自海邊歸。", "僕馬疲勞甚，郊原雨水時。", "經旬不得信，憑檻又吟詩。"]'),
('0b84beee-d25f-420a-be5b-78fee7cd8ff2','題太空子隠居','李師中','宋','宋诗','song-poetry','','[]','可道非常道，真空本不空。',48,'全唐诗/poet.song.23000.json','["可道非常道，真空本不空。", "茺郊自生草，閒地又栽松。", "無欲更何慮，有爲終必窮。", "風雲上天去，老子信猶龍。"]'),
('1234b885-2926-40d2-8899-fe56e3bde2d2','送桂州安撫余靖侍郎還京  其一','李師中','宋','宋诗','song-poetry','','[]','詔從東海付南麾，戎乘前驅上將威。',64,'全唐诗/poet.song.23000.json','["詔從東海付南麾，戎乘前驅上將威。", "異俗已傳吾父至，斯文更咏我公歸。", "歲時職貢還朱紱，晝日恩光賜兖衣。", "昔往今來亦何速，長亭楊柳尚依依。"]'),
('5d66f314-2b07-4332-91f1-a353a2c5f112','送桂州安撫余靖侍郎還京  其二','李師中','宋','宋诗','song-poetry','','[]','拜命南來得老臣，肅將廟畧制妖氛。',64,'全唐诗/poet.song.23000.json','["拜命南來得老臣，肅將廟畧制妖氛。", "淮西將吏尊儒帥，并土兒童認使君。", "新賜錦衣光照日，舊行棠樹茂如雲。", "應憐孤宦潮陽守，憔悴無人與上聞。"]'),
('4f1e478f-78fb-49d3-8e30-f186554ea76f','和李明叔理定道中','李師中','宋','宋诗','song-poetry','','[]','幽居日日數歸程，已寫華嚴兩帙經。',64,'全唐诗/poet.song.23000.json','["幽居日日數歸程，已寫華嚴兩帙經。", "門外初寒江氣白，嶺頭多雨曉痕青。", "曾逢飯顆嘲山笠，應載鴟夷笑井瓶。", "客土相思空引望，天涯風景似新亭。"]'),
('35c08c89-33cd-4442-9cb3-d8adc8688302','過嚴關有感  其一','李師中','宋','宋诗','song-poetry','','[]','大抵孤忠報國難，古今共是一長嘆。',32,'全唐诗/poet.song.23000.json','["大抵孤忠報國難，古今共是一長嘆。", "玉關還路春無綠，定遠歸來鬢已斑。"]'),
('15b3198d-54c8-4a4e-9d90-c68df638547a','過嚴關有感  其二','李師中','宋','宋诗','song-poetry','','[]','四年嶺外得生還，自顧無功但愧顔。',32,'全唐诗/poet.song.23000.json','["四年嶺外得生還，自顧無功但愧顔。", "欲識君恩至深處，嚴關便是玉門關。"]'),
('710636af-734e-4527-9c15-464a2c3c3b52','龍隠巖','李師中','宋','宋诗','song-poetry','','[]','軒冕儻來仍假借，功名難立更因循。',32,'全唐诗/poet.song.23000.json','["軒冕儻來仍假借，功名難立更因循。", "非才不繫蒼生望，收取林泉自在身。"]'),
('557b9f83-c8c0-43cd-baca-5d10e4638667','贈韓逈','李師中','宋','宋诗','song-poetry','','[]','未衰前已得懸車，骨立清風八十餘。',32,'全唐诗/poet.song.23000.json','["未衰前已得懸車，骨立清風八十餘。", "松竹最宜貧宅舍，江山徧照白髭鬚。"]'),
('94858bdc-4b27-4c2e-b847-fc88046da35e','客有寫真者見予因以三詩贈之  其一','李師中','宋','宋诗','song-poetry','','[]','嗟予少也賤，到老尚無功。',36,'全唐诗/poet.song.23000.json','["嗟予少也賤，到老尚無功。", "方寸浮名外，流年兩鬢中。", "對鏡猶慙媿，圖寫若爲容。"]'),
('598d7f7b-c331-42bb-8ec1-a8b80c217136','客有寫真者見予因以三詩贈之  其二','李師中','宋','宋诗','song-poetry','','[]','文命力能平水土，阿衡功亦格皇天。',32,'全唐诗/poet.song.23000.json','["文命力能平水土，阿衡功亦格皇天。", "形容不上麒麟閣，當日君臣任自然。"]'),
('68f09241-9a0f-41c9-9d49-294d719701c0','客有寫真者見予因以三詩贈之  其三','李師中','宋','宋诗','song-poetry','','[]','難逢古鑑明忠腹，長似騷人带病容。',32,'全唐诗/poet.song.23000.json','["難逢古鑑明忠腹，長似騷人带病容。", "幾向清溪曾照見，萬尋岩壑一青松。"]'),
('b3ce4ed7-a330-49c9-aee9-11df15aca7e9','送唐介進退韻','李師中','宋','宋诗','song-poetry','','[]','孤忠自許衆不與，獨立敢言人所難。',64,'全唐诗/poet.song.23000.json','["孤忠自許衆不與，獨立敢言人所難。", "去國一身輕似葉，高名千古重於山。", "並遊英俊顔何厚，未死奸諛骨已寒。", "天爲吾君扶社稷，肯教夫子不生還。"]'),
('e54328b8-db44-4365-9414-98f58427c443','穎國龐公挽詞','李師中','宋','宋诗','song-poetry','','[]','獨立無朋但任真，不持身勢掩君親。',32,'全唐诗/poet.song.23000.json','["獨立無朋但任真，不持身勢掩君親。", "若將坤體論臣道，公是朝廷第一人。"]'),
('74371d17-2154-4bd7-a2af-5e3250e87f76','麥積山','李師中','宋','宋诗','song-poetry','','[]','路入青松翠靄間，斜陽倒影入溪灣。',32,'全唐诗/poet.song.23000.json','["路入青松翠靄間，斜陽倒影入溪灣。", "此中猿鶴休相笑，謝傅東歸自有山。"]'),
('005354c0-18ea-40b1-83ab-9e1d17c79a26','天目山','李師中','宋','宋诗','song-poetry','','[]','壞壁摩娑少舊題，高情應怪賞音稀。',64,'全唐诗/poet.song.23000.json','["壞壁摩娑少舊題，高情應怪賞音稀。", "烟霞正自無今古，雲水從教遠是非。", "丹井金龍藏洞府，杞叢花犬蕩霞扉。", "登臨未學神仙事，老樹閒看獨鳥歸。"]'),
('47164f44-7e17-4ed7-8a78-27ec0172f396','韓魏公席上爲官妓賈愛卿作','李師中','宋','宋诗','song-poetry','','[]','願得貔貅十萬兵，犬戎巢穴一時平。',32,'全唐诗/poet.song.23000.json','["願得貔貅十萬兵，犬戎巢穴一時平。", "最來不用封侯印，只問君王乞愛卿。"]'),
('dfb04777-f57e-46ff-88a6-1fb5fe78f710','唐州太守','李師中','宋','宋诗','song-poetry','','[]','時屬艱危應有繫，天於名教豈無心。',64,'全唐诗/poet.song.23000.json','["時屬艱危應有繫，天於名教豈無心。", "大都狂賊終須滅，未殺忠臣禍不深。", "太尉有靈朱泚敗，中丞傳旨祿山擒。", "曾誰鼓舞康州事，兒女常情淚滿襟。"]'),
('7e1824d9-c2a8-4666-bf25-209cc7388d23','偶題','李師中','宋','宋诗','song-poetry','','[]','燕子知時節，還尋舊宇歸。',24,'全唐诗/poet.song.23000.json','["燕子知時節，還尋舊宇歸。", "新人方按曲，不許傍簾飛。"]'),
('e56aba62-cab6-4057-830c-8184af399068','昭陵挽詞','李師中','宋','宋诗','song-poetry','','[]','堯民喪考無生意，杞國憂天有壞時。',32,'全唐诗/poet.song.23000.json','["堯民喪考無生意，杞國憂天有壞時。", "聞道宗祧歸聖嗣，一時收淚賀重熙。"]'),
('266c0445-5009-407e-abec-69525b84aa24','咏松','李師中','宋','宋诗','song-poetry','','[]','半依巖岫倚雲端，獨上亭亭耐歲寒。',32,'全唐诗/poet.song.23000.json','["半依巖岫倚雲端，獨上亭亭耐歲寒。", "一事頗爲清節累，秦時曾作大夫官。"]'),
('708695b9-0fc1-4509-8f65-be0b0f6c50dc','子陵二首  其一','李師中','宋','宋诗','song-poetry','','[]','阿諛順旨爲深戒，遠比夷齊氣更豪。',32,'全唐诗/poet.song.23000.json','["阿諛順旨爲深戒，遠比夷齊氣更豪。", "半夜光芒侵帝座，有誰曾似客星高。"]'),
('37a4da88-9dec-45b6-b05b-985958132393','子陵二首  其二','李師中','宋','宋诗','song-poetry','','[]','社稷功名出隠淪，天高聽遠亦應聞。',32,'全唐诗/poet.song.23000.json','["社稷功名出隠淪，天高聽遠亦應聞。", "龐眉一去無人問，七里商山但白雲。"]'),
('47696cdd-7730-4738-bcfc-ec3e25f52204','中隠巖  其一','李師中','宋','宋诗','song-poetry','','[]','訪隠尋幽緩著鞭，梅花初試小春天。',64,'全唐诗/poet.song.23000.json','["訪隠尋幽緩著鞭，梅花初試小春天。", "孤峯上下分三洞，一水縈紆溉萬田。", "好向忙中拋俗事，却來閑處覓神仙。", "清虛不似人間世，野鶴飛雪遶檻前。"]'),
('e515483f-237e-4ae5-919a-954015618942','中隠巖  其二','李師中','宋','宋诗','song-poetry','','[]','坎止流行但信緣，嶠南風景異山川。',32,'全唐诗/poet.song.23000.json','["坎止流行但信緣，嶠南風景異山川。", "偶因乘興穿山腹，始悟壺中別有天。"]'),
