('ed9894f4-241f-4425-9606-e0a553c68e6f','挽老蘇先生','張燾','宋','宋诗','song-poetry','','[]','本朝文物盛西州，獨得宗公薦冕旒。',64,'全唐诗/poet.song.23000.json','["本朝文物盛西州，獨得宗公薦冕旒。", "稷嗣草儀書未奏，茂陵辭客病無瘳。", "一門歆向傳家學，二子機雲並雋遊。", "守蜀無因奠尊酒，素車應滿古原頭。"]'),
('855b705a-e9bd-4b82-a223-9144ec756897','耆英會詩','張燾','宋','宋诗','song-poetry','','[]','洛城今昔衣冠盛，韓國園林景物全。',64,'全唐诗/poet.song.23000.json','["洛城今昔衣冠盛，韓國園林景物全。", "功在三朝尊二相，數逾九老萃羣賢。", "當時鄉社爲高會，此日居留許款延。", "多幸不才陪履舄，更慚七十是新年。"]'),
('16064e1d-9576-4b5c-934c-543d50b6c65b','耆英會詩','張問','宋','宋诗','song-poetry','','[]','槐庭二老樂堯仁，盛集高年洛水濱。',192,'全唐诗/poet.song.23000.json','["槐庭二老樂堯仁，盛集高年洛水濱。", "華衮具瞻雖禮絕，白頭序齒却情親。", "清閑几席同禪院，山野巾裘似隠淪。", "尊酒椒香纔過節，池塘草色已催春。", "白公酣暢吟哦內，衛武康强笑語頻。", "豈獨丹青傳不朽，潛欣風俗欲還淳。", "芝田鶴戲調形健，蓮葉龜遊納息勻。", "商皓寂寥拘小隠，漢疏局促止家人。", "莫因氣貌疑丹竈，自有光陰寄大椿。", "復得兼謨爲重客，恐遺元爽在編民。", "神仙可學今方信，道術相忘久益真。", "滿座交歡祝眉壽，羣生五福託鴻鈞。"]'),
('741e0621-f70c-4fc9-ae88-f6a9e942f975','禮法門寺真身塔','張問','宋','宋诗','song-poetry','','[]','衆生瞻窣堵，迴向大覺身。',24,'全唐诗/poet.song.23000.json','["衆生瞻窣堵，迴向大覺身。", "內顧六尺軀，一雨無諸塵。"]'),
('b0914d41-bd27-4f10-80b0-3da52a3eae31','送唐介謫英州','徐九思','宋','宋诗','song-poetry','','[]','投荒萬里嶺南行，莫叩天閽訴不平。',64,'全唐诗/poet.song.23000.json','["投荒萬里嶺南行，莫叩天閽訴不平。", "忠讜若教無竄逐，奸邪何計竊安榮。", "一封疏在銘周鼎，三黜名高重漢京。", "最是中霄雷激烈，爲君特地發寃聲。"]'),
('cb15887a-e3f9-47be-bfa3-d3629e43cf1e','句','燕度','宋','宋诗','song-poetry','','[]','三山排鼎足，七塔布琴弦。',12,'全唐诗/poet.song.23000.json','["三山排鼎足，七塔布琴弦。"]'),
('076f6df0-40a7-44df-bbce-5d988b535ab1','書驛壁  其一','姚嗣宗','宋','宋诗','song-poetry','','[]','踏碎賀蘭石，掃清西海塵。',24,'全唐诗/poet.song.23000.json','["踏碎賀蘭石，掃清西海塵。", "布衣能效死，可惜作窮鱗。"]'),
('575aa40d-f244-4049-842f-8e5f206e1f47','書驛壁  其二','姚嗣宗','宋','宋诗','song-poetry','','[]','百越干戈未息肩，九原金鼓又轟天。',32,'全唐诗/poet.song.23000.json','["百越干戈未息肩，九原金鼓又轟天。", "崆峒山叟笑不語，靜聽松風春晝眠。"]'),
('f386f531-4edc-4edb-a52b-1f1a1296b852','題閩中驛舍','姚嗣宗','宋','宋诗','song-poetry','','[]','欲挂衣冠神武門，先尋水竹渭南村。',32,'全唐诗/poet.song.23000.json','["欲挂衣冠神武門，先尋水竹渭南村。", "却將舊斬樓蘭劍，買得黄牛教子孫。"]'),
('bfa614c3-2952-4723-9091-6194c8627a94','暢巖','姚嗣宗','宋','宋诗','song-poetry','','[]','石作峒房勢，水隨人意流。',48,'全唐诗/poet.song.23000.json','["石作峒房勢，水隨人意流。", "兩巖長濺雨，五月便驚秋。", "此景多深趣，吾心真樂遊。", "山翁中宿酒，欲醉五更頭。"]'),
('4615d8d9-2c03-4367-b2d6-b1853191b9c5','暢巖懷古','姚嗣宗','宋','宋诗','song-poetry','','[]','寒谷長留□秋氣，暢巖別是一壺天。',32,'全唐诗/poet.song.23000.json','["寒谷長留□秋氣，暢巖別是一壺天。", "清風不斷名猶在，還繼宣尼出聖賢。"]'),
('02b6bfc7-1ac0-4b36-83b9-8ddbb878e59b','句  其一','姚嗣宗','宋','宋诗','song-poetry','','[]','大開雙白眼，只見一青天。',12,'全唐诗/poet.song.23000.json','["大開雙白眼，只見一青天。"]'),
