('1237b17d-5135-402a-a390-81dd8d0fd716','雪','張元','宋','宋诗','song-poetry','','[]','五丁仗劍決雲霓，直取銀河下帝畿。',32,'全唐诗/poet.song.23000.json','["五丁仗劍決雲霓，直取銀河下帝畿。", "戰死玉龍三十萬，敗鱗風捲滿天飛。"]'),
('4200d21c-3e21-4614-b7c5-775636192650','詩一首','張元','宋','宋诗','song-poetry','','[]','夏竦何曾聳，韓琦未是奇。',24,'全唐诗/poet.song.23000.json','["夏竦何曾聳，韓琦未是奇。", "滿川龍虎舉，猶自說兵機。"]'),
('f01d8c2c-db4a-4308-bf54-cf391289fc44','句  其一','張元','宋','宋诗','song-poetry','','[]','好著金籠收拾取，莫教飛去別人家。',16,'全唐诗/poet.song.23000.json','["好著金籠收拾取，莫教飛去別人家。"]'),
('71834134-25b3-48ad-9b84-3f0955c78a1e','句  其二','張元','宋','宋诗','song-poetry','','[]','有心待搦月中兔，更向白雲頭上飛。',16,'全唐诗/poet.song.23000.json','["有心待搦月中兔，更向白雲頭上飛。"]'),
('0c471ea6-d9a4-4b40-a992-304a1e5428d3','峽山古調','杜曾','宋','宋诗','song-poetry','','[]','濫觴岷山側，朝宗蓋自然。',288,'全唐诗/poet.song.23000.json','["濫觴岷山側，朝宗蓋自然。", "沸沸出幽竇，滔滔成巨川。", "深流疑徹地，遠勢欲浮天。", "萬石攢若鬭，一流瀉如懸。", "二蜀通貨博，三峽爲防堅。", "上下比難險，往來爭泝沿。", "衝高濆氣盛，轉急洶形圓。", "行人戒仲夏，招子尚耆年。", "風波雖滅裂，灘磧且叢駢。", "湍聲混蠻市，漲潤入畬田。", "旁臨股且栗，順下目無前。", "浮沫逢槎聚，垂瀑依岸穿。", "哀猿藏森聳，渴鹿聽潺湲。", "幽勝祠宇密，傾危村舍聯。", "寒沙淹宿雨，暖溆罩春煙。", "青蕪隨遠曲，白鳥戲輕漣。", "常經祗名利，舊隠多神仙。", "至清逃鰌鱓，極奧容鱘鱣。", "楚臣忠義鬰，巫女威福專。", "龍驤戰具敏，鯀嗣導功全。", "瞿唐十里暗，灧澦一邱偏。", "砥柱未足擬，呂梁誠浪傳。", "伊予非智者，被命徒勉旃。", "尺短糾列郡，寸進乘孤船。"]'),
('5abf893c-0df1-483b-b619-c781c247f941','和趙閱道游海雲山','邢夢臣','宋','宋诗','song-poetry','','[]','使旌驅近郭，民宴列芳池。',48,'全唐诗/poet.song.23000.json','["使旌驅近郭，民宴列芳池。", "洩洩春臺上，沈沈暮海涯。", "鴻驚人宛轉，電激騎追隨。", "此會經年至，須防日似馳。"]'),
('75025296-88cd-4cb2-ada8-8b11eea2b19e','司馬晉州待制哀辭','馬端','宋','宋诗','song-poetry','','[]','志古流難合，談高道自明。',144,'全唐诗/poet.song.23000.json','["志古流難合，談高道自明。", "風波志恩分，鍼石盡交情。", "讓節蒙知厚，華班絕綺榮。", "賤生懷感遇，當路假晶熒。", "累次清油幕，中間白玉京。", "吏文容議緩，邦事卹言輕。", "自此嗟流梗，何期苦見兵。", "寒垣心易動，漳浦信彌驚。", "玉蕊悲無驗，金臺望忽傾。", "歲闌雲慘淡，天迥淚縱橫。", "世有真忠亮，今亡至直清。", "舊僚知葬日，投此弔佳城。"]'),
('395f14fa-754b-44f8-b9e9-89d1d0ef5170','冬夕小齋聯句寄梅聖俞','陸經','宋','宋诗','song-poetry','','[]','寒窗明夜月，散帙耿燈火。',120,'全唐诗/poet.song.23000.json','["寒窗明夜月，散帙耿燈火。", "破硯裂冰澌，敗席薦霜笴。", "廢書浩長吟，想子實勞我。", "清篇追曹劉，苦語侔島可。", "酣飲每頹山，談笑工炙輠。", "駕言當有期，歲晚何未果。", "幽夢辭如雲，別愁牢若鎖。", "雪水漸漣漪，春枝將婀娜。", "客心莫遲留，苑葩即紛墮。", "何當迎笈前，相逢嘲飯顆。"]'),
('43e57357-2462-435d-ab8d-e6f78c78b828','丁中允宰剡','陸經','宋','宋诗','song-poetry','','[]','塵土官曹幾處閒，今君得邑好開顔。',64,'全唐诗/poet.song.23000.json','["塵土官曹幾處閒，今君得邑好開顔。", "落帆直向剡谿口，入境先登天姥山。", "魚鳥半和風俗處，雲霞多雜簿書閒。", "雪晴須去尋安道，不作經宵興盡還。"]'),
('b9f7f399-77ed-4000-be56-3099f48100bd','震山巖','陸經','宋','宋诗','song-poetry','','[]','稍變春羅色，還追雲壑遊。',48,'全唐诗/poet.song.23000.json','["稍變春羅色，還追雲壑遊。", "俯探青玉窟，傍挹翠綃流。", "九夏日車冷，四時龍氣浮。", "隠淪今不見，釣叟浪垂鈎。"]'),
('9cc585fe-22e3-4283-b4f9-479356f3361e','化成巖','陸經','宋','宋诗','song-poetry','','[]','交臂尋幽歲已殘，瘦藤枯石重躋攀。',64,'全唐诗/poet.song.23000.json','["交臂尋幽歲已殘，瘦藤枯石重躋攀。", "忽逢晴洞龍開室，冷瞰寒溪玉繞山。", "猿鳥窺人知舊識，藤蘿引逕入無間。", "遊車自向紅塵去，日暮老僧催閉關。"]'),
('293c337a-af19-4ee0-8928-78962d6aaece','雷潭','陸經','宋','宋诗','song-poetry','','[]','山郭五里餘，氣象忽異色。',156,'全唐诗/poet.song.23000.json','["山郭五里餘，氣象忽異色。", "蛟龍嘗此蟠，潭水至今黑。", "變化驗莫窮，白晝起霹靂。", "山形抱江來，怪石莫傾側。", "有寺出其間，戶牖立丹壁。", "微雲垂鑑中，彩色畫不得。", "小閣纔數弓，吐納半江碧。", "日光涵遊鱼，到底如不隔。", "老竹風蕭蕭，長根擘青石。", "送聲寄哀絃，往往動魂魄。", "載酒同遨遊，逢奇得搜索。", "形體相與忘，山林信吾適。", "乃知人世間，捨上固怵迫。"]'),
('ba8f898a-e517-43d5-bd30-6380c56da749','晚泛秀水','陸經','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','落日進扁舟，沿迴碧玉流。',48,'全唐诗/poet.song.23000.json','["落日進扁舟，沿迴碧玉流。", "未能追白鳥，貪共數游鯈。", "翠壁玲瓏倒，青天表裏浮。", "誰湔世間熱，灑出洞庭秋。"]'),
('eb0a6f34-e5ba-4524-b819-468b0b8ca149','句  其一','陸經','宋','宋诗','song-poetry','','[]','寄語瀛洲未歸客，醉翁今已作仙翁。',16,'全唐诗/poet.song.23000.json','["寄語瀛洲未歸客，醉翁今已作仙翁。"]'),
('160b5dcb-72ea-47d4-8046-4ccba44da72e','句  其二','陸經','宋','宋诗','song-poetry','','[]','薄有田園歸去好，苦無官況莫來休。',16,'全唐诗/poet.song.23000.json','["薄有田園歸去好，苦無官況莫來休。"]'),
('12668a55-27a4-45cf-9f4f-ded073a17907','題天章','劉誥','宋','宋诗','song-poetry','','[]','逸少蘭亭六百年，別營樓閣奉金仙。',64,'全唐诗/poet.song.23000.json','["逸少蘭亭六百年，別營樓閣奉金仙。", "琅函帝賜三朝筆，貌座僧談二祖禪。", "山怪有時渾露石，地靈無處不通泉。", "塵心未悟真如理，空爇晨鑪一篆煙。"]'),
('42a46127-ee62-491f-bd01-994f0e7b1a8a','句  其一','李珣','宋','宋诗','song-poetry','','[]','參差草樹連巴國，依約雲煙遶楚臺。',16,'全唐诗/poet.song.23000.json','["參差草樹連巴國，依約雲煙遶楚臺。"]'),
('1df15f17-19af-415f-912c-bd109d97dcf6','句  其二','李珣','宋','宋诗','song-poetry','','[]','月窗花院夢悠揚。',8,'全唐诗/poet.song.23000.json','["月窗花院夢悠揚。"]'),
('7abee726-66d4-472f-91ba-6d291b321ede','迎趙清獻公遊雁蕩','石景立','宋','宋诗','song-poetry','','[]','雁蕩天台路險艱，多應特地隔塵寰。',64,'全唐诗/poet.song.23000.json','["雁蕩天台路險艱，多應特地隔塵寰。", "不辭登陟來千里，爲是東南第一山。", "爭望台星從海上，方知蓬島在人間。", "武林二老圖中見，重惜官師遠莫攀。"]'),
('b6b570ca-1452-4433-98c1-ffceeef5bef5','桐柏崇道觀','楊愈','宋','宋诗','song-poetry','','[]','深入黄庭景，徒思五滴泉。',48,'全唐诗/poet.song.23000.json','["深入黄庭景，徒思五滴泉。", "青牛眠藥塢，白鹿卧芝田。", "浮世人空老，長生事宛然。", "三尸飛不去，皆是自留連。"]'),
('a9c790c1-ce91-4523-bc3d-9783b28f6b6c','句','朱元瑜','宋','宋诗','song-poetry','','[]','嚼梅香襲齒，攀柳綠藏巾。',12,'全唐诗/poet.song.23000.json','["嚼梅香襲齒，攀柳綠藏巾。"]'),
('053409c3-de4b-4dca-a901-3aa39e6f216c','上元口號','張正己','宋','宋诗','song-poetry','','[]','繡車蕭鼓動香街，鐵鎖龜城度曉開。',64,'全唐诗/poet.song.23000.json','["繡車蕭鼓動香街，鐵鎖龜城度曉開。", "仙鳳傳香留蜀國，夜龍銜燭上蓬萊。", "月如流水隨天遠，人似夭桃出洞來。", "無限風光追不盡，只驚信馬到瑶臺。"]'),
('8df860d0-40a4-4004-a747-3ebf4c481fda','和龐學士','藍方','宋','宋诗','song-poetry','','[]','仰告明君乞得身，不妨林下戴紗巾。',64,'全唐诗/poet.song.23000.json','["仰告明君乞得身，不妨林下戴紗巾。", "滿斟村酒浮瓊蟻，旋釣溪魚鱠錦鱗。", "元府烏鴉飛後夜，洞中花木鎮長春。", "吾官儻若爲同志，箇裏才由兩箇人。"]'),
('a1f08020-ae6c-41d5-9db5-3c8b6e594576','贈養素先生','龐昌','宋','宋诗','song-poetry','','[]','聖澤濃雲隠逸身，道裝宜用葛爲巾。',64,'全唐诗/poet.song.23000.json','["聖澤濃雲隠逸身，道裝宜用葛爲巾。", "祝融峯下醉明月，綠水源頭釣紫鱗。", "曾見海桃三結子，不知仙豆幾回春。", "他年我若功成去，願作雲橋跪履人。"]'),
('79628758-67ca-46af-b7af-44d032ac7f36','干友人詩','高言','宋','宋诗','song-poetry','','[]','昨夜陰風透膽寒，地爐無火酒瓶乾。',32,'全唐诗/poet.song.23000.json','["昨夜陰風透膽寒，地爐無火酒瓶乾。", "男兒慷慨平生事，時復挑燈把劍看。"]'),
('236eea09-c40a-4fe2-804d-7a9b71e0986d','句','王度','宋','宋诗','song-poetry','','[]','風摧秀林木，色變附藍絲。',12,'全唐诗/poet.song.23000.json','["風摧秀林木，色變附藍絲。"]'),
('a9deb7cf-e1f7-4faf-a5fd-85fd46b7ecd6','送梵才大師歸天台','高竦','宋','宋诗','song-poetry','','[]','吟指建標霞，南歸繼永嘉。',48,'全唐诗/poet.song.23000.json','["吟指建標霞，南歸繼永嘉。", "老禪心是佛，新句玉無瑕。", "乳竇流雲液，松風落粉花。", "舊房閒宴外，不復夢京華。"]'),
('1d4bf741-3aac-4239-89d5-af4fc7f63777','接宣撫偕道正訪九龍巖主喜師率成二十八字','章詢','宋','宋诗','song-poetry','','[]','閒携羽客記靈巖，巖透山光秀潑藍。',32,'全唐诗/poet.song.23000.json','["閒携羽客記靈巖，巖透山光秀潑藍。", "星使未來邨館近，爲師終日絆征驂。"]'),
('595314d4-e09b-475a-9db6-b50799ed9e64','水簾','虞大博','宋','宋诗','song-poetry','','[]','疏水成簾造化功，冷光千丈半巖風。',64,'全唐诗/poet.song.23000.json','["疏水成簾造化功，冷光千丈半巖風。", "層霄螮蝀正鋪地，蒼海珠璣初墮空。", "天下奇觀更何處，騷人幽詠未全工。", "要知出壑爭流意，不向三巴直向東。"]'),
('dbfd0626-5df4-4497-876b-380238aae108','資韻經略吳及石門洞','杜于能','宋','宋诗','song-poetry','','[]','桂風泛泛桂江流，南師旌牙喜訪求。',64,'全唐诗/poet.song.23000.json','["桂風泛泛桂江流，南師旌牙喜訪求。", "詩刻蒼崖留篆在，雲生纖徑稱欄幽。", "而今入幕賓僚盛，又況褰帷政事修。", "更對酒樽堪醉傲，幾多泉石助吟游。"]'),
('c1457a84-fb1a-4aea-b5fc-bb3ccf14486b','句','劉宏','宋','宋诗','song-poetry','','[]','黄茅苦露宜加意，莫累吾君殺諫臣。',16,'全唐诗/poet.song.23000.json','["黄茅苦露宜加意，莫累吾君殺諫臣。"]'),
('dbea2797-4fdc-4225-bdf3-347269734fae','古歌贈巖主喜公','陶羽','宋','宋诗','song-poetry','','[]','喜公心眼如有靈，善擇此巖來構扃。',128,'全唐诗/poet.song.23000.json','["喜公心眼如有靈，善擇此巖來構扃。", "崖根踏碎暮煙碧，洞門鑿破蒼苔青。", "交加亂石虎狼隊，縱橫怪木龍蛟形。", "其間可以松蘿招隠，雲霞放情。", "傲復傲兮何富貴，恣復恣兮閑利名。", "況乎龍蛟勇背俟風雨，靈龜垂首思雷霆。", "我今方爲年少英，青山未有歸去心。", "他時致堯功業成，與師高卧白雲深。"]'),
('00b9b62f-4e59-4535-901d-34a91775242b','虎跑泉','錢嵊','宋','宋诗','song-poetry','','[]','虎攫靈泉發地根，傳疑傳信事難分。',64,'全唐诗/poet.song.23000.json','["虎攫靈泉發地根，傳疑傳信事難分。", "深涵月影千尋透，溜作溪聲一带聞。", "流迸石渠珠若露，溟濛竹徑氣如雲。", "公餘共酌醍醐味，應想於菟乳子文。"]'),
('ff73f409-479b-4a11-9a24-a3f5b64be6df','贈何中立','郭從周','宋','宋诗','song-poetry','','[]','三字從來月正圓，一麾從此出秦關。',32,'全唐诗/poet.song.23000.json','["三字從來月正圓，一麾從此出秦關。", "錢塘春色濃如酒，貪醉花間卧不還。"]'),
('673c23db-e9a6-452d-86b9-0fa19c8b2106','經戰地','魯交','宋','宋诗','song-poetry','','[]','西邊用兵地，黯慘無人耕。',48,'全唐诗/poet.song.23000.json','["西邊用兵地，黯慘無人耕。", "戰士報國死，寒草迎春生。", "沙飛賊風起，晝黑陣雲橫。", "未持天下箒，何以反欃槍。"]'),
('cb8d9625-1543-4667-8126-815961079c7b','大雪','魯交','宋','宋诗','song-poetry','','[]','萬象曉一色，皓然天地中。',48,'全唐诗/poet.song.23000.json','["萬象曉一色，皓然天地中。", "楚山雲母障，漢殿水精宮。", "遠近梅花信，高低柳絮風。", "吟魂清不徹，和月上晴空。"]'),
('01ca634c-c10b-4e51-991a-0c1ef552211d','遊安樂山','魯交','宋','宋诗','song-poetry','','[]','苔逕傍巖斜，林間是道家。',24,'全唐诗/poet.song.23000.json','["苔逕傍巖斜，林間是道家。", "夜潭魚戲月，春地鹿眠花。"]'),
('3c98e615-2e66-49d7-9674-09bfadcd2351','遊華山張超谷','魯交','宋','宋诗','song-poetry','','[]','太華鎖深谷，我來真景分。',48,'全唐诗/poet.song.23000.json','["太華鎖深谷，我來真景分。", "有苗皆是藥，無石不生雲。", "急瀑和煙瀉，清猿带雨聞。", "幽悽未忍別，峰半日將曛。"]'),
('d0c261ec-7e9f-4596-a9c2-2d7b466df29b','江樓晴望','魯交','宋','宋诗','song-poetry','','[]','江干一雨收，霽色染新愁。',48,'全唐诗/poet.song.23000.json','["江干一雨收，霽色染新愁。", "遠水碧千里，夕陽紅半樓。", "笛寒漁浦晚，山翠海門秋。", "更待牛津月，袁宏欲泛舟。"]'),
('46002cd9-7db1-4e1f-8fa2-356ccd63fd16','燭','魯交','宋','宋诗','song-poetry','','[]','暖煙紅炬兩飄香，珠箔沈沈下建章。',64,'全唐诗/poet.song.23000.json','["暖煙紅炬兩飄香，珠箔沈沈下建章。", "有燄只憑心一寸，無愁虛滴煙千行。", "流蘇帳裏回殘夢，白玉臺邊映宿妝。", "若到蓬山留夜直，金蓮應照珮鏘鏘。"]'),
('db925a8c-7d2b-4a49-b84b-61a1a3f799d8','清夜吟','魯交','宋','宋诗','song-poetry','','[]','露華清八極，吟上小樓東。',48,'全唐诗/poet.song.23000.json','["露華清八極，吟上小樓東。", "月色水鋪地，雁聲秋滿空。", "明河欲瀉浪，瘦竹自生風。", "坐久心骨爽，此懷誰與同。"]'),
('42981c24-2a48-4607-9f01-c4dd6c4195e3','有寄','魯交','宋','宋诗','song-poetry','','[]','思君又是東風起，樓倚浮雲目千里。',32,'全唐诗/poet.song.23000.json','["思君又是東風起，樓倚浮雲目千里。", "芳草不知人斷腸，带煙带雨連春水。"]'),
('442f528e-1413-4813-8e7f-ca883b76e4ba','經秦皇墓','魯交','宋','宋诗','song-poetry','','[]','祖龍何事苦東巡，仙駕歸來冢草新。',64,'全唐诗/poet.song.23000.json','["祖龍何事苦東巡，仙駕歸來冢草新。", "項籍已飛三月火，子嬰猶醉六宮春。", "元來滄海殊無藥，却是芒碭暗有人。", "自古乾坤屬真主，驪山山下好霑巾。"]'),
('e30bb796-bac1-47b3-a8f2-70bd11b57126','寄劉彥炳','魯交','宋','宋诗','song-poetry','','[]','征旆遥分苑路西，馬蹄春去弋陽溪。',32,'全唐诗/poet.song.23000.json','["征旆遥分苑路西，馬蹄春去弋陽溪。", "相思欲和烏啼曲，一拂瑶弦意總迷。"]'),
('e0390edd-22df-496f-9a01-9fcd6c5d5b5f','句  其一','魯交','宋','宋诗','song-poetry','','[]','萬仞青崖碧玉寒，岩蘿相引徹仙壇。',16,'全唐诗/poet.song.23000.json','["萬仞青崖碧玉寒，岩蘿相引徹仙壇。"]'),
('a77dd1c6-5ab0-492b-8a90-a6a1f84db306','句  其二','魯交','宋','宋诗','song-poetry','','[]','煙蘿梓郡東，蓮梵白雲中。',12,'全唐诗/poet.song.23000.json','["煙蘿梓郡東，蓮梵白雲中。"]'),
('ed65c5ed-3615-466c-897c-ca3f9fe5e69b','南莊','許昌齡','宋','宋诗','song-poetry','','[]','南莊相對北莊居，更入深山十里餘。',64,'全唐诗/poet.song.23000.json','["南莊相對北莊居，更入深山十里餘。", "幽路每尋樵徑上，真心還與世情疎。", "雲中犬吠流星過，天外鷄鳴曉日初。", "昨日有人相問訊，旋將落葉寫回書。"]'),
('48c5d841-64fb-4208-8f11-3b364555f702','謁館閣校勘歐陽公','蔡高','宋','宋诗','song-poetry','','[]','此日登史閣，高風孰可追。',48,'全唐诗/poet.song.23000.json','["此日登史閣，高風孰可追。", "學期明主佐，道許後生師。", "余豈能自信，公真不我欺。", "微躬托所厚，慚愧異新和。"]'),
('12849729-c8d7-41cb-9f0e-f13103afafb4','登狼山','吳及','宋','宋诗','song-poetry','','[]','郡僻山更遠，塵喧與世違。',48,'全唐诗/poet.song.23000.json','["郡僻山更遠，塵喧與世違。", "水橫觀雁度，天靜見龍歸。", "落葉霜凝樹，思親淚濕衣。", "西風怕回首，不忍白雪飛。"]'),
('586c9289-955d-4e21-a714-8f8e76dd56ba','長橋','吳及','宋','宋诗','song-poetry','','[]','有客過津亭，高歌願濯纓。',48,'全唐诗/poet.song.23000.json','["有客過津亭，高歌願濯纓。", "闌干聚烟碧，波浪捲秋聲。", "蝀飲瀟湘渴，龍游河漢橫。", "夕陽看不厭，待看月華生。"]'),
('abb61968-e638-4b64-8c75-33fd0efb2c73','餞光祿兩張卿退居  其一','呂溱','宋','宋诗','song-poetry','','[]','壯爾盡忠力，耆年保素心。',96,'全唐诗/poet.song.23000.json','["壯爾盡忠力，耆年保素心。", "東門脫圭組，南國傲雲林。", "水石排清景，簷楹入翠陰。", "雜花春瑩酒，脆葉夜驚禽。", "竹月歌欹枕，松風一解襟。", "體清塵累去，天得道腴深。", "坐有三公適，中無一芥侵。", "大恩嗟未報，何日奉觴琴。"]'),
('c30d40a9-8f4c-40de-a59c-1afa9529c3f2','餞光祿兩張卿退居  其二','呂溱','宋','宋诗','song-poetry','','[]','江上築臺遺世塵，堂中虛白見天真。',64,'全唐诗/poet.song.23000.json','["江上築臺遺世塵，堂中虛白見天真。", "丹心許國平生事，皓首還家自在身。", "水樹芬馨憐茝蕙，雪軒顔色愛松筠。", "清時解紱端榮佚，不獨賢哉詠古人。"]'),
('0a9f2267-9da0-4cb0-a706-e9ea47c8621e','句','呂溱','宋','宋诗','song-poetry','','[]','九霄離海嶠，一息到天池。',12,'全唐诗/poet.song.23000.json','["九霄離海嶠，一息到天池。"]'),
('7ef6293a-14e8-476a-9980-b214d478dab9','和邵堯夫見寄','呂誨','宋','宋诗','song-poetry','','[]','冥冥鴻羽在雲天，邈阻風音已十年。',64,'全唐诗/poet.song.23000.json','["冥冥鴻羽在雲天，邈阻風音已十年。", "不謂聖朝求治理，尚容遺逸卧林泉。", "羨君自有隨時樂，顧我官閒飽晝眠。", "應笑無成三黜後，病衰方始賦歸田。"]'),
('d633815f-403c-4df8-957c-4402e954f8f1','寄堯夫三首  其一','呂誨','宋','宋诗','song-poetry','','[]','江頭五日艤輕舟，欲去遲遲更自留。',32,'全唐诗/poet.song.23000.json','["江頭五日艤輕舟，欲去遲遲更自留。", "目斷旌旗暮天闊，龍峰峰上倚層樓。"]'),
('93b76e26-1d25-4e0e-842b-7b9376c7c1b2','寄堯夫三首  其二','呂誨','宋','宋诗','song-poetry','','[]','去年同作南遷客，今日更持刺史權。',32,'全唐诗/poet.song.23000.json','["去年同作南遷客，今日更持刺史權。", "推挽試知民吏意，無因談會向尊前。"]'),
('69fa8885-61f9-4f7f-b385-1629a190359a','寄堯夫三首  其三','呂誨','宋','宋诗','song-poetry','','[]','碧草茸茸照綠波，暮春歸客興如何。',32,'全唐诗/poet.song.23000.json','["碧草茸茸照綠波，暮春歸客興如何。", "滄浪應有清渾處，羞見漁人鼓枻歌。"]'),
('8082e772-c3f4-44c3-a112-c19ce6ac0a9c','句  其一','呂誨','宋','宋诗','song-poetry','','[]','我今從帝爲司糾，更有何人植柏臺。',16,'全唐诗/poet.song.23000.json','["我今從帝爲司糾，更有何人植柏臺。"]'),
('65b32b8b-21bc-4aba-93fc-d0accd5b46ee','句  其二','呂誨','宋','宋诗','song-poetry','','[]','料峭東風不易禁。',8,'全唐诗/poet.song.23000.json','["料峭東風不易禁。"]'),
('4d91c9fe-1d21-4ca9-8375-c00b2cbb2090','七星巖','孔延之','宋','宋诗','song-poetry','','[]','隠安樓閣貫空嵌，絕頂磨霄凝悴嵐。',32,'全唐诗/poet.song.23000.json','["隠安樓閣貫空嵌，絕頂磨霄凝悴嵐。", "若到白雲猶未半，憑君更上七星巖。"]'),
('db8c6d0f-5316-40f2-bcca-320489126f4b','頂山寺','孔延之','宋','宋诗','song-poetry','','[]','高山峯峯頂欲參天，蓄怪儲靈遠近傳。',65,'全唐诗/poet.song.23000.json','["高山峯峯頂欲參天，蓄怪儲靈遠近傳。", "雲岫萬重圍凈土，石門千丈落飛泉。", "羣居在昔論三益，少別於今已十年。", "繞檻穿雲似蝴蝶，夢魂何夕不翩翩。"]'),
('0818b6a1-10c6-4ad0-b340-35303d3769a7','句','孔延之','宋','宋诗','song-poetry','','[]','天目遠隨雙鳳落，海門遥蹙兩潮趨。',16,'全唐诗/poet.song.23000.json','["天目遠隨雙鳳落，海門遥蹙兩潮趨。"]'),
('dc897e2c-eafe-4401-bac2-caec8a90c0f2','寄吳處厚','邵亢','宋','宋诗','song-poetry','','[]','流年直是隙中駒，別後情懷懶似疏。',64,'全唐诗/poet.song.23000.json','["流年直是隙中駒，別後情懷懶似疏。", "天上又頒新歲曆，牀頭未答故人書。", "殷懃魚雁功曹檄，狼藉杯盤上客魚。", "好在仲宣家萬里，從軍苦樂定何如。"]'),
('129b6b03-12e9-4a97-b93b-c06c5df12fe0','方氏故居','邵亢','宋','宋诗','song-poetry','','[]','偶分魚竹到稽山，處士林泉一望間。',64,'全唐诗/poet.song.23000.json','["偶分魚竹到稽山，處士林泉一望間。", "歲月自隨流水遠，姓名長與白雲閑。", "鑑中人去荒遺跡，溪口僧來與舊顔。", "何日放船訪巖藪，吾門高第約躋攀。"]'),
('371dff3c-9020-4c95-bb0f-c7d9d96d9bc5','送程給事知越州','邵亢','宋','宋诗','song-poetry','','[]','澄江渺渺豫章樓，曾是雙旌再歲留。',64,'全唐诗/poet.song.23000.json','["澄江渺渺豫章樓，曾是雙旌再歲留。", "五馬解鞍方北上，萬艘蜚栗又南遊。", "說棠重到清陰在，埋劍將磨異氣浮。", "求得公閒且行樂，即看華髮滿人頭。"]'),
('102d19ca-2e9f-4486-bfcc-d6769de49961','題釣臺','邵亢','宋','宋诗','song-poetry','','[]','子陵臺下山層層，奇峰壯氣橫雲生。',80,'全唐诗/poet.song.23000.json','["子陵臺下山層層，奇峰壯氣橫雲生。", "處士溪邊水泚泚，碧波明月涵天清。", "老松偃蹇傲世色，綠竹瀟灑吟風聲。", "潮頭百仞出海門，飄吳繫越如毛輕。", "飛來灘下不敢過，變作平浪歸滄溟。"]'),
('399ac04c-b983-4c12-ae78-5bbb7f0106a2','重過京口','邵亢','宋','宋诗','song-poetry','','[]','今春揚子渡，江柳拂人頭。',48,'全唐诗/poet.song.23000.json','["今春揚子渡，江柳拂人頭。", "轉面庭幃遠，傷心歲月流。", "練塘荷芰晚，甘露黍禾秋。", "此日南歸路，雲閒醉壽丘。"]'),
('1184f876-16fa-454f-8dd7-36890010c797','南京種山藥法  其一','蔡挺','宋','宋诗','song-poetry','','[]','青青正是中分天，區種何妨試玉延。',32,'全唐诗/poet.song.23000.json','["青青正是中分天，區種何妨試玉延。", "即見引鬚緣夏木，定知如蹠薦冬筵。"]'),
('db2c545e-f1db-48b7-9f84-9c0e6d5299d7','南京種山藥法  其二','蔡挺','宋','宋诗','song-poetry','','[]','潤還御水冰霜結，蔭近堯雲雨露偏。',32,'全唐诗/poet.song.23000.json','["潤還御水冰霜結，蔭近堯雲雨露偏。", "自裹自題還自愧，揠苗應笑宋人然。"]'),
('f11f290d-5001-42f7-8c08-3a1286bb5619','皇子生獻詩','蔡挺','宋','宋诗','song-poetry','','[]','昨夜薰風入舜韶，君王未御正衙朝。',32,'全唐诗/poet.song.23000.json','["昨夜薰風入舜韶，君王未御正衙朝。", "陽暉已得前星助，陰沴潛隨夜雨消。"]'),
('7a7b7bdf-043e-4f2d-9430-88bff96e2074','禹碑','劉贄','宋','宋诗','song-poetry','','[]','壇峙麻姑石，溪忘夏禹碑。',24,'全唐诗/poet.song.23000.json','["壇峙麻姑石，溪忘夏禹碑。", "物神人所貴，世事遠誰知。"]'),
('be3d47d6-8e8e-4b9c-b419-fe2117c5935d','遊後洞詩','劉贄','宋','宋诗','song-poetry','','[]','寺久荒寂無足往，念有子厚彌陀碑。',256,'全唐诗/poet.song.23000.json','["寺久荒寂無足往，念有子厚彌陀碑。", "獨趨一里轉巖腹，剝粉敗赤逢門楣。", "亭亭故碑亡舊主，覆以老屋疎且欹。", "常嗟古人不可見，尚喜書誌存於斯。", "世言書字出心畫，體制類彼人所爲。", "子厚少年頗疎雋，字合飄逸往不覊。", "胡爲氣質反端厚，至今觀者多有疑。", "或云彼以竄農久，志氣軟熟非前時。", "或云高才尚薄世，故獨立法無所師。", "吾嗟世俗日無理，好惡不正論苦卑。", "臆決萬事豈獨此，此書何媿人不知。", "碑陰三百四十字，疎瘦勁麗何精奇。", "九十二人姓名具，陳績寶曆元年題。", "云此子厚二碑者，元和五年刊厥辭。", "至是二月始建立，都其事者楊與倪。", "塵蒙壁礙世未見，自我訪尋初管之。"]'),
('075cba56-b2bc-4a04-b067-74f399624c12','句','宋道','宋','宋诗','song-poetry','','[]','自笑顛狂便歸去，並無穿繫買山錢。',16,'全唐诗/poet.song.23000.json','["自笑顛狂便歸去，並無穿繫買山錢。"]'),
('a76706ae-1ad8-41c3-86df-eefee7345561','句','釋道臻','宋','宋诗','song-poetry','','[]','疑君魂夢在清都。',8,'全唐诗/poet.song.23000.json','["疑君魂夢在清都。"]'),
('3c78777f-fd65-4930-bab7-ac92d3eb2594','句','高堯輔','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','一枕寒聲湘浦雨，滿窗秋色洞庭煙。',16,'全唐诗/poet.song.23000.json','["一枕寒聲湘浦雨，滿窗秋色洞庭煙。"]'),
('e8cfdaae-65f2-42c7-bb64-3d1af9d65533','遊碧落洞同李兟諸公','顔庶幾','宋','宋诗','song-poetry','','[]','神地秘靈室，壺天鎖翠微。',48,'全唐诗/poet.song.23000.json','["神地秘靈室，壺天鎖翠微。", "歌詠極今古，登臨忘是非。", "況有麋鹿侶，堪紉蘭蕙衣。", "得志此何遠，豈復懷塵機。"]'),
('5af59ee1-38bf-4ba1-8f25-9bd0b8ef89ad','送成都護戎韓舍人','范祥','宋','宋诗','song-poetry','','[]','全蜀兵符重，霄宸注念勞。',96,'全唐诗/poet.song.23000.json','["全蜀兵符重，霄宸注念勞。", "臨戎號人傑，分組得時髦。", "軍府威名播，齋壇世閥高。", "歷橋題駟馬，揚旆啟三刀。", "矍鑠前謀大，澄清此志豪。", "忠臣希子貢，民頌繼王褒。", "臘市繁千蓋，春江漲萬艘。", "浣溪雲粉薄，公暇廢援毫。"]'),
('1d152155-a9b7-4ca3-a6c1-462d20639d94','留題郫縣西禪院古調詩','徐仲謀','宋','宋诗','song-poetry','','[]','郫縣七十年，碁布于郊坰。',240,'全唐诗/poet.song.23000.json','["郫縣七十年，碁布于郊坰。", "景德當道衢，寶塔騰青冥。", "其間西禪院，地勝景物靈。", "何以使索然，中有大藏經。", "自從沒官來，卷帙何零丁。", "府民納其直，將遷離梵庭。", "奇哉陳氏子，覩此而涕零。", "謂寺無九部，何以重佛僧。", "如人去五臟，何以主神形。", "捨財百萬餘，贖之俾安寧。", "蘭若皆修飾，具葉重芬馨。", "籤函列金玉，堂殿揮丹青。", "永以鎮福地，實可壯禪扃。", "命僧開寶藏，煌煌如日星。", "讀誦香院裏，音響何泠泠。", "聞者與見者，如醉而得醒。", "豈不獲洪福，深遠於滄溟。", "凡人富金帛，安能延百齡。", "唯有好善道，聲譽喧雷霆。", "高吟二百言，長使郫民聽。"]'),
('a5869f3f-6468-4640-80be-a8a64b6f016e','白蘋洲','徐仲謀','宋','宋诗','song-poetry','','[]','風流人物兩相逢，白傅高文紀漢公。',32,'全唐诗/poet.song.23000.json','["風流人物兩相逢，白傅高文紀漢公。", "三圃五亭裝郡景，千花萬卉媚春風。"]'),
('f74d5701-0847-4c7a-8737-973c12804043','句  其一','徐仲謀','宋','宋诗','song-poetry','','[]','湖上風濤或泛浮，城南因立鎮湖樓。',16,'全唐诗/poet.song.23000.json','["湖上風濤或泛浮，城南因立鎮湖樓。"]'),
('48d43c62-1b4c-41b2-be55-9d2f2ba9ed97','句  其二','徐仲謀','宋','宋诗','song-poetry','','[]','四水交流霅霅聲。',8,'全唐诗/poet.song.23000.json','["四水交流霅霅聲。"]'),
('3dd58284-23a2-4069-a0a4-0dc9e8c977a4','句  其三','徐仲謀','宋','宋诗','song-poetry','','[]','郡城重疊聳危樓，最愛清風景物優。',16,'全唐诗/poet.song.23000.json','["郡城重疊聳危樓，最愛清風景物優。"]'),
('472de74d-9cf7-427b-98ca-4387e84eb08d','句  其四','徐仲謀','宋','宋诗','song-poetry','','[]','安寢有時延皓月，閉門無處不清風。',16,'全唐诗/poet.song.23000.json','["安寢有時延皓月，閉門無處不清風。"]'),
('286875b5-95ed-4cab-96e3-28ddf4b328af','句  其五','徐仲謀','宋','宋诗','song-poetry','','[]','羅列全如斗極星。',8,'全唐诗/poet.song.23000.json','["羅列全如斗極星。"]'),
('3c06dd07-cf06-4855-bcae-80eecfae5a41','興慶池禊宴','張子定','宋','宋诗','song-poetry','','[]','月標元巳樂嘉辰，興慶煙波漲曉津。',64,'全唐诗/poet.song.23000.json','["月標元巳樂嘉辰，興慶煙波漲曉津。", "宴集幸聯台衮坐，風流仍繼禊堂春。", "蘭亭事古成遺跡，華蕚樓空委路塵。", "歌吹滿舡花夾岸，酒帘無處不留人。"]'),
('dbc40093-75d8-41ba-a1b0-3efeba60f9ec','陝府芮城縣羣賢凉軒詩','李寔','宋','宋诗','song-poetry','','[]','自昔聞南國，於今訟已微。',48,'全唐诗/poet.song.23000.json','["自昔聞南國，於今訟已微。", "優哉賢墨綬，經始雅軒扉。", "白日有餘樂，清風知所歸。", "如何心已化，尚寄玉琴徽。"]'),
('8c083e6f-c945-46de-8647-9f94e80f4bea','興慶池禊宴','王庭揚','宋','宋诗','song-poetry','','[]','宗臣上已宴東池，雅俗嘉賓盛集時。',64,'全唐诗/poet.song.23000.json','["宗臣上已宴東池，雅俗嘉賓盛集時。", "禊席臨川花照耀，游車分路水逶迤。", "賞心唯欲居民樂，縱飲猶虞坐客疲。", "獨願我公歸柄用，盡令天下洽春熙。"]'),
('40303eca-c248-45cc-a6ae-0522de408103','雙皂莢行','陳叔度','宋','宋诗','song-poetry','','[]','綠葉森森迎曉日，雙雙暗結秋霜實。',128,'全唐诗/poet.song.23000.json','["綠葉森森迎曉日，雙雙暗結秋霜實。", "乾坤造化借風流，陰靈滑稽爲誰匹。", "一蔕雙葩心兩同，風力雨綿神其功。", "中官始奏獻奇異，祥圖瑞牒揮毫鋒。", "四海萬方只一株，繚繞周牆百丈餘。", "侍從宮娃共爭取，攀援棘刺血羅襦。", "采得溫泉奉金輦，雪瑩肌膚紅玉暖。", "合歡當前此物生，上皇都笑天機淺。"]'),
('472b659b-a807-4609-a3e6-851ce8fd0b47','興慶池禊宴','董士廉','宋','宋诗','song-poetry','','[]','歲和事簡正韶春，興慶池邊樂衆賓。',64,'全唐诗/poet.song.23000.json','["歲和事簡正韶春，興慶池邊樂衆賓。", "尋勝此時追曲水，賞芳良會屬平津。", "映花語笑秋千女，隔岸絲簧祓禊人。", "深愧薄才叨下幕，酒酣應許吐車茵。"]'),
('70e1ea61-e946-4541-9f04-651a8be98951','隠潭','郟修輔','宋','宋诗','song-poetry','','[]','在昔知何人，鑿破青山骨。',72,'全唐诗/poet.song.23000.json','["在昔知何人，鑿破青山骨。", "飛泉直下來，千尺瀉倏忽。", "兩壁蒼翠間，一陣風雷突。", "傍無塵埃蹤，中有蛟龍窟。", "寒氣不可響，猛勢豈能屈。", "安得當旱年，爲霖濟羣物。"]'),
('1d5c675a-640b-4808-ad71-feda5ffeca83','興慶池禊宴','趙濟','宋','宋诗','song-poetry','','[]','撫封占清境，禊宴協良辰。',48,'全唐诗/poet.song.23000.json','["撫封占清境，禊宴協良辰。", "物態隨春秀，歌聲洽政淳。", "擷芳尋陌綺，泛棹繫波鱗。", "天幸陪開府，非才愧席賓。"]'),
('6ff483fd-77ca-4f08-87b8-97b20e04b177','詩一首','陳昉','宋','宋诗','song-poetry','','[]','二十餘年作吏人，後園花木也成林。',64,'全唐诗/poet.song.23000.json','["二十餘年作吏人，後園花木也成林。", "盡是筆頭那撚得，枝枝葉葉有寃聲。", "刑重惟恐囚人怨，情輕又怕本官嗔。", "不知無事早歸去，免得生魂對死魂。"]'),
('1479cb23-23d8-42a3-a355-ab66fd3a711e','送王才元入京','王崇','宋','宋诗','song-poetry','','[]','渭城楊柳已青青，强駐行人聽渭城。',64,'全唐诗/poet.song.23000.json','["渭城楊柳已青青，强駐行人聽渭城。", "不問使車歸路遠，且從樽酒滿杯傾。", "相逢洮塞休兵後，此去秦川照眼明。", "若立螭頭前借箸，且教充國事春耕。"]'),
('e9a4b645-1103-4f77-b89b-7fe64175fc87','詩贈富樂山海公長老','王綱','宋','宋诗','song-poetry','','[]','心地如今不動塵，大千境界百年身。',64,'全唐诗/poet.song.23000.json','["心地如今不動塵，大千境界百年身。", "掩關明月上峯頂，滿座清風生玉津。", "雪嶺松筠爲節操，石樓鐘磬度昏晨。", "已同七老圖巖壁，便是龍華會裏人。"]'),
('aed40a7a-8ede-41df-9b0e-fc79628632ba','降真巖','何羣','宋','宋诗','song-poetry','','[]','鳳頂孤峯聳絕奇，仙家雲馭久棲遲。',64,'全唐诗/poet.song.23000.json','["鳳頂孤峯聳絕奇，仙家雲馭久棲遲。", "飛勝岷嶺元和日，留記山巖景祐時。", "水透山阿朝北坎，山開井勢拱南離。", "他年殿閣鳴鐘磬，廣運重開帝載熙。"]'),
('03f9ceb3-4a9a-41e2-a376-8015d028ea9a','題惠泉寄知軍郎中','句龍緯','宋','宋诗','song-poetry','','[]','崎嶇荆門山，叢起爲東阨。',192,'全唐诗/poet.song.23000.json','["崎嶇荆門山，叢起爲東阨。", "陽岡盤氣勢，陰竇融液脈。", "源濯雲根移，流噴石罅拆。", "呀呀兩岸間，平澗纔數席。", "環岸貯清泚，古鏡照秋色。", "恬風不生紋，至底無隠物。", "澄輝泛嵐翠，凈影溶天碧。", "潛花深冏冏，蔭樹高崒崒。", "清光照毛髮，爽氣灑肌骨。", "如入冰壺中，亭宇何鮮飾。", "缾罌日往來，舉汲易爲力。", "短綆何勞人，輕舠恰容客。", "當時竟陵翁，老死却不歷。", "品第十九泉，遺此良可惜。", "此泉惠此土，唯日流不息。", "作詩頌惠泉，勉哉君子德。"]'),
('b4784289-6390-4e0c-893f-99fe73f96957','玉華山','宋球','宋','宋诗','song-poetry','','[]','玉華山來自何處，巉巉拔立陵紫煙。',116,'全唐诗/poet.song.23000.json','["玉華山來自何處，巉巉拔立陵紫煙。", "上有干雲切霄之蒼松，下有迸崖漱壑之清泉。", "長河西來齧山足，燐火白日明峯巔。", "浮嵐暖翠入窗戶，六月殿閣風泠然。", "我來豈暇弔古蹟，俛仰但喜遺囂喧。", "心魂澄澈耳目醒，如脫世故游神僊。", "平明却入俗塵去，回首煙蘿羞滿顔。"]'),
('ab0eb18f-f5a7-42a2-adfc-531b6ed20beb','玉華寺','宋球','宋','宋诗','song-poetry','','[]','一逕入雲壑，遊人高下行。',48,'全唐诗/poet.song.23000.json','["一逕入雲壑，遊人高下行。", "綠蘿垂紺幰，屏壁削層城。", "山氣蒸衣濕，松風灑面清。", "野僧遺萬事，飽聽石泉聲。"]'),
('cee4c175-fc92-4397-9590-6cc157cf2b21','拙詩奉贈富樂山海公禪師','宋球','宋','宋诗','song-poetry','','[]','遊遍西南轉法輪，歸來挂錫舊溪濱。',64,'全唐诗/poet.song.23000.json','["遊遍西南轉法輪，歸來挂錫舊溪濱。", "師心皎皎潭中月，世俗悠悠几上塵。", "白雪眉毫俱晚暮，碧雲章句獨清新。", "近來素壁皆圖像，如滿聯成七老人。"]'),
('452a2f7d-040f-4286-9d1a-6f0347d8f19c','玉華山','張道宗','宋','宋诗','song-poetry','','[]','玉華山形鬰崷崒，白晝莽蒼常生煙。',112,'全唐诗/poet.song.23000.json','["玉華山形鬰崷崒，白晝莽蒼常生煙。", "近村百家濕翠黛，陰崖千尺淙寒泉。", "山根宛轉抱河曲，河流倒影浸碧巔。", "文皇性熱不奈暑，當時宮此安徒然。", "得非遍選天下勝，莫如茲地無煩喧。", "蹔遊已駭非俗骨，久駐直恐成真仙。", "何當借得神畫筆，霜綃十幅圖孱顔。"]'),
('e2693410-f0f1-452d-8d72-a74cef0710fb','玉華寺','張道宗','宋','宋诗','song-poetry','','[]','殿閣依山古，尋春閑客行。',48,'全唐诗/poet.song.23000.json','["殿閣依山古，尋春閑客行。", "誰知唐帝館，今在梵王城。", "禾黍傷時變，松篁入夜清。", "惟餘碧巖溜，依舊昔年聲。"]'),
('113c5632-06ed-4293-81d9-8d40a1d5687a','和吳公仲庶遊海雲寺','馮介','宋','宋诗','song-poetry','','[]','及時行樂慰刀州，曉背重城信馬頭。',64,'全唐诗/poet.song.23000.json','["及時行樂慰刀州，曉背重城信馬頭。", "彩石散隨香被去，芳塵紛逐鈿車流。", "悤悤曲水當年會，草草東山舊日遊。", "不是海雲今獨勝，清風長共好詩留。"]'),
('fbb58415-0257-4fdc-98ca-5eaec6f278c2','句  其一','馮介','宋','宋诗','song-poetry','','[]','白雲處士來觀樂，翠黛佳人笑繫甌。',16,'全唐诗/poet.song.23000.json','["白雲處士來觀樂，翠黛佳人笑繫甌。"]'),
('530b031f-6ab0-4a96-8295-ced17c0e1afb','句  其二','馮介','宋','宋诗','song-poetry','','[]','坐上繫甌清似玉，檻前流水碧如藍。',16,'全唐诗/poet.song.23000.json','["坐上繫甌清似玉，檻前流水碧如藍。"]'),
('e3b55f03-dec0-42e3-bc73-ce3b4ebbf183','代人送廣州劉待制','金君卿','宋','宋诗','song-poetry','','[]','元精生俊臣，其器疏以博。',288,'全唐诗/poet.song.23000.json','["元精生俊臣，其器疏以博。", "渾玉謝雕鎸，古樂鎮浮薄。", "文章發粹藴，雲漢相紛搏。", "軒昂仕路間，獨立羣雞鶴。", "朝端聳風采，衆聽嘉蹇諤。", "緣飾吏事餘，中有名教樂。", "按獄袪煩苛，餽糧得豐約。", "邛蜀號險艱，靜制猶扃鑰。", "歸來奏成績，高議凌霄鶚。", "往釐東南計，詎足煩精畧。", "中道發詔書，飛榮上天閣。", "抗旌出五嶺，廣府開巨幕。", "提封犬牙制，被海珠貝錯。", "況當蠻獠衝，尚苦蜂蠆蠚。", "日望公之來，坐見起民瘼。", "先聲百粵外，猾寇千里却。", "行當靜海隅，天步清且廓。", "栖栖外臺吏，正困韁鏁縛。", "忻聞大旆過，一見如刮膜。", "下坐聽語言，渴引醇酎酌。", "退嗟蠅蟲癡，敢議驥尾託。", "願公南轅還，四海霖雨作。", "嘻噓和氣行，瞬息羣動躍。", "及此分寸苗，庶幾秋有穫。"]'),
('e403dc47-8432-4576-89d6-7d5b0fd4314c','南埜書懷','金君卿','宋','宋诗','song-poetry','','[]','險途吁可憎，淺俗寖澆競。',288,'全唐诗/poet.song.23000.json','["險途吁可憎，淺俗寖澆競。", "進物莫若利，趨時不如佞。", "吾道何由亨，讒人方醜正。", "予生與時戾，所賦得剛勁。", "力古恥浮文，論經斥非聖。", "强勉悅時事，難乎易天性。", "木舌不卷柔，枯株微蔭映。", "沿洄避風波，進退觸機穽。", "八載脫流銓，恩與萬家令。", "移官瘴嶺下，親闈阻溫凊。", "南荒地多暑，嵐氛午猶暝。", "因思古令尹，舒慘繫民命。", "士元都下治，汲黯辭以病。", "幾欲慕伊人，去就得非輕。", "雖然萬夫長，亦足觀以政。", "升進由漸階，困窮亦前定。", "所以勤吏術，敺民一其行。", "澄清疏浚源，披攘塞邪徑。", "吏手不得縱，奸豪無敢橫。", "訓染所難入，未免加笞榜。", "宿黠殊欲悛，良民適相慶。", "僅慰百里心，莫聳四海聽。", "世人重苟且，耳目非卓夐。", "庸兒難共議，寧與智者爭。"]'),
('4507f623-252c-4b50-b37d-1e36f2ac0e38','雙檜分題','金君卿','宋','宋诗','song-poetry','','[]','名藍壓城闉，巀岌聳雙檜。',132,'全唐诗/poet.song.23000.json','["名藍壓城闉，巀岌聳雙檜。", "得地不孤立，陵風自相對。", "根盤乖龍獰，葉剪蒼璧碎。", "交柯紐頑銅，疊影森翠蓋。", "勁無絲蘿託，直與松柏配。", "爭高丈夫氣，恥學兒女態。", "雪霜正柔落，草木任顛沛。", "同心歲寒間，正色煙霞外。", "斧斤未翦拂，志節已高邁。", "出羣才可驚，有作器必大。", "考室須棟隆，濟川俟舟載。"]'),
('1735fa08-b5bf-4668-aa6f-b388d29e0106','區著作湘潭舊隠有二亭焉求詩以歸','金君卿','宋','宋诗','song-poetry','','[]','危亭揭池心，池水表且滑。',48,'全唐诗/poet.song.23000.json','["危亭揭池心，池水表且滑。", "九秋煙露濃，四面芙蓉發。", "此時浩歌去，萬事不掛舌。", "把酒酣清風，投竿釣明月。"]'),
('8283f40c-cd73-4674-ab81-0ccf29b0c6a6','寄題張秀才此君亭','金君卿','宋','宋诗','song-poetry','','[]','一徑入叢深，四軒森翠玉。',48,'全唐诗/poet.song.23000.json','["一徑入叢深，四軒森翠玉。", "紅塵不到處，清秋長在目。", "主人厭薄官，欲躡高士躅。", "日日念此君，招我湘江曲。"]'),
('4bfba6dd-598f-4262-b670-8674ee745c06','題胡主簿澄清軒','金君卿','宋','宋诗','song-poetry','','[]','危壁敞新軒，西風滿蘭芷。',72,'全唐诗/poet.song.23000.json','["危壁敞新軒，西風滿蘭芷。", "披襟豁萬慮，舉目照千里。", "丈夫固有待，澄清不虛紀。", "勾稽職雖賤，爲仁決由己。", "芳盛無良苗，源污無潔水。", "願推天下心，先從邑中始。"]'),
('a7da1c32-3903-4089-ae63-81cb70e99463','過姑孰溪觀李白舊詩洎樂天弔太白墳短句因而繼和','金君卿','宋','宋诗','song-poetry','','[]','水從照亭來，蕩漾涵秋凈。',48,'全唐诗/poet.song.23000.json','["水從照亭來，蕩漾涵秋凈。", "樓臺闞空渺，倒影入明鏡。", "溪山久寂寥，勝遊誰與並。", "新月生暮寒，謳歌發漁艇。"]'),
('db05be5f-a1b3-4136-ad21-6035176aca9c','淩歊臺','金君卿','宋','宋诗','song-poetry','','[]','風流六朝士，曾此登高岑。',48,'全唐诗/poet.song.23000.json','["風流六朝士，曾此登高岑。", "太白訪幽蹤，飄飄成微吟。", "牧之感遺事，名字留碑陰。", "我來徒感慨，千載一披襟。"]'),
('2fa2d3e6-cc68-46b0-a6aa-92b12235a384','汴渠','金君卿','宋','宋诗','song-poetry','','[]','洪河貫中州，隨汴鑿支流。',108,'全唐诗/poet.song.23000.json','["洪河貫中州，隨汴鑿支流。", "滔滔萬里來，禹浪東南浮。", "糧道所由濟，日逝千斯舟。", "嗟哉隋皇帝，禍起江都遊。", "先身不先民，及樂不及憂。", "遠棄宗室重，死作社稷羞。", "胡爲得民力，舉鍤成巨溝。", "後來蒙其利，厥功固難酬。", "願思所以失，宴安仍仇讎。"]'),
('64f898b8-19f9-432e-842c-dfcce437b529','慈竹','金君卿','宋','宋诗','song-poetry','','[]','欲知慈姥心，看此磯上竹。',48,'全唐诗/poet.song.23000.json','["欲知慈姥心，看此磯上竹。", "四時無改易，一節念幽猶。", "蟠根石罅牢，倒影潭心綠。", "直恐霜雪姿，化爲水蒼玉。"]'),
('9cac2820-3b3b-4594-9c88-bfbed77634c0','哭劉卿材','金君卿','宋','宋诗','song-poetry','','[]','人皆哭仲途，我獨悲卿材。',108,'全唐诗/poet.song.23000.json','["人皆哭仲途，我獨悲卿材。", "仲途於卿材，猶賜也與回。", "回行不可泯，孔絃有餘哀。", "卿材不偶聖，人孰知賢哉。", "龍馬駕鼓車，不如一駑駘。", "燕金正掛賞，痛惜骨已埋。", "操舟過君家，登山甫徘徊。", "墓樹忽成拱，犯雪色不摧。", "携觴奠其下，淚涕霑蒼苔。"]'),
('82c0f2e4-ea9e-48d6-8710-91c970681ce1','丹陽湖','金君卿','宋','宋诗','song-poetry','','[]','島樹壓叢雲，波光鋪寒雪。',48,'全唐诗/poet.song.23000.json','["島樹壓叢雲，波光鋪寒雪。", "迥浸寒無暑，平空曉猶月。", "呂父已入周，范蠡未辭越。", "扁舟誰與同，浩歌幾千闋。"]'),
('28e18434-40ab-4f9e-897f-ac1837d0965e','留題楊子陸清照亭','金君卿','宋','宋诗','song-poetry','','[]','縣舍敵幽居，蕭然敞軒檻。',60,'全唐诗/poet.song.23000.json','["縣舍敵幽居，蕭然敞軒檻。", "高迎遠峯入，下與新池闞。", "清景月生晝，寒光冰滿鑑。", "狎鳥自相得，輕舠不容泛。", "對此須澄心，宜哉水爲鑒。"]'),
('54f02229-df79-4bb5-8dee-a6334cf7d0c3','書簡寂觀','金君卿','宋','宋诗','song-poetry','','[]','欹危煙靄間，覆壓山岳半。',48,'全唐诗/poet.song.23000.json','["欹危煙靄間，覆壓山岳半。", "境窮天地寒，氣古金碧爛。", "泉源長清霽，雲木杳淩亂。", "尋高下來遠，白日己西竄。"]'),
('50d6b097-c408-4725-beff-39cfe42c38ed','贈僧惟益','金君卿','宋','宋诗','song-poetry','','[]','益也非庸僧，黄卷粗漁獵。',84,'全唐诗/poet.song.23000.json','["益也非庸僧，黄卷粗漁獵。", "身雖闤闠中，恥與喧囂接。", "朝彈側楸局，暮杵青黏葉。", "妙理脫扃鍵，高談騰輔頰。", "繄予困韁鎖，荏苒尚吏牒。", "不見才七年，霜髭已盈鑷。", "借問何所因，苦吟詩滿篋。"]'),
('011e0d84-5c26-4b72-98c7-723d5093108b','僧靈辯南歸','金君卿','宋','宋诗','song-poetry','','[]','僧如靈辯者，翹枝秀叢林。',108,'全唐诗/poet.song.23000.json','["僧如靈辯者，翹枝秀叢林。", "浩蕩遊九州，窮奇發清吟。", "巨軸謁明光，朝奏暮拜恩。", "䓞袍拂天香，珍重如腰銀。", "逸足不可羈，歸雲渺無根。", "清明汴口開，一葉東南奔。", "故山盤冰溪，百尺數纖鱗。", "洗耳外名教，灑然鷗鷺羣。", "應笑未歸客，青衫京洛塵。"]'),
('2a740ed5-02ac-4048-b770-ab48ca08cd90','文相生日','金君卿','宋','宋诗','song-poetry','','[]','聖賢不世出，會合未可知。',288,'全唐诗/poet.song.23000.json','["聖賢不世出，會合未可知。", "朝廷餘百年，天將右重熙。", "經綸須得人，公爲生斯時。", "維時秋九月，爽氣橫海涯。", "三葉凋階蓂，嘉夢符熊羆。", "豈特鍾嶽靈，囊括昴與箕。", "夾山州之望，罄竭敢自私。", "復疑於其來，釋老親抱持。", "道貌瑩襁褓，公相乃餘姿。", "勝衣惜寸陰，問學俱忘疲。", "過目已解悟，知妙初無師。", "峨冠踐場屋，發策趨丹墀。", "儒館聊稅息，偉望臨華夷。", "知公離能盡，荆公每嗟咨。", "謂與公所學，展矣無可疑。", "所憂異世習，老不見設施。", "勃興得神考，丞弼須臯夔。", "公始在勸講，朝夕輸論思。", "君臣由一德，協合踰塤篪。", "法度日新美，小不遺毫釐。", "銜恤俄去位，虛佇同調饑。", "迨歸不閱歲，再遷居近司。", "荆公鎮江左，成績憂廢隳。", "潤色固頼何，可但如曹隨。"]'),
('25c1d93f-9671-4a94-ab36-cbbd88f992c2','怪石','金君卿','宋','宋诗','song-poetry','','[]','凡物以怪見憎嫉，爾獨何爲人采拂。',160,'全唐诗/poet.song.23000.json','["凡物以怪見憎嫉，爾獨何爲人采拂。", "巉頑累疊百千狀，人獸鬼魅相髣髴。", "裸蠻面縛夷吾囚，日剝風皴子胥骨。", "比干愛主心見剖，孫子兼人足先刖。", "枯龜灼墨足兆坼，蟄蛇驚春暫蟠屈。", "古器斷爛猶斵雕，老木鱗皴半枯杌。", "僧軒閑殺日月長，劚地擠排破煙鬰。", "簷溜滴窮蛾子垤，蔓延引入蝸牛窟。", "我來不以爾貌取，所愛鏗然最堅質。", "終當鍛鍊持補天，安此兀兀爲玩物。"]'),
('c2b7efce-00cc-4aa5-9980-7ac0a258d7b6','清江臺','金君卿','宋','宋诗','song-poetry','','[]','貢章湍險吁可驚，岸翻石走轟雷霆。',112,'全唐诗/poet.song.23000.json','["貢章湍險吁可驚，岸翻石走轟雷霆。", "崩奔出贑一千里，江勢到此纔淵渟。", "道山仙府相照映，盤泊下飲蒼龍精。", "金沙洗淘洲嶼出，紅紫錯雜圍春城。", "郡臺峨空壓萬瓦，況值開霽宜高明。", "老郎官冷厭韁鎖，亦有罇酒難獨傾。", "旋烹茗粥別官佐，明朝又作新昌行。"]'),
('04af31be-4928-44d0-8ff3-532a5f1b22db','寄題浮梁縣豐樂亭','金君卿','宋','宋诗','song-poetry','','[]','百流南瀉昌江潯，涵光吐潤生良金。',160,'全唐诗/poet.song.23000.json','["百流南瀉昌江潯，涵光吐潤生良金。", "從前良令固無幾，矧復惠政留于今。", "四十年來耆舊語，李謝劉楊遺愛深。", "高君氣象又宏遠，能以和易調羣心。", "政平訟簡日多暇，遠囂淩俗開胸襟。", "旋治東園敞軒闥，四睇環聳千高岑。", "已占溪山足清思，更添桃李成濃陰。", "斯亭不獨與民樂，樂得賢者同登臨。", "嗟予萬思走燕趙，弱羽歸飛思故林。", "空吟絕致未能往，徙倚南風聊寄音。"]'),
('6ac60c78-1aa5-4c7e-a570-3a3d8625e907','留題張氏頤文閣','金君卿','宋','宋诗','song-poetry','','[]','鄱陽才子鍾慶門，巍冠大带何紛紛。',144,'全唐诗/poet.song.23000.json','["鄱陽才子鍾慶門，巍冠大带何紛紛。", "誠心樂道自頤養，霧豹蔚彧珍其文。", "朱欄碧瓦江之垠，更敞高閣淩煙氛。", "烟中數岫列窗牖，急雨洗出青無痕。", "乍來耳目益開爽，況日文酒酣天真。", "前年詔下起嵓隠，子直奮起軒浮雲。", "不嫌官小喜及養，斂板歸拜高堂親。", "子方歸寧亦同樂，與子登眺開芳樽。", "定交酌壽雖所愧，相望蘭桂長清芬。"]'),
('f6321533-1528-47ae-af1f-5289679114a8','九日過長蘆泊小港留題龍山古寺','金君卿','宋','宋诗','song-poetry','','[]','輕舟晚過長蘆渡，西風吹帆落沙溆。',128,'全唐诗/poet.song.23000.json','["輕舟晚過長蘆渡，西風吹帆落沙溆。", "空桑古市漁家烟，信步閑尋石城去。", "石城苦遠日苦晚，崎嶇半入龍山路。", "山回路轉翹林處，披開白雲見幽寺。", "家菊海榴矜晚芳，落華鳴泉足秋思。", "野叟耕塚出壞石，虛城埋狐井射鮒。", "老僧推門揖我入，古碣荒唐草中覷。", "仰天一笑六朝事，過鴈書天作文字。"]'),
('1dda9cf7-4d21-407b-854c-ed569f24e1ca','留雲山居呈長老元禪師','金君卿','宋','宋诗','song-poetry','','[]','衡陽崗阜羣龍奔，截起萬仞磨天閽。',96,'全唐诗/poet.song.23000.json','["衡陽崗阜羣龍奔，截起萬仞磨天閽。", "宿雲收蹤著平地，星辰滿軒斗可捫。", "河漢鴻湧巖泉噴，六月飛雪冰木根。", "下視吳楚區域分，衆山培塿烏足云。", "我來環走竟朝曛，擺脫韁鎖忘塵紛。", "更聞高論益清曠，如挹仙袂遊崑崙。"]'),
('b4dbf4ac-ecdd-46f2-acf1-7009102dae68','寄題張秀才此君亭','金君卿','宋','宋诗','song-poetry','','[]','羣山四向盤青雲，山足一徑縈雲根。',144,'全唐诗/poet.song.23000.json','["羣山四向盤青雲，山足一徑縈雲根。", "拂雲截徑敞軒檻，檻外百卉鋪重茵。", "矜春哆哆弄顔色，散漫紅紫何紛紛。", "主人養高不累俗，欲以清節遺子孫。", "剪花芟草植修竹，半卷畫籜含霜筠。", "漸迎風露竟百畝，碧油黕地無纖塵。", "對之氣思自瀟灑，行吟足以窮朝曛。", "吾居接境未始到，手馳大筆胡能云。", "勸子無渝歲寒操，惟日虛心比此君。"]'),
('249151d2-356d-4446-b612-7e3817a3b7fc','范資政移鎮杭州一百韻','金君卿','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','聖門高弟游淵源，當時所得惟十賢。',384,'全唐诗/poet.song.23000.json','["聖門高弟游淵源，當時所得惟十賢。", "科張言行政與學，兼此四者誰能然。", "公含天資得具美，出文入武材謨全。", "軒昂盛時進以道，行高德鉅齊回騫。", "發爲文章動驚俗，邈與游夏爭差肩。", "手鑿大竅破混沌，分得清濁歸坤乾。", "斯文去聖日已遠，泯塞不絕猶涓涓。", "公恢吾儒獨振起，力引巨海吞百川。", "周旋六經後諸子，陟彼泰山望八埏。", "提携千篇去奏御，列宿環拱分經躔。", "章韶夏濩忽冥昧，琥璜圭璧慙雕鎸。", "詞雄語險氣復銳，猛將正怒揮戈鋋。", "羣邪衆枉困淩暴，辟易萬里窮無邊。", "飛名禁林號獨步，多士仰則猶權衡。", "惟時朝廷政不一，衆口噤暗同寒蟬。", "公鬰奇材未得吐，盤虹積玉胸中填。", "囊書萬言究大政，徑欲鍛石持補天。", "自從諫言抉心膽，慷慨大論君之前。", "采詩上誦關雎化，稽古下陳無逸篇。", "材高於時衆所忌，讒機巧網相包纏。", "如公之言遽見斥，嗟嗟吾道何其邅。", "上思賈生久不見，一日開悟俄詔還。", "歸來復踐諫諍列，正似猛矢加勁弦。", "遂登天閣承顧問，凡日三接親邃延。"]'),
('273896d0-50c0-4207-9f0b-957bba31e494','夜泊竹篠港寄鄱陽朱安石','金君卿','宋','宋诗','song-poetry','','[]','江陰滄漭雲四垂，風蘋雨杜饒秋悲。',64,'全唐诗/poet.song.23000.json','["江陰滄漭雲四垂，風蘋雨杜饒秋悲。", "孤檣轉汀落處晚，漁歌傲笑鷗羣疑。", "肥魚新酒且可挹，萬緒一破忘者誰。", "驚波到枕不成夢，鴻聲半夜東南飛。"]'),
('05c699ae-b155-47c1-9b43-8d5cee38327e','和李公素舍人真州通濟亭詩','金君卿','宋','宋诗','song-poetry','','[]','虹堤崛起開危軒，四徹空曠圍山川。',64,'全唐诗/poet.song.23000.json','["虹堤崛起開危軒，四徹空曠圍山川。", "刺天萬里煙樹外，破浪一去風中船。", "青黄亂眼裂春錦，鳴聲聒耳驚秋蟬。", "亭前深處不百尺，神物窟此猶安然。"]'),
('6050b4ce-2036-4b58-b717-b32619a62d11','和御製觀龍圖閣三聖御書','金君卿','宋','宋诗','song-poetry','','[]','累聖傳真蹟，天苞炳瑞文。',48,'全唐诗/poet.song.23000.json','["累聖傳真蹟，天苞炳瑞文。", "珍藏留紫禁，寶構拂叢雲。", "焜燿三辰爛，周旋八體分。", "宸心追睿轍，尤念保邦勤。"]'),
('ae7372bf-2672-46f9-926b-f407f1d679ce','送張明遠歸丹陽','金君卿','宋','宋诗','song-poetry','','[]','此行非遠別，何用慘離顔。',48,'全唐诗/poet.song.23000.json','["此行非遠別，何用慘離顔。", "縱棹谿亭外，清歌罇酒間。", "相期在西笑，從此望南還。", "歸去重回首，夕陽江外山。"]'),
('1ac0ae19-da5b-4ced-837f-368ed6eb6876','張子禮鎖廳下第南歸','金君卿','宋','宋诗','song-poetry','','[]','官小事如麻，去官書滿車。',48,'全唐诗/poet.song.23000.json','["官小事如麻，去官書滿車。", "干時不得薦，垂翅又還家。", "知命獨無愧，沉英衆所嗟。", "風波信一葉，流落向天涯。"]'),
('5b024e8e-2f6e-405c-9a86-4dca614ed505','寄題廣信鄭倅潛道齋','金君卿','宋','宋诗','song-poetry','','[]','養志浮名外，潛神聖壺中。',48,'全唐诗/poet.song.23000.json','["養志浮名外，潛神聖壺中。", "誠心如自得，樂事固無窮。", "齋靜橫賓榻，詩成促遞筩。", "英瓊何以報，惟有四般同。"]'),
('309f9f2d-d010-455f-88f5-e00724eb1141','淝山東歸','金君卿','宋','宋诗','song-poetry','','[]','巨區苦行役，今日又東歸。',48,'全唐诗/poet.song.23000.json','["巨區苦行役，今日又東歸。", "攬轡月盈把，出林霜滿衣。", "眼看風葉亂，心逐野雲飛。", "稅馬山前驛，長天又落暉。"]'),
('b725afbc-e691-4fb9-b911-62196ef691ec','寄題畢郎中宅御書閣','金君卿','宋','宋诗','song-poetry','','[]','帝構籠多士，春官喜得人。',48,'全唐诗/poet.song.23000.json','["帝構籠多士，春官喜得人。", "慶氛騰寶札，睿睠寵詞臣。", "敞第張層構，傳家號絕珍。", "更藏書萬卷，酣咏樂天鈞。"]'),
('994733e2-d011-49de-8ec8-dab0bde4e073','病間偶作','金君卿','宋','宋诗','song-poetry','','[]','壯矣尚無成，區區京國行。',48,'全唐诗/poet.song.23000.json','["壯矣尚無成，區區京國行。", "食貧諳世態，卧病見交情。", "萬事風埃過，寸心霜雪明。", "誰知丈夫志，日月照功名。"]'),
('a145d960-3e1e-4239-96b2-c48c25a9cbb0','靈辯大師歸江南','金君卿','宋','宋诗','song-poetry','','[]','睿讚釋真筌，惟師得本原。',48,'全唐诗/poet.song.23000.json','["睿讚釋真筌，惟師得本原。", "歌時詩百首，祝聖頌千言。", "巨軸朝聞御，方袍夕拜恩。", "江南歸舊隠，高卧老乾坤。"]'),
('c2f01ee5-7566-4b75-bf68-a8fe650b9b3b','清風閣','金君卿','宋','宋诗','song-poetry','','[]','勢壓最高峯，四軒橫斷虹。',48,'全唐诗/poet.song.23000.json','["勢壓最高峯，四軒橫斷虹。", "江山形勝外，疆埸畫圖中。", "景物浩無主，塵襟到即空。", "何須遲炎暑，特地揖清風。"]'),
('c65b028d-63ac-44a1-a0e5-aebd631e42a8','戚郎中紅黄拒霜花','金君卿','宋','宋诗','song-poetry','','[]','霜曉禁寒色不摧，若論花品是奇材。',64,'全唐诗/poet.song.23000.json','["霜曉禁寒色不摧，若論花品是奇材。", "紅如錦帳香囊綻，黄似霓裳舞袖開。", "幸與畹蘭同素景，恥隨籬槿委輕埃。", "郡齋得地逢嘉賞，不逐羣英爛漫栽。"]'),
('a56a7ee1-8b7c-41d1-9a0e-4504f9e9f464','題晉匡廬先生廟','金君卿','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','山壓重江萬里波，半空精鐵鎖嵯峨。',64,'全唐诗/poet.song.23000.json','["山壓重江萬里波，半空精鐵鎖嵯峨。", "先生死去雲情薄，六國興來佛事多。", "萬剎金蓮開碧落，一祠茅竹蔽叢蘿。", "遊人但逐僧歸去，古隠荒凉誰肯過。"]'),
('991f4464-d9de-4130-93f4-3f5027d4538d','送廣州劉待制','金君卿','宋','宋诗','song-poetry','','[]','光摇劍外使星還，天閣平躋侍從班。',64,'全唐诗/poet.song.23000.json','["光摇劍外使星還，天閣平躋侍從班。", "暫命剖符開廣府，先聲指日定諸蠻。", "浮江大斾翩翻去，過嶺新恩次第頒。", "濟俗有謀方適用，卷舒應在笑談間。"]'),
('3b44c4ca-1200-46a2-9cd4-91e356251dc8','招王闞二同年','金君卿','宋','宋诗','song-poetry','','[]','偶憶去年逃暑飲，與君通夕屢忘歸。',64,'全唐诗/poet.song.23000.json','["偶憶去年逃暑飲，與君通夕屢忘歸。", "旋沽美酒開罇淥，更買新魚斫鱠肥。", "今日忽驚池水漲，小亭依舊柳陰圍。", "停舟待月波心去，携手相過莫我違。"]'),
('4d0ae2c7-c17a-4ca3-af44-cf21254d510b','寄題六安縣徐介夫園亭','金君卿','宋','宋诗','song-poetry','','[]','峨峨武步對精廬，潄玉寒泉灌石渠。',64,'全唐诗/poet.song.23000.json','["峨峨武步對精廬，潄玉寒泉灌石渠。", "醅脚滿篘先臘釀，茗叢棲塢及春鋤。", "清風儔侶簷前竹，黄卷生涯架上書。", "養志待時應自信，臨邛人莫誚相如。"]');
